// AUTO-GENERATED by scripts/utils/sync-partner-static.js — do not edit
export const PARTNER_STATIC_BUNDLE = {"admin-partner/index.html":{"contentType":"text/html; charset=utf-8","body":"<!DOCTYPE html>\n<html lang=\"en\" data-portal=\"admin\">\n<head>\n  <meta charset=\"utf-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>Eazpire Partner Ops</title>\n  <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\" />\n  <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin />\n  <link href=\"https://fonts.googleapis.com/css2?family=Inter:wght@400;600;650;700;750;800;850&display=swap\" rel=\"stylesheet\" />\n  <style>[hidden]{display:none!important}.modal-backdrop:not(.show){display:none!important}</style>\n  <link rel=\"stylesheet\" href=\"/partner/shared/css/partner-ui.css\" />\n</head>\n<body>\n  <div id=\"app-shell\" class=\"app-root\" hidden>\n    <aside class=\"sidebar\">\n      <div class=\"brand-block\">\n        <div class=\"logo-mark\">EZ</div>\n        <div>\n          <div class=\"brand-name\">Eazpire Partners</div>\n          <div class=\"brand-sub\">Admin Ops</div>\n        </div>\n      </div>\n      <nav id=\"partner-nav\"></nav>\n      <div class=\"sidebar-card\">\n        <h4>Partner Network Ops</h4>\n        <p>Manufacturer onboarding, catalog QA, fulfillment monitoring, and certification reviews.</p>\n      </div>\n    </aside>\n    <div id=\"sidebar-backdrop\" class=\"sidebar-backdrop\" aria-hidden=\"true\"></div>\n    <header class=\"topbar\">\n      <button type=\"button\" class=\"icon-btn sidebar-toggle\" id=\"sidebar-toggle\" aria-label=\"Open menu\" aria-expanded=\"false\" aria-controls=\"partner-nav\">☰</button>\n      <div class=\"topbar-start\">\n        <div class=\"crumbs\">\n          <span class=\"crumbs-host\">admin.eazpire.com</span>\n          <span class=\"crumbs-sep\">/</span>\n          <strong id=\"crumb-current\">Command Center</strong>\n        </div>\n      </div>\n      <div class=\"topbar-actions\">\n        <div class=\"search-box\" role=\"search\">\n          <span aria-hidden=\"true\">⌕</span>\n          <input type=\"search\" placeholder=\"Search manufacturers, orders, products…\" aria-label=\"Search\" />\n        </div>\n        <div id=\"topbar-extra\"></div>\n        <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-logout\">Sign out</button>\n      </div>\n    </header>\n    <main class=\"main\">\n      <section class=\"view active layout-stage command-layout\" data-route=\"/partner\" id=\"view-command\"></section>\n      <section class=\"view layout-stage studio-layout\" data-route=\"/partner/manufacturers\" id=\"view-manufacturers\"></section>\n      <section class=\"view layout-stage studio-layout\" data-route=\"/partner/catalog\" id=\"view-catalog\"></section>\n      <section class=\"view layout-stage ops-layout\" data-route=\"/partner/orders\" id=\"view-orders\"></section>\n      <section class=\"view layout-stage api-console\" data-route=\"/partner/api\" id=\"view-api\"></section>\n      <section class=\"view layout-stage cert-hq\" data-route=\"/partner/certification\" id=\"view-certification\"></section>\n      <section class=\"view layout-stage\" data-route=\"/partner/requests\" id=\"view-requests\"></section>\n    </main>\n  </div>\n\n  <div id=\"app-login\" class=\"partner-screen\" hidden>\n    <div class=\"login-card admin-login-card\" id=\"login-panel\">\n      <div class=\"brand-block login-brand\">\n        <div class=\"logo-mark\">EZ</div>\n        <div>\n          <div class=\"brand-name\" style=\"color:var(--text)\">Eazpire Partners</div>\n          <div class=\"brand-sub\" style=\"color:var(--muted)\">Admin Ops</div>\n        </div>\n      </div>\n      <h1>Sign in to Partner Ops</h1>\n      <p>Enter your authorized admin email. We will send a secure magic link — no Shopify login required.</p>\n      <form id=\"login-form\">\n        <div class=\"field\">\n          <label for=\"login-email\">Email</label>\n          <input class=\"input\" id=\"login-email\" type=\"email\" required autocomplete=\"email\" placeholder=\"you@eazpire.com\" />\n        </div>\n        <button class=\"btn btn-primary\" type=\"submit\" style=\"width:100%\">Send magic link</button>\n      </form>\n      <p id=\"login-message\" class=\"login-message\"></p>\n    </div>\n  </div>\n\n  <div id=\"app-loading\" class=\"partner-screen\" hidden>\n    <div class=\"login-card admin-login-card\">\n      <div class=\"logo-mark\" style=\"margin-bottom:14px\">EZ</div>\n      <h1>Partner Ops</h1>\n      <p>Checking admin session…</p>\n    </div>\n  </div>\n\n  <div id=\"modal-backdrop\" class=\"modal-backdrop\" hidden>\n    <div class=\"modal\" role=\"dialog\" aria-modal=\"true\">\n      <div class=\"modal-head\">\n        <h3 id=\"modal-title\">Modal</h3>\n        <button type=\"button\" class=\"icon-btn\" id=\"modal-close\" aria-label=\"Close\">×</button>\n      </div>\n      <div class=\"modal-body\" id=\"modal-body\"></div>\n      <div class=\"modal-foot\">\n        <button type=\"button\" class=\"btn btn-secondary\" id=\"modal-cancel\">Cancel</button>\n        <button type=\"button\" class=\"btn btn-primary\" id=\"modal-save\">Save</button>\n      </div>\n    </div>\n  </div>\n  <div id=\"partner-toast\" class=\"toast\"><strong></strong><span></span></div>\n  <script>window.__PARTNER_API_BASE__ = window.location.origin + \"/partner\";</script>\n  <script type=\"module\" src=\"/partner/js/app.js\"></script>\n</body>\n</html>\n"},"admin-partner/js/app.js":{"contentType":"application/javascript; charset=utf-8","body":"import { partnerFetch, badgeForStatus, escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { initShell, openModal, closeModal, confirmAction, openActionModeModal, showToast, renderTable, setTopbarExtra } from \"/partner/shared/js/partner-shell.js\";\nimport { openProductEditor } from \"./catalog-editor/shell.js\";\n\nconst NAV_CORE = [\n  { route: \"/partner\", label: \"Command Center\", icon: \"⌘\" },\n  { route: \"/partner/manufacturers\", label: \"Manufacturers\", icon: \"🏭\" },\n  { route: \"/partner/catalog\", label: \"Catalog Studio\", icon: \"▦\" },\n  { route: \"/partner/orders\", label: \"Order Ops\", icon: \"↗\" },\n  { route: \"/partner/api\", label: \"API Console\", icon: \"{ }\" },\n  { route: \"/partner/certification\", label: \"Certification HQ\", icon: \"✓\" },\n];\n\nconst NETWORK_TABS = [\n  { key: \"pending\", label: \"Pending\" },\n  { key: \"approved\", label: \"Approved\" },\n  { key: \"rejected\", label: \"Rejected\" },\n  { key: \"suspended\", label: \"Suspended\" },\n  { key: \"blocked\", label: \"Blocked\" },\n];\n\nconst CRUMB_LABELS = {\n  \"/partner\": \"Command Center\",\n  \"/partner/manufacturers\": \"Manufacturers\",\n  \"/partner/catalog\": \"Catalog Studio\",\n  \"/partner/orders\": \"Order Ops\",\n  \"/partner/api\": \"API Console\",\n  \"/partner/certification\": \"Certification HQ\",\n  \"/partner/requests\": \"Partner Requests\",\n};\n\nconst THEME_BY_ROUTE = {\n  \"/partner\": \"\",\n  \"/partner/manufacturers\": \"\",\n  \"/partner/catalog\": \"theme-studio\",\n  \"/partner/orders\": \"theme-ops\",\n  \"/partner/api\": \"theme-api\",\n  \"/partner/certification\": \"theme-cert\",\n  \"/partner/requests\": \"\",\n};\n\nconst COMMAND_TIME_RANGES = [\n  { key: \"today\", label: \"Today\" },\n  { key: \"7d\", label: \"7 days\" },\n  { key: \"30d\", label: \"30 days\" },\n];\n\nfunction getCommandTimeRange() {\n  const stored = sessionStorage.getItem(\"admin_command_time_range\");\n  return COMMAND_TIME_RANGES.some((r) => r.key === stored) ? stored : \"today\";\n}\n\nfunction commandTimeTabsHtml(activeKey) {\n  return `<div class=\"pill-tabs\" role=\"tablist\">${COMMAND_TIME_RANGES.map(\n    (r) =>\n      `<button type=\"button\" class=\"pill-tab ${activeKey === r.key ? \"active\" : \"\"}\" data-command-time=\"${r.key}\">${r.label}</button>`\n  ).join(\"\")}</div>`;\n}\n\nconst CATALOG_STUDIO_TABS = [\n  { key: \"partners\", label: \"Partners\" },\n  { key: \"eazpire\", label: \"Eazpire Products\" },\n  { key: \"review\", label: \"Review Queue\" },\n];\n\nfunction getCatalogStudioTab() {\n  const tab = sessionStorage.getItem(\"admin_catalog_studio_tab\") || \"partners\";\n  return CATALOG_STUDIO_TABS.some((t) => t.key === tab) ? tab : \"partners\";\n}\n\nfunction setCatalogStudioTab(tab) {\n  sessionStorage.setItem(\"admin_catalog_studio_tab\", tab);\n  renderCatalog();\n}\n\nfunction getCatalogTab() {\n  const tab = sessionStorage.getItem(\"admin_catalog_tab\") || \"products\";\n  return tab === \"blueprints\" ? \"blueprints\" : \"products\";\n}\n\nfunction setCatalogTab(tab) {\n  sessionStorage.setItem(\"admin_catalog_tab\", tab === \"blueprints\" ? \"blueprints\" : \"products\");\n  renderCatalog();\n}\n\nfunction getNetworkTab() {\n  const fromUrl = new URLSearchParams(location.search).get(\"tab\");\n  if (fromUrl && NETWORK_TABS.some((t) => t.key === fromUrl)) return fromUrl;\n  const stored = sessionStorage.getItem(\"admin_network_tab\");\n  if (stored && NETWORK_TABS.some((t) => t.key === stored)) return stored;\n  return \"pending\";\n}\n\nfunction setNetworkTab(tab) {\n  sessionStorage.setItem(\"admin_network_tab\", tab);\n  const url = new URL(location.href);\n  if (tab === \"approved\") url.searchParams.delete(\"tab\");\n  else url.searchParams.set(\"tab\", tab);\n  history.replaceState({}, \"\", url.pathname + url.search);\n  renderManufacturers();\n}\n\nfunction formatNetworkDate(ts) {\n  if (!ts) return \"—\";\n  return new Date(ts).toLocaleDateString(undefined, { year: \"numeric\", month: \"short\", day: \"numeric\" });\n}\n\nfunction priorHistoryLabel(event) {\n  const date = formatNetworkDate(event.at);\n  if (event.type === \"rejected\") return `Rejected on ${date}`;\n  if (event.type === \"suspended\") return `Suspended on ${date}`;\n  return `Prior event on ${date}`;\n}\n\nfunction priorHistoryHtml(history) {\n  if (!history?.length) return \"\";\n  return `<div class=\"prior-history-list\">${history\n    .map((event) => {\n      const payload = encodeURIComponent(JSON.stringify(event));\n      return `<button type=\"button\" class=\"prior-history-chip\" data-prior=\"${payload}\">${escapeHtml(priorHistoryLabel(event))}</button>`;\n    })\n    .join(\"\")}</div>`;\n}\n\nfunction openReasonInfoModal({ title, subtitle, reason, dateLabel, dateValue }) {\n  openModal({\n    title,\n    bodyHtml: `\n      ${subtitle ? `<p class=\"confirm-modal-message\">${escapeHtml(subtitle)}</p>` : \"\"}\n      ${dateLabel ? `<p><strong>${escapeHtml(dateLabel)}:</strong> ${escapeHtml(dateValue || \"—\")}</p>` : \"\"}\n      <div class=\"field\" style=\"margin-top:12px\">\n        <label>Reason</label>\n        <div class=\"info-reason-box\">${reason ? escapeHtml(reason) : \"No reason was provided.\"}</div>\n      </div>`,\n    onSave: null,\n  });\n  const saveBtn = document.getElementById(\"modal-save\");\n  if (saveBtn) saveBtn.style.display = \"none\";\n}\n\nfunction openPriorHistoryModal(event) {\n  const title = event.type === \"rejected\" ? \"Previous rejection\" : \"Previous suspension\";\n  openReasonInfoModal({\n    title,\n    subtitle: event.company_name ? `Company: ${event.company_name}` : \"\",\n    dateLabel: event.type === \"rejected\" ? \"Rejected on\" : \"Suspended on\",\n    dateValue: formatNetworkDate(event.at),\n    reason: event.reason,\n  });\n}\n\nfunction initials(name) {\n  return String(name || \"?\")\n    .split(/\\s+/)\n    .slice(0, 2)\n    .map((w) => w[0]?.toUpperCase() || \"\")\n    .join(\"\");\n}\n\nfunction entityCell(name, sub = \"\") {\n  return `<div class=\"entity\"><div class=\"avatar\">${escapeHtml(initials(name))}</div><div><strong>${escapeHtml(name)}</strong>${sub ? `<span>${escapeHtml(sub)}</span>` : \"\"}</div></div>`;\n}\n\nfunction stageHeading(kicker, title, desc, actionsHtml = \"\") {\n  return `<div class=\"stage-heading\"><div><div class=\"stage-kicker\">${escapeHtml(kicker)}</div><h1 class=\"stage-title\">${escapeHtml(title)}</h1><p class=\"stage-desc\">${escapeHtml(desc)}</p></div>${actionsHtml}</div>`;\n}\n\nfunction applyRouteTheme(route) {\n  const body = document.body;\n  body.classList.remove(\"theme-studio\", \"theme-ops\", \"theme-api\", \"theme-cert\");\n  const theme = THEME_BY_ROUTE[route];\n  if (theme) body.classList.add(theme);\n}\n\nasync function ensureAdminSession() {\n  try {\n    await partnerFetch(\"admin-auth-me\");\n    return true;\n  } catch {\n    return false;\n  }\n}\n\nfunction showLogin(authErrorCode = \"\") {\n  document.getElementById(\"app-login\").hidden = false;\n  document.getElementById(\"app-shell\").hidden = true;\n  const loading = document.getElementById(\"app-loading\");\n  if (loading) loading.hidden = true;\n  const msg = document.getElementById(\"login-message\");\n  if (msg && authErrorCode) {\n    const messages = {\n      invalid_or_expired_token: \"This sign-in link is invalid or has expired. Request a new link below.\",\n      token_already_used:\n        \"This sign-in link was already used (often by an email security scanner). Request a new link below.\",\n      token_required: \"Sign-in link is missing. Request a new link below.\",\n    };\n    msg.textContent = messages[authErrorCode] || \"Sign-in failed. Request a new link below.\";\n  }\n}\n\nfunction showShell() {\n  document.getElementById(\"app-login\").hidden = true;\n  document.getElementById(\"app-shell\").hidden = false;\n  const loading = document.getElementById(\"app-loading\");\n  if (loading) loading.hidden = true;\n}\n\nfunction manufacturerModeBadge(m) {\n  if (m.api_enabled || m.integration_mode === \"api\") return \"badge-purple\";\n  return \"badge-neutral\";\n}\n\nfunction manufacturerModeLabel(m) {\n  if (m.api_enabled || m.integration_mode === \"api\") return \"API Partner\";\n  return \"Portal\";\n}\n\nasync function renderCommand() {\n  setTopbarExtra(\"\");\n  const el = document.getElementById(\"view-command\");\n  const timeRange = getCommandTimeRange();\n  // TODO: pass timeRange to admin-manufacturer-network-overview when API supports days filter\n  const data = await partnerFetch(\"admin-manufacturer-network-overview\");\n  const kpis = data.kpis || {};\n  const health = data.manufacturer_health || [];\n  const alerts = data.alerts || [];\n  const atRisk = Number(kpis.at_risk ?? 0);\n  const timeLabel = COMMAND_TIME_RANGES.find((r) => r.key === timeRange)?.label || \"Today\";\n\n  el.innerHTML = `\n    ${stageHeading(\n      \"Overview\",\n      \"Command Center\",\n      \"Network health, risk radar, and manufacturer onboarding pipeline.\",\n      commandTimeTabsHtml(timeRange)\n    )}\n    <p class=\"command-time-hint\">Showing all-time network data · selected range: ${escapeHtml(timeLabel)} (V1)</p>\n    <div class=\"kpi-grid\">\n      <div class=\"kpi-card\"><div class=\"kpi-label\">Active Manufacturers</div><div class=\"kpi-value\">${escapeHtml(kpis.manufacturers_total ?? 0)}</div><div class=\"kpi-trend\">↗ network total</div></div>\n      <div class=\"kpi-card\"><div class=\"kpi-label\">Catalog Products</div><div class=\"kpi-value\">${escapeHtml(kpis.catalog_products ?? 0)}</div><div class=\"kpi-trend\">↗ in network</div></div>\n      <div class=\"kpi-card\"><div class=\"kpi-label\">Open Orders</div><div class=\"kpi-value\">${escapeHtml(kpis.orders_open ?? 0)}</div><div class=\"kpi-trend ${atRisk ? \"is-warning\" : \"\"}\">${atRisk ? `⚠ ${atRisk} at risk` : \"✓ on track\"}</div></div>\n      <div class=\"kpi-card\"><div class=\"kpi-label\">Avg Quality Score</div><div class=\"kpi-value\">${escapeHtml(kpis.avg_quality_score ?? \"—\")}</div><div class=\"kpi-trend\">✓ certified network</div></div>\n    </div>\n    <div class=\"content-grid\">\n      <div class=\"panel map-panel\">\n        <div class=\"map-grid\"></div>\n        <div class=\"node a\"><h4>Manufacturers</h4><p>${escapeHtml(kpis.manufacturers_total ?? 0)} in network</p></div>\n        <div class=\"node b\"><h4>Pending review</h4><p>${escapeHtml(kpis.products_pending ?? 0)} products</p></div>\n        <div class=\"node c\"><h4>Open orders</h4><p>${escapeHtml(kpis.orders_open ?? 0)} active</p></div>\n        <div class=\"node d\"><h4>Quality avg</h4><p>${escapeHtml(kpis.avg_quality_score ?? \"—\")} score</p></div>\n      </div>\n      <div class=\"panel\">\n        <div class=\"panel-header\">\n          <div><h2 class=\"panel-title\">Risk Radar</h2><p class=\"panel-subtitle\">Items needing operator attention</p></div>\n          ${alerts.length ? `<span class=\"badge badge-warning\">${alerts.length} alerts</span>` : `<span class=\"badge badge-success\">Clear</span>`}\n        </div>\n        <div class=\"panel-body timeline\">\n          ${\n            alerts.length\n              ? alerts\n                  .map(\n                    (a, i) => `<div class=\"timeline-item\"><div class=\"dot\">${i + 1}</div><div class=\"timeline-content\"><strong>${escapeHtml(a.title)}</strong><p>${escapeHtml(a.detail || \"\")}</p></div></div>`\n                  )\n                  .join(\"\")\n              : `<div class=\"empty-state\"><div class=\"icon\">✓</div><h3>All clear</h3><p>No network alerts require attention right now.</p></div>`\n          }\n        </div>\n      </div>\n    </div>\n    <div class=\"panel\" style=\"margin-top:18px\">\n      <div class=\"panel-header\">\n        <div><h2 class=\"panel-title\">Manufacturer Health</h2><p class=\"panel-subtitle\">Listview for partner operations</p></div>\n      </div>\n      ${renderTable(\n        [\"Manufacturer\", \"Region\", \"Mode\", \"Quality\", \"Status\", \"Action\"],\n        health\n          .map(\n            (m) => `<tr>\n          <td>${entityCell(m.name, m.product_focus || m.owner_email || \"\")}</td>\n          <td>${escapeHtml(m.country || \"—\")}</td>\n          <td><span class=\"badge ${manufacturerModeBadge(m)}\">${manufacturerModeLabel(m)}</span></td>\n          <td>${escapeHtml(m.quality_score ?? \"—\")}</td>\n          <td><span class=\"badge ${badgeForStatus(m.status)}\">${escapeHtml(m.status)}</span></td>\n          <td><button type=\"button\" class=\"btn btn-secondary btn-open-mfg\" data-id=\"${escapeHtml(m.id)}\">Open</button></td>\n        </tr>`\n          )\n          .join(\"\") || '<tr><td colspan=\"6\" class=\"empty\">No manufacturers yet</td></tr>'\n      )}\n    </div>`;\n\n  el.querySelectorAll(\"[data-command-time]\").forEach((btn) => {\n    btn.onclick = () => {\n      sessionStorage.setItem(\"admin_command_time_range\", btn.dataset.commandTime);\n      renderCommand();\n    };\n  });\n\n  el.querySelectorAll(\".btn-open-mfg\").forEach((btn) => {\n    btn.onclick = () => navigateToManufacturers();\n  });\n}\n\nfunction navigateToManufacturers() {\n  const nav = document.querySelector('[data-route=\"/partner/manufacturers\"]');\n  nav?.click();\n}\n\nasync function renderManufacturers() {\n  setTopbarExtra(`<button type=\"button\" class=\"btn btn-primary\" id=\"btn-invite\">Invite Partner</button>`);\n  const el = document.getElementById(\"view-manufacturers\");\n  const tab = getNetworkTab();\n  const { board } = await partnerFetch(\"admin-manufacturer-network-board\");\n  const counts = board?.counts || {};\n\n  const tabsHtml = NETWORK_TABS.map(\n    (t) =>\n      `<button type=\"button\" class=\"pill-tab ${tab === t.key ? \"active\" : \"\"}\" data-network-tab=\"${t.key}\">${escapeHtml(t.label)}${counts[t.key] ? `<span class=\"pill-tab-count\">${counts[t.key]}</span>` : \"\"}</button>`\n  ).join(\"\");\n\n  el.innerHTML = `\n    ${stageHeading(\n      \"Core Portal\",\n      \"Manufacturers\",\n      \"Review applications and manage approved partners in the Eazpire manufacturer network.\",\n      `<button type=\"button\" class=\"btn btn-primary\" id=\"btn-invite-heading\">Invite Partner</button>`\n    )}\n    <div class=\"catalog-toolbar\" style=\"margin-bottom:14px\">\n      <div class=\"pill-tabs\">${tabsHtml}</div>\n    </div>\n    <div class=\"panel\">\n      <div class=\"panel-header\">\n        <div><h2 class=\"panel-title\">${escapeHtml(NETWORK_TABS.find((t) => t.key === tab)?.label || \"Network\")}</h2><p class=\"panel-subtitle\">${escapeHtml(networkTabSubtitle(tab))}</p></div>\n        <span class=\"badge badge-neutral\">${escapeHtml(String(counts[tab] ?? 0))}</span>\n      </div>\n      <div class=\"panel-body\">${renderNetworkTabPanel(tab, board)}</div>\n    </div>`;\n\n  el.querySelectorAll(\"[data-network-tab]\").forEach((btn) => {\n    btn.onclick = () => setNetworkTab(btn.dataset.networkTab);\n  });\n\n  const openInvite = () => inviteManufacturerModal(el);\n  document.getElementById(\"btn-invite\")?.addEventListener(\"click\", openInvite);\n  document.getElementById(\"btn-invite-heading\")?.addEventListener(\"click\", openInvite);\n\n  bindNetworkTabActions(el, tab);\n}\n\nfunction networkTabSubtitle(tab) {\n  const map = {\n    pending: \"Applications awaiting operator decision\",\n    approved: \"Verified partners active in the network\",\n    rejected: \"Declined partner applications\",\n    suspended: \"Partners with suspended portal access\",\n    blocked: \"Emails blocked from new applications\",\n  };\n  return map[tab] || \"\";\n}\n\nfunction renderNetworkTabPanel(tab, board) {\n  if (tab === \"pending\") return renderPendingPanel(board?.pending || []);\n  if (tab === \"approved\") return renderApprovedPanel(board?.approved || []);\n  if (tab === \"rejected\") return renderRejectedPanel(board?.rejected || []);\n  if (tab === \"suspended\") return renderSuspendedPanel(board?.suspended || []);\n  if (tab === \"blocked\") return renderBlockedPanel(board?.blocked || []);\n  return `<div class=\"empty-state\"><p>No data</p></div>`;\n}\n\nfunction renderPendingPanel(applications) {\n  return renderTable(\n    [\"Company\", \"Contact\", \"Email\", \"Country\", \"Status\", \"Actions\"],\n    applications\n      .map((app) => {\n        const historyHtml = priorHistoryHtml(app.prior_history);\n        const companyCell = `${entityCell(app.company_name, app.product_types || \"\")}${historyHtml}`;\n        const actions =\n          app.status === \"pending_review\"\n            ? `<button type=\"button\" class=\"btn btn-primary btn-app-approve\" data-id=\"${escapeHtml(app.id)}\">Approve</button>\n               <button type=\"button\" class=\"btn btn-ghost btn-app-reject\" data-id=\"${escapeHtml(app.id)}\" data-name=\"${escapeHtml(app.company_name)}\">Reject</button>`\n            : `<span class=\"stage-desc\">Awaiting email verify</span>`;\n        return `<tr>\n          <td>${companyCell}</td>\n          <td>${escapeHtml(app.contact_name)}</td>\n          <td>${escapeHtml(app.email)}</td>\n          <td>${escapeHtml(app.country || \"—\")}</td>\n          <td><span class=\"badge ${badgeForStatus(app.status)}\">${escapeHtml(app.status)}</span></td>\n          <td>${actions}</td>\n        </tr>`;\n      })\n      .join(\"\") || '<tr><td colspan=\"6\" class=\"empty\">No pending applications</td></tr>'\n  );\n}\n\nfunction renderApprovedPanel(manufacturers) {\n  return renderTable(\n    [\"Manufacturer\", \"Region\", \"Mode\", \"Quality\", \"Status\", \"Actions\"],\n    manufacturers\n      .map(\n        (m) => `<tr>\n          <td>${entityCell(m.name, m.owner_email || \"\")}</td>\n          <td>${escapeHtml(m.country || \"—\")}</td>\n          <td><span class=\"badge ${manufacturerModeBadge(m)}\">${manufacturerModeLabel(m)}</span></td>\n          <td>${escapeHtml(m.quality_score ?? \"—\")}</td>\n          <td><span class=\"badge ${badgeForStatus(m.status)}\">${escapeHtml(m.status)}</span></td>\n          <td>\n            ${m.status === \"approved_for_test\" ? `<button type=\"button\" class=\"btn btn-secondary btn-approve\" data-id=\"${escapeHtml(m.id)}\" data-name=\"${escapeHtml(m.name)}\">Verify</button>` : \"\"}\n            <button type=\"button\" class=\"btn btn-ghost btn-suspend\" data-id=\"${escapeHtml(m.id)}\" data-name=\"${escapeHtml(m.name)}\">Suspend</button>\n          </td>\n        </tr>`\n      )\n      .join(\"\") || '<tr><td colspan=\"6\" class=\"empty\">No approved manufacturers</td></tr>'\n  );\n}\n\nfunction renderRejectedPanel(applications) {\n  return renderTable(\n    [\"Company\", \"Contact\", \"Email\", \"Rejected\", \"Actions\"],\n    applications\n      .map((app) => {\n        const reasonPayload = encodeURIComponent(JSON.stringify({ type: \"rejected\", reason: app.rejection_reason, at: app.reviewed_at, company_name: app.company_name }));\n        return `<tr>\n          <td>${entityCell(app.company_name, app.product_types || \"\")}</td>\n          <td>${escapeHtml(app.contact_name)}</td>\n          <td>${escapeHtml(app.email)}</td>\n          <td>${escapeHtml(formatNetworkDate(app.reviewed_at))}</td>\n          <td><button type=\"button\" class=\"btn btn-ghost btn-reason-info\" data-reason=\"${reasonPayload}\">View reason</button></td>\n        </tr>`;\n      })\n      .join(\"\") || '<tr><td colspan=\"5\" class=\"empty\">No rejected applications</td></tr>'\n  );\n}\n\nfunction renderSuspendedPanel(manufacturers) {\n  return renderTable(\n    [\"Manufacturer\", \"Email\", \"Region\", \"Suspended\", \"Actions\"],\n    manufacturers\n      .map((m) => {\n        const reasonPayload = encodeURIComponent(\n          JSON.stringify({ type: \"suspended\", reason: m.suspend_reason, at: m.suspended_at, company_name: m.name })\n        );\n        return `<tr>\n          <td>${entityCell(m.name, m.country || \"\")}</td>\n          <td>${escapeHtml(m.owner_email || \"—\")}</td>\n          <td>${escapeHtml(m.country || \"—\")}</td>\n          <td>${escapeHtml(formatNetworkDate(m.suspended_at))}</td>\n          <td>\n            <button type=\"button\" class=\"btn btn-secondary btn-reactivate\" data-id=\"${escapeHtml(m.id)}\" data-name=\"${escapeHtml(m.name)}\">Reactivate</button>\n            <button type=\"button\" class=\"btn btn-ghost btn-reason-info\" data-reason=\"${reasonPayload}\">View reason</button>\n          </td>\n        </tr>`;\n      })\n      .join(\"\") || '<tr><td colspan=\"5\" class=\"empty\">No suspended manufacturers</td></tr>'\n  );\n}\n\nfunction renderBlockedPanel(blocks) {\n  return renderTable(\n    [\"Email\", \"Blocked\", \"Reason\", \"Actions\"],\n    blocks\n      .map((row) => {\n        const reasonPayload = encodeURIComponent(JSON.stringify({ type: \"blocked\", reason: row.reason, at: row.blocked_at, email: row.email }));\n        return `<tr>\n          <td>${escapeHtml(row.email)}</td>\n          <td>${escapeHtml(formatNetworkDate(row.blocked_at))}</td>\n          <td>${row.reason ? escapeHtml(row.reason.slice(0, 80)) : \"—\"}</td>\n          <td><button type=\"button\" class=\"btn btn-ghost btn-reason-info\" data-reason=\"${reasonPayload}\">View details</button></td>\n        </tr>`;\n      })\n      .join(\"\") || '<tr><td colspan=\"4\" class=\"empty\">No blocked emails</td></tr>'\n  );\n}\n\nfunction bindNetworkTabActions(root) {\n  root.querySelectorAll(\".prior-history-chip\").forEach((btn) => {\n    btn.onclick = () => {\n      try {\n        openPriorHistoryModal(JSON.parse(decodeURIComponent(btn.dataset.prior || \"%7B%7D\")));\n      } catch {\n        showToast(\"Error\", \"Could not load history details\");\n      }\n    };\n  });\n\n  root.querySelectorAll(\".btn-reason-info\").forEach((btn) => {\n    btn.onclick = () => {\n      try {\n        const data = JSON.parse(decodeURIComponent(btn.dataset.reason || \"%7B%7D\"));\n        if (data.type === \"blocked\") {\n          openReasonInfoModal({\n            title: \"Blocked email\",\n            subtitle: data.email || \"\",\n            dateLabel: \"Blocked on\",\n            dateValue: formatNetworkDate(data.at),\n            reason: data.reason,\n          });\n          return;\n        }\n        openPriorHistoryModal(data);\n      } catch {\n        showToast(\"Error\", \"Could not load reason details\");\n      }\n    };\n  });\n\n  root.querySelectorAll(\".btn-app-approve\").forEach((btn) => {\n    btn.onclick = () => {\n      confirmAction({\n        title: \"Approve application\",\n        message: \"Approve this partner application? A manufacturer account and magic link will be created.\",\n        confirmLabel: \"Approve\",\n        onConfirm: async () => {\n          await partnerFetch(\"admin-partner-application-approve\", {\n            method: \"POST\",\n            body: { application_id: btn.dataset.id },\n          });\n          showToast(\"Application approved\", \"Magic link sent to applicant\");\n          await renderManufacturers();\n        },\n      });\n    };\n  });\n\n  root.querySelectorAll(\".btn-app-reject\").forEach((btn) => {\n    btn.onclick = () => {\n      const name = btn.dataset.name || \"this application\";\n      openActionModeModal({\n        title: \"Reject application\",\n        message: `Reject ${name}? The applicant will be notified by email.`,\n        modes: [\n          { value: \"reject\", label: \"Just Reject\", description: \"Decline this application. They may apply again later.\" },\n          { value: \"reject_block\", label: \"Reject and Block\", description: \"Decline and block this email from future applications.\" },\n        ],\n        defaultMode: \"reject\",\n        reasonPlaceholder: \"Optional note for the applicant (included in email)…\",\n        confirmLabels: { reject: \"Reject\", reject_block: \"Reject and Block\" },\n        confirmClasses: { reject_block: \"btn-danger\" },\n        onConfirm: async ({ mode, reason }) => {\n          await partnerFetch(\"admin-partner-application-reject\", {\n            method: \"POST\",\n            body: {\n              application_id: btn.dataset.id,\n              mode,\n              reason: reason || undefined,\n            },\n          });\n          showToast(\"Application rejected\", mode === \"reject_block\" ? \"Email blocked\" : \"\");\n          await renderManufacturers();\n        },\n      });\n    };\n  });\n\n  root.querySelectorAll(\".btn-approve\").forEach((btn) => {\n    btn.onclick = () => {\n      const name = btn.dataset.name || \"this manufacturer\";\n      confirmAction({\n        title: \"Verify manufacturer\",\n        message: `Verify ${name}? They will be fully approved in the partner network.`,\n        confirmLabel: \"Verify\",\n        onConfirm: async () => {\n          await partnerFetch(\"admin-manufacturer-approve\", { method: \"POST\", body: { manufacturer_id: btn.dataset.id } });\n          showToast(\"Verified\", \"Manufacturer fully approved\");\n          await renderManufacturers();\n        },\n      });\n    };\n  });\n\n  root.querySelectorAll(\".btn-suspend\").forEach((btn) => {\n    btn.onclick = () => {\n      const name = btn.dataset.name || \"this manufacturer\";\n      openActionModeModal({\n        title: \"Suspend manufacturer\",\n        message: `Suspend ${name}? They will lose partner portal access until reactivated.`,\n        modes: [\n          { value: \"suspend\", label: \"Suspend\", description: \"Revoke portal access. They may apply again later.\" },\n          { value: \"suspend_block\", label: \"Suspend and Block\", description: \"Revoke access and block this email from new applications.\" },\n        ],\n        defaultMode: \"suspend\",\n        reasonPlaceholder: \"Optional note for the partner (included in email)…\",\n        confirmLabels: { suspend: \"Suspend\", suspend_block: \"Suspend and Block\" },\n        confirmClasses: { suspend: \"btn-warning\", suspend_block: \"btn-danger\" },\n        onConfirm: async ({ mode, reason }) => {\n          await partnerFetch(\"admin-manufacturer-suspend\", {\n            method: \"POST\",\n            body: {\n              manufacturer_id: btn.dataset.id,\n              mode,\n              reason: reason || undefined,\n            },\n          });\n          showToast(\"Suspended\", mode === \"suspend_block\" ? \"Partner suspended and email blocked\" : \"Partner access revoked\");\n          await renderManufacturers();\n        },\n      });\n    };\n  });\n\n  root.querySelectorAll(\".btn-reactivate\").forEach((btn) => {\n    btn.onclick = () => {\n      const name = btn.dataset.name || \"this manufacturer\";\n      confirmAction({\n        title: \"Reactivate manufacturer\",\n        message: `Reactivate ${name}? They will regain partner portal access.`,\n        confirmLabel: \"Reactivate\",\n        onConfirm: async () => {\n          await partnerFetch(\"admin-manufacturer-reactivate\", { method: \"POST\", body: { manufacturer_id: btn.dataset.id } });\n          showToast(\"Reactivated\", \"Manufacturer access restored\");\n          await renderManufacturers();\n        },\n      });\n    };\n  });\n}\n\nfunction inviteManufacturerModal(el) {\n  openModal({\n    title: \"Invite manufacturer\",\n    bodyHtml: `\n      <div class=\"split-row\">\n        <div class=\"field\"><label>Company name</label><input class=\"input\" id=\"m-name\" /></div>\n        <div class=\"field\"><label>Country</label><input class=\"input\" id=\"m-country\" /></div>\n      </div>\n      <div class=\"field\"><label>Owner email</label><input class=\"input\" id=\"m-email\" type=\"email\" /></div>`,\n    onSave: async () => {\n      await partnerFetch(\"admin-manufacturer-create\", {\n        method: \"POST\",\n        body: {\n          name: document.getElementById(\"m-name\").value,\n          owner_email: document.getElementById(\"m-email\").value,\n          country: document.getElementById(\"m-country\").value,\n        },\n      });\n      showToast(\"Manufacturer invited\", \"Magic link sent to owner email\");\n      await renderManufacturers();\n    },\n  });\n}\n\nasync function renderCatalog() {\n  setTopbarExtra(\"\");\n  const el = document.getElementById(\"view-catalog\");\n  const studioTab = getCatalogStudioTab();\n  const { products: pendingProducts } = await partnerFetch(\"admin-manufacturer-product-list\", {\n    query: { status: \"pending_review\" },\n  });\n  const { blueprints: pendingBlueprints } = await partnerFetch(\"admin-blueprint-list\", {\n    query: { status: \"pending_admin_review\" },\n  });\n  const pendingCount = (pendingProducts || []).length;\n  const blueprintCount = (pendingBlueprints || []).length;\n\n  el.innerHTML = `\n    ${stageHeading(\n      \"Catalog Studio\",\n      \"Catalog Studio\",\n      \"Manage partner catalogs, Eazpire shop products, and manufacturer review queues.\",\n      `<button type=\"button\" class=\"btn btn-secondary\" id=\"btn-catalog-mirror\">Mirror to publish index</button>\n       <button type=\"button\" class=\"btn btn-primary\" id=\"btn-catalog-refresh\">Refresh</button>`\n    )}\n    <div class=\"catalog-toolbar\" style=\"margin-bottom:16px\">\n      <div class=\"pill-tabs\">\n        ${CATALOG_STUDIO_TABS.map(\n          (t) =>\n            `<button type=\"button\" class=\"pill-tab ${studioTab === t.key ? \"active\" : \"\"}\" data-studio-tab=\"${t.key}\">${t.label}${\n              t.key === \"review\" ? ` (${pendingCount + blueprintCount})` : \"\"\n            }</button>`\n        ).join(\"\")}\n      </div>\n    </div>\n    <div id=\"admin-catalog-panel\"></div>`;\n\n  el.querySelectorAll(\"[data-studio-tab]\").forEach((btn) => {\n    btn.onclick = () => setCatalogStudioTab(btn.dataset.studioTab);\n  });\n  document.getElementById(\"btn-catalog-refresh\").onclick = () => renderCatalog();\n  document.getElementById(\"btn-catalog-mirror\").onclick = async () => {\n    const result = await partnerFetch(\"admin-eazpire-catalog-mirror-run\", { method: \"POST\", body: {} });\n    showToast(\"Mirror complete\", `${result.mirrored ?? 0} product(s) synced to publish index`);\n    await renderCatalog();\n  };\n\n  const panel = document.getElementById(\"admin-catalog-panel\");\n  if (studioTab === \"partners\") await renderPartnerCatalogPanel(panel);\n  else if (studioTab === \"eazpire\") await renderEazpireProductsPanel(panel);\n  else await renderCatalogReviewPanel(panel, pendingProducts || [], pendingBlueprints || []);\n}\n\nasync function renderPartnerCatalogPanel(panel) {\n  const { partners } = await partnerFetch(\"admin-partner-list\");\n  const printify = (partners || []).find((p) => p.slug === \"printify\") || partners?.[0];\n  let providers = [];\n  let blueprints = [];\n  if (printify) {\n    const provData = await partnerFetch(\"admin-partner-fulfillment-providers\", {\n      query: { manufacturer_id: printify.id },\n    });\n    providers = provData.providers || [];\n    const bpData = await partnerFetch(\"admin-partner-catalog-blueprints\", {\n      query: { manufacturer_id: printify.id, status: \"live\" },\n    });\n    blueprints = bpData.blueprints || [];\n  }\n\n  panel.innerHTML = `\n    <div class=\"split-row\" style=\"align-items:flex-start;gap:16px\">\n      <div class=\"panel\" style=\"flex:1\">\n        <div class=\"panel-header\">\n          <div><h2 class=\"panel-title\">Partners</h2><p class=\"panel-subtitle\">Fulfillment aggregators & manufacturers</p></div>\n          <button type=\"button\" class=\"btn btn-primary\" id=\"btn-sync-printify\">Sync Printify catalog</button>\n        </div>\n        <div class=\"panel-body\">${renderTable(\n          [\"Partner\", \"Type\", \"Sub-providers\", \"Blueprints\", \"Eazpire products\"],\n          (partners || [])\n            .map(\n              (p) => `<tr>\n            <td>${entityCell(p.name, p.slug)}</td>\n            <td>${escapeHtml(p.integration_type)}</td>\n            <td>${escapeHtml(p.fulfillment_provider_count ?? 0)}</td>\n            <td>${escapeHtml(p.live_blueprint_count ?? 0)}</td>\n            <td>${escapeHtml(p.eazpire_product_count ?? 0)}</td>\n          </tr>`\n            )\n            .join(\"\")\n        )}</div>\n      </div>\n      <div class=\"panel\" style=\"flex:1\">\n        <div class=\"panel-header\"><div><h2 class=\"panel-title\">${escapeHtml(printify?.name || \"Partner\")} — Sub-providers</h2></div></div>\n        <div class=\"panel-body\">${providers.length ? renderTable(\n          [\"Name\", \"External ID\", \"Status\"],\n          providers\n            .map(\n              (fp) => `<tr>\n            <td>${escapeHtml(fp.name)}</td>\n            <td>${escapeHtml(fp.external_provider_id)}</td>\n            <td><span class=\"badge badge-success\">${escapeHtml(fp.status)}</span></td>\n          </tr>`\n            )\n            .join(\"\")\n        ) : `<div class=\"empty-state\"><p>No sub-providers synced yet. Run Printify sync.</p></div>`}</div>\n      </div>\n    </div>\n    <div class=\"panel\" style=\"margin-top:16px\">\n      <div class=\"panel-header\"><div><h2 class=\"panel-title\">Partner catalog (live blueprints)</h2><p class=\"panel-subtitle\">${blueprints.length} blueprint(s)</p></div></div>\n      <div class=\"panel-body\">${blueprints.length ? renderTable(\n        [\"Title\", \"Category\", \"Quality\", \"Updated\"],\n        blueprints\n          .slice(0, 50)\n          .map(\n            (b) => `<tr>\n          <td>${escapeHtml(b.title)}</td>\n          <td>${escapeHtml(b.normalized_category || \"—\")}</td>\n          <td>${escapeHtml(b.quality_score ?? \"—\")}</td>\n          <td>${escapeHtml(b.updated_at ? new Date(b.updated_at).toLocaleDateString() : \"—\")}</td>\n        </tr>`\n          )\n          .join(\"\")\n      ) : `<div class=\"empty-state\"><p>Run Printify sync to import blueprints for online products.</p></div>`}</div>\n    </div>`;\n\n  document.getElementById(\"btn-sync-printify\").onclick = async () => {\n    try {\n      showToast(\"Syncing Printify…\", \"Online products only\");\n      const result = await partnerFetch(\"admin-partner-sync-printify\", { method: \"POST\", body: {} });\n      const s = result.sync?.synced || {};\n      showToast(\"Printify sync complete\", `${s.blueprints ?? 0} blueprint(s), ${result.import?.count ?? 0} product(s) imported`);\n      await renderCatalog();\n    } catch (e) {\n      const hint = e.data?.hint ? String(e.data.hint).slice(0, 120) : \"\";\n      showToast(\"Sync failed\", `${e.message}${hint ? \" — \" + hint : \"\"}`);\n    }\n  };\n}\n\nasync function renderEazpireProductsPanel(panel) {\n  const { products } = await partnerFetch(\"admin-eazpire-product-list\");\n  let driftHtml = \"\";\n  try {\n    const drift = await partnerFetch(\"admin-eazpire-catalog-mirror-status-v2\");\n    driftHtml = `<p class=\"panel-subtitle\">${drift.in_sync ?? 0} / ${drift.total ?? 0} in sync with publish index (drift v2)</p>`;\n  } catch {\n    driftHtml = \"\";\n  }\n\n  panel.innerHTML = `\n    <div class=\"panel\">\n      <div class=\"panel-header\">\n        <div><h2 class=\"panel-title\">Eazpire shop products</h2>${driftHtml}</div>\n        <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-import-catalog\">Import from publish index</button>\n      </div>\n      <div class=\"panel-body\">${(products || []).length ? renderTable(\n        [\"Product key\", \"Title\", \"Status\", \"Versions\", \"\"],\n        (products || [])\n          .map(\n            (p) => `<tr>\n          <td><code>${escapeHtml(p.product_key)}</code></td>\n          <td>${escapeHtml(p.title)}</td>\n          <td><span class=\"badge ${p.catalog_status === \"online\" ? \"badge-success\" : \"badge-secondary\"}\">${escapeHtml(p.catalog_status)}</span></td>\n          <td>${escapeHtml(p.version_count ?? 0)}</td>\n          <td><button type=\"button\" class=\"btn btn-primary btn-sm btn-edit-eaz-product\" data-key=\"${escapeHtml(p.product_key)}\">Edit</button></td>\n        </tr>`\n          )\n          .join(\"\")\n      ) : `<div class=\"empty-state\"><h3>No Eazpire products yet</h3><p>Run Printify sync or import from publish index.</p></div>`}</div>\n    </div>`;\n\n  document.getElementById(\"btn-import-catalog\").onclick = async () => {\n    const result = await partnerFetch(\"admin-eazpire-catalog-import\", { method: \"POST\", body: {} });\n    showToast(\"Import complete\", `${result.count ?? 0} online product(s)`);\n    await renderCatalog();\n  };\n\n  panel.querySelectorAll(\".btn-edit-eaz-product\").forEach((btn) => {\n    btn.onclick = () => openProductEditor(btn.dataset.key);\n  });\n}\n\nasync function renderCatalogReviewPanel(panel, pendingProducts, pendingBlueprints) {\n  const tab = getCatalogTab();\n  panel.innerHTML = `\n    <div class=\"catalog-toolbar\">\n      <div class=\"pill-tabs\">\n        <button type=\"button\" class=\"pill-tab ${tab === \"products\" ? \"active\" : \"\"}\" data-admin-tab=\"products\">Product review (${pendingProducts.length})</button>\n        <button type=\"button\" class=\"pill-tab ${tab === \"blueprints\" ? \"active\" : \"\"}\" data-admin-tab=\"blueprints\">Blueprint review (${pendingBlueprints.length})</button>\n      </div>\n    </div>\n    <div id=\"admin-catalog-review-inner\"></div>`;\n  panel.querySelectorAll(\"[data-admin-tab]\").forEach((btn) => {\n    btn.onclick = () => setCatalogTab(btn.dataset.adminTab);\n  });\n  const inner = document.getElementById(\"admin-catalog-review-inner\");\n  if (tab === \"blueprints\") await renderBlueprintReview(inner, pendingBlueprints);\n  else await renderProductReview(inner, pendingProducts);\n}\n\nasync function renderProductReview(panel, products) {\n  if (!products?.length) {\n    panel.innerHTML = `<div class=\"empty-state\"><div class=\"icon\">▦</div><h3>No products pending</h3><p>Manufacturer product submissions will appear here for review.</p></div>`;\n    return;\n  }\n\n  panel.innerHTML = `<div class=\"card-grid catalog-grid\">${products\n    .map(\n      (p) => `<article class=\"product-card\">\n      <div class=\"product-image\">📦</div>\n      <div class=\"product-card-content\">\n        <h3>${escapeHtml(p.title)}</h3>\n        <p>${escapeHtml(p.manufacturer_name || p.manufacturer_id)} · pending review</p>\n        <div class=\"meta-row\">\n          <span class=\"badge ${badgeForStatus(p.status)}\">${escapeHtml(p.status)}</span>\n          <div style=\"display:flex;gap:6px\">\n            <button type=\"button\" class=\"btn btn-primary btn-approve-product\" data-id=\"${escapeHtml(p.id)}\">Approve</button>\n            <button type=\"button\" class=\"btn btn-secondary btn-reject-product\" data-id=\"${escapeHtml(p.id)}\">Reject</button>\n          </div>\n        </div>\n      </div>\n    </article>`\n    )\n    .join(\"\")}</div>`;\n\n  panel.querySelectorAll(\".btn-approve-product\").forEach((btn) => {\n    btn.onclick = () => {\n      confirmAction({\n        title: \"Approve product\",\n        message: \"Approve this product for the catalog?\",\n        confirmLabel: \"Approve\",\n        onConfirm: async () => {\n          await partnerFetch(\"admin-manufacturer-product-review\", { method: \"POST\", body: { product_id: btn.dataset.id, approve: true } });\n          showToast(\"Product approved\", \"\");\n          await renderCatalog();\n        },\n      });\n    };\n  });\n  panel.querySelectorAll(\".btn-reject-product\").forEach((btn) => {\n    btn.onclick = () => {\n      confirmAction({\n        title: \"Reject product\",\n        message: \"Reject this product? The manufacturer will need to revise and resubmit.\",\n        confirmLabel: \"Reject\",\n        confirmClass: \"btn-danger\",\n        onConfirm: async () => {\n          await partnerFetch(\"admin-manufacturer-product-review\", { method: \"POST\", body: { product_id: btn.dataset.id, approve: false } });\n          showToast(\"Product rejected\", \"\");\n          await renderCatalog();\n        },\n      });\n    };\n  });\n}\n\nasync function renderBlueprintReview(panel, blueprints) {\n  if (!blueprints?.length) {\n    panel.innerHTML = `<div class=\"empty-state\"><div class=\"icon\">◈</div><h3>No blueprints pending</h3><p>Universal Blueprint submissions will appear here for admin review.</p></div>`;\n    return;\n  }\n\n  panel.innerHTML = `<div class=\"panel\"><div class=\"panel-header\"><div><h2 class=\"panel-title\">Blueprint queue</h2><p class=\"panel-subtitle\">Pending admin review</p></div></div>\n    ${renderTable(\n      [\"Blueprint\", \"Manufacturer\", \"Category\", \"Quality\", \"\"],\n      blueprints\n        .map(\n          (b) => `<tr>\n        <td>${entityCell(b.title, b.normalized_category || \"\")}</td>\n        <td>${escapeHtml(b.manufacturer_name || b.manufacturer_id)}</td>\n        <td>${escapeHtml(b.normalized_category || \"—\")}</td>\n        <td>${escapeHtml(b.quality_score ?? \"—\")}</td>\n        <td><button type=\"button\" class=\"btn btn-secondary btn-review-bp\" data-id=\"${escapeHtml(b.id)}\">Review</button></td>\n      </tr>`\n        )\n        .join(\"\")\n    )}</div>`;\n\n  panel.querySelectorAll(\".btn-review-bp\").forEach((btn) => {\n    btn.onclick = () => openBlueprintReviewModal(btn.dataset.id);\n  });\n}\n\nasync function openBlueprintReviewModal(blueprintId) {\n  const data = await partnerFetch(\"admin-blueprint-review-get\", { query: { blueprint_id: blueprintId } });\n  const v = data.validation || {};\n  const eaz = data.eazpire || {};\n  openModal({\n    title: `Blueprint review — ${eaz.title || blueprintId}`,\n    bodyHtml: `\n      <p><strong>Manufacturer:</strong> ${escapeHtml(eaz.manufacturer_name || eaz.manufacturer_id)}</p>\n      <p><strong>Status:</strong> ${escapeHtml(eaz.status)} · Quality score ${escapeHtml(v.score ?? \"—\")}</p>\n      <p><strong>Variants:</strong> ${escapeHtml((eaz.normalized?.variants || []).length)} ·\n         <strong>Print areas:</strong> ${escapeHtml((eaz.normalized?.print_areas || []).length)}</p>\n      ${v.errors?.length ? `<div class=\"panel\" style=\"margin-top:12px\"><div class=\"panel-body\"><strong>Errors</strong><ul>${v.errors.map((e) => `<li>${escapeHtml(e.message || e.code)}</li>`).join(\"\")}</ul></div></div>` : \"\"}\n      ${v.warnings?.length ? `<div class=\"panel\" style=\"margin-top:12px\"><div class=\"panel-body\"><strong>Warnings</strong><ul>${v.warnings.map((w) => `<li>${escapeHtml(w.message || w.code)}</li>`).join(\"\")}</ul></div></div>` : \"\"}\n      <div class=\"field\" style=\"margin-top:12px\"><label>Admin notes</label><textarea class=\"textarea\" id=\"bp-admin-notes\" rows=\"2\">${escapeHtml(eaz.admin_notes || \"\")}</textarea></div>\n      <div style=\"margin-top:14px;display:flex;gap:8px;flex-wrap:wrap\">\n        <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-bp-rerun\">Re-run conversion</button>\n        <button type=\"button\" class=\"btn btn-warning\" id=\"btn-bp-changes\">Request changes</button>\n        <button type=\"button\" class=\"btn btn-ghost\" id=\"btn-bp-reject\">Reject</button>\n        <button type=\"button\" class=\"btn btn-primary\" id=\"btn-bp-approve\">Approve & go live</button>\n      </div>`,\n    onSave: async () => {},\n  });\n  document.getElementById(\"modal-save\").style.display = \"none\";\n\n  const notes = () => document.getElementById(\"bp-admin-notes\")?.value || \"\";\n  const reopenReview = () => openBlueprintReviewModal(blueprintId);\n  document.getElementById(\"btn-bp-rerun\").onclick = () => {\n    confirmAction({\n      title: \"Re-run conversion\",\n      message: \"Re-run blueprint conversion?\",\n      confirmLabel: \"Re-run\",\n      confirmClass: \"btn-secondary\",\n      onCancel: reopenReview,\n      onConfirm: async () => {\n        await partnerFetch(\"admin-blueprint-rerun-conversion\", { method: \"POST\", body: { blueprint_id: blueprintId } });\n        showToast(\"Conversion re-run\", \"\");\n        openBlueprintReviewModal(blueprintId);\n      },\n    });\n  };\n  document.getElementById(\"btn-bp-approve\").onclick = () => {\n    confirmAction({\n      title: \"Approve blueprint\",\n      message: \"Approve this blueprint and make it live?\",\n      confirmLabel: \"Approve & go live\",\n      onCancel: reopenReview,\n      onConfirm: async () => {\n        await partnerFetch(\"admin-blueprint-approve\", { method: \"POST\", body: { blueprint_id: blueprintId, notes: notes() } });\n        showToast(\"Blueprint live\", \"Creators can use this blueprint\");\n        document.getElementById(\"modal-save\").style.display = \"\";\n        await renderCatalog();\n      },\n    });\n  };\n  document.getElementById(\"btn-bp-reject\").onclick = () => {\n    confirmAction({\n      title: \"Reject blueprint\",\n      message: \"Reject this blueprint?\",\n      confirmLabel: \"Reject\",\n      confirmClass: \"btn-danger\",\n      onCancel: reopenReview,\n      onConfirm: async () => {\n        await partnerFetch(\"admin-blueprint-reject\", { method: \"POST\", body: { blueprint_id: blueprintId, notes: notes() } });\n        showToast(\"Blueprint rejected\", \"\");\n        document.getElementById(\"modal-save\").style.display = \"\";\n        await renderCatalog();\n      },\n    });\n  };\n  document.getElementById(\"btn-bp-changes\").onclick = () => {\n    confirmAction({\n      title: \"Request changes\",\n      message: \"Request changes from the partner on this blueprint?\",\n      confirmLabel: \"Request changes\",\n      confirmClass: \"btn-warning\",\n      onCancel: reopenReview,\n      onConfirm: async () => {\n        await partnerFetch(\"admin-blueprint-request-changes\", { method: \"POST\", body: { blueprint_id: blueprintId, notes: notes() } });\n        showToast(\"Changes requested\", \"Partner notified via status\");\n        document.getElementById(\"modal-save\").style.display = \"\";\n        await renderCatalog();\n      },\n    });\n  };\n}\n\nconst KANBAN_COLS = [\n  { key: \"received\", label: \"Received\", badge: \"badge-neutral\" },\n  { key: \"accepted\", label: \"Accepted\", badge: \"badge-info\" },\n  { key: \"in_production\", label: \"In Production\", badge: \"badge-warning\" },\n  { key: \"shipped\", label: \"Shipped\", badge: \"badge-success\" },\n];\n\nasync function renderOrders() {\n  setTopbarExtra(`<button type=\"button\" class=\"btn btn-primary\" id=\"btn-test-order\">Create Test Order</button>`);\n  const el = document.getElementById(\"view-orders\");\n  const { board } = await partnerFetch(\"admin-manufacturer-orders-board\");\n\n  el.innerHTML = `\n    ${stageHeading(\n      \"Order Ops\",\n      \"Order Operations\",\n      \"Kanban command board for manufacturer order routing, production status, and fulfillment tracking.\",\n      `<button type=\"button\" class=\"btn btn-primary\" id=\"btn-test-order-heading\">Create Test Order</button>`\n    )}\n    <div class=\"kanban-board\">${KANBAN_COLS.map((col) => kanbanCol(col, board?.[col.key] || [])).join(\"\")}</div>`;\n\n  const openTestOrder = () => testOrderModal();\n  document.getElementById(\"btn-test-order\")?.addEventListener(\"click\", openTestOrder);\n  document.getElementById(\"btn-test-order-heading\")?.addEventListener(\"click\", openTestOrder);\n}\n\nfunction kanbanCol(col, orders) {\n  return `<div class=\"kanban-col\">\n    <div class=\"kanban-head\"><h3>${escapeHtml(col.label)}</h3><span class=\"badge ${col.badge}\">${orders.length}</span></div>\n    ${\n      orders.length\n        ? orders\n            .map(\n              (o) => `<div class=\"order-card\"><h4>${escapeHtml(o.order_number || o.id)}</h4><p>${escapeHtml(o.manufacturer_name || \"\")} · ${escapeHtml(o.status)}</p><div class=\"order-meta\"><span>${escapeHtml(o.status)}</span><span>${escapeHtml(o.manufacturer_name || \"\")}</span></div></div>`\n            )\n            .join(\"\")\n        : `<div class=\"empty-state\"><div class=\"icon\">↘</div><h3>Empty column</h3><p>Orders in this stage will appear here.</p></div>`\n    }\n  </div>`;\n}\n\nfunction testOrderModal() {\n  openModal({\n    title: \"Create test order\",\n    bodyHtml: `\n      <div class=\"field\"><label>Manufacturer ID</label><input class=\"input\" id=\"to-mfg\" /></div>\n      <div class=\"field\"><label>Product ID</label><input class=\"input\" id=\"to-product\" /></div>\n      <div class=\"field\"><label>Variant ID (optional)</label><input class=\"input\" id=\"to-variant\" /></div>`,\n    onSave: async () => {\n      await partnerFetch(\"admin-test-order-create\", {\n        method: \"POST\",\n        body: {\n          manufacturer_id: document.getElementById(\"to-mfg\").value,\n          product_id: document.getElementById(\"to-product\").value,\n          variant_id: document.getElementById(\"to-variant\").value || undefined,\n        },\n      });\n      showToast(\"Test order created\", \"\");\n      await renderOrders();\n    },\n  });\n}\n\nasync function renderApi() {\n  setTopbarExtra(`<button type=\"button\" class=\"btn btn-primary\" disabled title=\"Coming in V2\">Generate API Key</button>`);\n  const el = document.getElementById(\"view-api\");\n  el.innerHTML = `\n    ${stageHeading(\n      \"API Console\",\n      \"API Developer Console\",\n      \"Documentation-first developer experience for API partners: keys, webhooks, sandbox orders, and payload examples.\",\n      `<button type=\"button\" class=\"btn btn-primary\" disabled>Generate API Key</button>`\n    )}\n    <div class=\"api-layout\">\n      <aside class=\"panel\">\n        <div class=\"panel-header\"><div><h2 class=\"panel-title\">API Navigation</h2><p class=\"panel-subtitle\">Docs sidebar component</p></div></div>\n        <div class=\"panel-body doc-list\">\n          <div class=\"doc-item\"><strong>Authentication</strong><span>API keys, signatures, scopes</span></div>\n          <div class=\"doc-item\"><strong>Catalog Sync</strong><span>Products, variants, print areas</span></div>\n          <div class=\"doc-item\"><strong>Order API</strong><span>Receive fulfillment orders</span></div>\n          <div class=\"doc-item\"><strong>Tracking Webhooks</strong><span>Production and shipment updates</span></div>\n          <div class=\"doc-item\"><strong>Artifact Ready</strong><span>QR payload and serial rules</span></div>\n          <div class=\"doc-item\"><strong>Sandbox</strong><span>Test orders and validation logs</span></div>\n        </div>\n      </aside>\n      <section class=\"code-panel\">\n        <div class=\"code-tabs\"><div class=\"code-tab\">GET admin-manufacturer-list</div></div>\n        <pre>GET ${location.origin}/partner?op=admin-manufacturer-list\n\n// V1 read-only admin ops. Webhook logs and key management ship in V2.</pre>\n      </section>\n    </div>\n    <div class=\"component-zone\" style=\"margin-top:18px\">\n      <div class=\"panel\">\n        <div class=\"panel-header\"><div><h2 class=\"panel-title\">Webhook Logs</h2><p class=\"panel-subtitle\">Recent integration events</p></div><span class=\"badge badge-neutral\">V2</span></div>\n        <div class=\"panel-body\"><div class=\"empty-state\"><div class=\"icon\">{ }</div><h3>Coming in V2</h3><p>Webhook logs and API key management will appear here.</p></div></div>\n      </div>\n      <div class=\"panel\">\n        <div class=\"panel-header\"><div><h2 class=\"panel-title\">API Key Form</h2><p class=\"panel-subtitle\">Form component style</p></div></div>\n        <div class=\"panel-body\">\n          <div class=\"field\"><label>Key name</label><input class=\"input\" value=\"Production API Key\" disabled /></div>\n          <div class=\"field\"><label>Scopes</label><select class=\"select\" disabled><option>orders:read, orders:write, tracking:write</option></select></div>\n          <button type=\"button\" class=\"btn btn-primary\" disabled>Save key settings</button>\n        </div>\n      </div>\n    </div>`;\n}\n\nasync function renderCertification() {\n  setTopbarExtra(`<button type=\"button\" class=\"btn btn-primary\" id=\"btn-cert-review\" disabled>Run Review</button>`);\n  const el = document.getElementById(\"view-certification\");\n  const { manufacturers } = await partnerFetch(\"admin-manufacturer-list\", { query: { status: \"verified\" } });\n  const list = manufacturers || [];\n  const avgScore =\n    list.length > 0\n      ? (list.reduce((s, m) => s + Number(m.quality_score || 0), 0) / list.filter((m) => m.quality_score > 0).length || 0).toFixed(0)\n      : \"—\";\n  const ringPct = avgScore === \"—\" ? 0 : Math.min(100, Number(avgScore));\n\n  el.innerHTML = `\n    ${stageHeading(\n      \"Certification HQ\",\n      \"Certification HQ\",\n      \"Trust, safety and certification dashboard for Verified Manufacturer, Artifact Ready, and quality badges.\",\n      `<button type=\"button\" class=\"btn btn-primary\" disabled>Run Review</button>`\n    )}\n    <div class=\"cert-layout\">\n      <section>\n        <div class=\"cert-hero\">\n          <h2>Certification creates trust before the first order.</h2>\n          <p>Use a premium B2B certification system to protect marketplace quality, prevent fulfillment failures and highlight the best manufacturers in the Eazpire network.</p>\n          <div class=\"cert-badges\">\n            <span class=\"cert-badge\">Verified Manufacturer</span>\n            <span class=\"cert-badge\">Artifact Ready</span>\n            <span class=\"cert-badge\">Fast Fulfillment</span>\n            <span class=\"cert-badge\">Vegan Friendly</span>\n            <span class=\"cert-badge\">Premium Quality</span>\n          </div>\n        </div>\n        <div class=\"panel\" style=\"margin-top:18px\">\n          <div class=\"panel-header\"><div><h2 class=\"panel-title\">Certification Pipeline</h2><p class=\"panel-subtitle\">Checklist and approval listview</p></div></div>\n          ${renderTable(\n            [\"Manufacturer\", \"Quality\", \"Status\", \"Actions\"],\n            list\n              .map(\n                (m) => `<tr>\n              <td>${entityCell(m.name, m.country || \"\")}</td>\n              <td>${escapeHtml(m.quality_score ?? \"—\")}</td>\n              <td><span class=\"badge badge-success\">${escapeHtml(m.status)}</span></td>\n              <td>\n                <button type=\"button\" class=\"btn btn-primary btn-cert-pass\" data-id=\"${escapeHtml(m.id)}\">Pass</button>\n                <button type=\"button\" class=\"btn btn-ghost btn-cert-fail\" data-id=\"${escapeHtml(m.id)}\">Fail</button>\n              </td>\n            </tr>`\n              )\n              .join(\"\") || '<tr><td colspan=\"4\" class=\"empty\">No verified manufacturers</td></tr>'\n          )}\n        </div>\n      </section>\n      <aside class=\"panel\">\n        <div class=\"panel-header\"><div><h2 class=\"panel-title\">Network scorecard</h2><p class=\"panel-subtitle\">Certification overview</p></div></div>\n        <div class=\"panel-body\">\n          <div class=\"score-ring\" style=\"background:conic-gradient(var(--success) 0 ${ringPct}%, #e2e8f0 ${ringPct}% 100%)\"><strong>${escapeHtml(avgScore)}</strong></div>\n          <div class=\"checklist\">\n            <div class=\"check-item\"><strong>Verified manufacturers</strong><span class=\"badge badge-success\">${list.length}</span></div>\n            <div class=\"check-item\"><strong>Avg quality score</strong><span class=\"badge badge-info\">${escapeHtml(avgScore)}</span></div>\n            <div class=\"check-item\"><strong>Artifact readiness</strong><span class=\"badge badge-warning\">Monitoring</span></div>\n          </div>\n        </div>\n      </aside>\n    </div>`;\n\n  el.querySelectorAll(\".btn-cert-pass\").forEach((btn) => {\n    btn.onclick = () => {\n      confirmAction({\n        title: \"Certification passed\",\n        message: \"Mark this manufacturer as certification passed?\",\n        confirmLabel: \"Mark passed\",\n        onConfirm: async () => {\n          await partnerFetch(\"admin-certification-review\", {\n            method: \"POST\",\n            body: { manufacturer_id: btn.dataset.id, certification_key: \"verified_manufacturer\", approve: true },\n          });\n          showToast(\"Certification passed\", \"\");\n          await renderCertification();\n        },\n      });\n    };\n  });\n  el.querySelectorAll(\".btn-cert-fail\").forEach((btn) => {\n    btn.onclick = () => {\n      confirmAction({\n        title: \"Certification failed\",\n        message: \"Mark this manufacturer as certification failed?\",\n        confirmLabel: \"Mark failed\",\n        confirmClass: \"btn-danger\",\n        onConfirm: async () => {\n          await partnerFetch(\"admin-certification-review\", {\n            method: \"POST\",\n            body: { manufacturer_id: btn.dataset.id, certification_key: \"verified_manufacturer\", approve: false },\n          });\n          showToast(\"Certification failed\", \"\");\n          await renderCertification();\n        },\n      });\n    };\n  });\n}\n\nasync function renderPartnerRequests() {\n  sessionStorage.setItem(\"admin_network_tab\", \"pending\");\n  document.querySelector('[data-route=\"/partner/manufacturers\"]')?.click();\n}\n\nconst ROUTES = {\n  \"/partner\": renderCommand,\n  \"/partner/manufacturers\": renderManufacturers,\n  \"/partner/catalog\": renderCatalog,\n  \"/partner/orders\": renderOrders,\n  \"/partner/api\": renderApi,\n  \"/partner/certification\": renderCertification,\n  \"/partner/requests\": renderPartnerRequests,\n};\n\nasync function onRoute(route) {\n  const path = route || \"/partner\";\n  applyRouteTheme(path);\n  const fn = ROUTES[path] || ROUTES[\"/partner\"];\n  try {\n    await fn();\n  } catch (e) {\n    if (e.status === 401 || e.status === 403) showLogin();\n    else showToast(\"Error\", e.message || String(e));\n  }\n}\n\ndocument.getElementById(\"login-form\").addEventListener(\"submit\", async (e) => {\n  e.preventDefault();\n  const email = document.getElementById(\"login-email\").value.trim();\n  await partnerFetch(\"admin-auth-request\", { method: \"POST\", body: { email } });\n  document.getElementById(\"login-message\").textContent =\n    \"If this email is authorized, you will receive a sign-in link within a few minutes. Check spam.\";\n});\n\ndocument.getElementById(\"btn-logout\").addEventListener(\"click\", async () => {\n  await partnerFetch(\"admin-auth-logout\", { method: \"POST\" });\n  showLogin();\n});\n\n(async function boot() {\n  if (await ensureAdminSession()) {\n    showShell();\n    initShell({\n      navSections: [{ title: \"Core Portal\", items: NAV_CORE }],\n      onRoute,\n      brandSub: \"Admin Ops\",\n      crumbLabels: CRUMB_LABELS,\n    });\n  } else {\n    const authError = new URLSearchParams(location.search).get(\"auth_error\") || \"\";\n    showLogin(authError);\n    if (authError) {\n      history.replaceState({}, \"\", location.pathname);\n    }\n  }\n})();\n"},"admin-partner/js/catalog-editor/api.js":{"contentType":"application/javascript; charset=utf-8","body":"import { partnerFetch } from \"/partner/shared/js/partner-api.js\";\n\nexport async function fetchEditorBundle(productKey) {\n  return partnerFetch(\"admin-eazpire-product-editor-bundle\", { query: { product_key: productKey } });\n}\n\nexport async function fetchDriftV2() {\n  return partnerFetch(\"admin-eazpire-catalog-mirror-status-v2\");\n}\n\nexport async function mirrorProduct(productKey) {\n  return partnerFetch(\"admin-eazpire-catalog-mirror-run\", {\n    method: \"POST\",\n    body: { product_key: productKey },\n  });\n}\n\nexport async function saveMeta(productKey, body) {\n  return partnerFetch(\"admin-eazpire-product-meta-save\", {\n    method: \"POST\",\n    body: { product_key: productKey, ...body },\n  });\n}\n\nexport async function fetchProvidersBundle(productKey) {\n  return partnerFetch(\"admin-eazpire-product-providers-bundle\", { query: { product_key: productKey } });\n}\n\nexport async function saveProviders(productKey, body) {\n  return partnerFetch(\"admin-eazpire-product-providers-save\", {\n    method: \"POST\",\n    body: { product_key: productKey, ...body },\n  });\n}\n\nexport async function createVersion(productKey, body) {\n  return partnerFetch(\"admin-eazpire-product-version-create\", {\n    method: \"POST\",\n    body: { product_key: productKey, ...body },\n  });\n}\n\nexport async function deleteVersion(versionId) {\n  return partnerFetch(\"admin-eazpire-product-version-delete\", {\n    method: \"POST\",\n    body: { id: versionId },\n  });\n}\n\nexport async function saveVersionConfig(versionId, body) {\n  return partnerFetch(\"admin-eazpire-product-version-config-save\", {\n    method: \"POST\",\n    body: { id: versionId, ...body },\n  });\n}\n\nexport async function fetchPrintAreaBundle(productKey, printProviderId, versionId) {\n  return partnerFetch(\"admin-eazpire-print-area-bundle\", {\n    query: {\n      product_key: productKey,\n      print_provider_id: printProviderId || undefined,\n      version_id: versionId || undefined,\n    },\n  });\n}\n\nexport async function savePrintAreaSnapshot(versionId, body) {\n  return partnerFetch(\"admin-eazpire-print-area-snapshot-save\", {\n    method: \"POST\",\n    body: { version_id: versionId, ...body },\n  });\n}\n\nexport async function fetchVariantsBundle(productKey, printProviderId) {\n  return partnerFetch(\"admin-eazpire-variants-bundle\", {\n    query: { product_key: productKey, print_provider_id: printProviderId },\n  });\n}\n\nexport async function saveVariants(productKey, printProviderId, body) {\n  return partnerFetch(\"admin-eazpire-variants-save\", {\n    method: \"POST\",\n    body: { product_key: productKey, print_provider_id: printProviderId, ...body },\n  });\n}\n\nexport async function fetchTemplateBundle(productKey, printProviderId) {\n  return partnerFetch(\"admin-eazpire-template-bundle\", {\n    query: { product_key: productKey, print_provider_id: printProviderId },\n  });\n}\n\nexport async function saveTemplate(productKey, printProviderId, body) {\n  return partnerFetch(\"admin-eazpire-template-save\", {\n    method: \"POST\",\n    body: { product_key: productKey, print_provider_id: printProviderId, ...body },\n  });\n}\n\nexport async function fetchMockupsBundle(productKey, printProviderId) {\n  return partnerFetch(\"admin-eazpire-mockups-bundle\", {\n    query: {\n      product_key: productKey,\n      print_provider_id: printProviderId || undefined,\n    },\n  });\n}\n\nexport async function saveMockups(productKey, body) {\n  return partnerFetch(\"admin-eazpire-mockups-save\", {\n    method: \"POST\",\n    body: { product_key: productKey, ...body },\n  });\n}\n\nexport async function saveAutomations(versionId, body) {\n  return partnerFetch(\"admin-eazpire-automations-save\", {\n    method: \"POST\",\n    body: { version_id: versionId, ...body },\n  });\n}\n\nexport async function fetchPublishedBundle(productKey) {\n  return partnerFetch(\"admin-eazpire-published-bundle\", { query: { product_key: productKey } });\n}\n\nexport async function updatePublished(body) {\n  return partnerFetch(\"admin-eazpire-published-update\", { method: \"POST\", body });\n}\n\nexport async function deletePublished(body) {\n  return partnerFetch(\"admin-eazpire-published-delete\", { method: \"POST\", body });\n}\n"},"admin-partner/js/catalog-editor/shell.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { showToast } from \"/partner/shared/js/partner-shell.js\";\nimport { fetchEditorBundle, mirrorProduct } from \"./api.js\";\nimport { renderMetaTab, saveMetaTab } from \"./tabs/meta.js\";\nimport { loadProvidersTab, bindProvidersTab, saveProvidersTab } from \"./tabs/providers.js\";\nimport { loadTemplateTab, saveTemplateTab } from \"./tabs/template.js\";\nimport { loadMockupsTab, saveMockupsTab } from \"./tabs/mockups.js\";\nimport { loadVariantsTab, saveVariantsTab } from \"./tabs/variants.js\";\nimport { loadPrintAreaTab, bindPrintAreaTab, savePrintAreaTab } from \"./tabs/print-area.js\";\nimport { loadProductsTab, bindProductsTab, saveProductsTab } from \"./tabs/products.js\";\nimport { renderAutomationsTab, bindAutomationsTab, saveAutomationsTab } from \"./tabs/automations.js\";\n\nconst TABS = [\n  { id: \"provider\", label: \"Provider\", needsProvider: false },\n  { id: \"template\", label: \"Template\", needsProvider: true },\n  { id: \"mockups\", label: \"Mockups\", needsProvider: true },\n  { id: \"variants\", label: \"Variants\", needsProvider: true },\n  { id: \"print_area\", label: \"Print Area\", needsProvider: true },\n  { id: \"meta_data\", label: \"Meta\", needsProvider: false },\n  { id: \"products\", label: \"Products\", needsProvider: false },\n  { id: \"automations\", label: \"Automations\", needsProvider: true },\n];\n\nlet overlayEl = null;\nlet editorState = null;\n\nfunction ensureOverlay() {\n  if (overlayEl) return overlayEl;\n  overlayEl = document.createElement(\"div\");\n  overlayEl.id = \"catalog-editor-overlay\";\n  overlayEl.className = \"catalog-editor-overlay\";\n  overlayEl.hidden = true;\n  overlayEl.innerHTML = `\n    <div class=\"catalog-editor\" role=\"dialog\" aria-modal=\"true\">\n      <header class=\"catalog-editor-header\">\n        <div class=\"catalog-editor-title\">\n          <div>\n            <p class=\"catalog-editor-sub\">Product editor</p>\n            <h1 id=\"ce-title\">Product</h1>\n            <p id=\"ce-drift\" class=\"catalog-editor-sub\"></p>\n          </div>\n        </div>\n        <div class=\"catalog-editor-actions\">\n          <button type=\"button\" class=\"icon-btn\" id=\"ce-close\" aria-label=\"Close editor\">×</button>\n        </div>\n      </header>\n      <nav class=\"catalog-editor-tabs\" id=\"ce-tabs\"></nav>\n      <nav class=\"catalog-editor-subnav\" id=\"ce-subnav\" hidden>\n        <div class=\"ce-provider-pills\" id=\"ce-subnav-pills\"></div>\n      </nav>\n      <main class=\"catalog-editor-body\" id=\"ce-body\"></main>\n      <footer class=\"catalog-editor-foot\">\n        <div class=\"catalog-editor-foot-actions\">\n          <button type=\"button\" class=\"btn btn-secondary\" id=\"ce-mirror\">Mirror to publish index</button>\n          <button type=\"button\" class=\"btn btn-primary\" id=\"ce-save\">Save tab</button>\n        </div>\n      </footer>\n    </div>`;\n  document.body.appendChild(overlayEl);\n  overlayEl.querySelector(\"#ce-close\").onclick = closeProductEditor;\n  overlayEl.querySelector(\"#ce-save\").onclick = () => saveCurrentTab();\n  overlayEl.querySelector(\"#ce-mirror\").onclick = () => runMirror();\n  overlayEl.addEventListener(\"click\", (e) => {\n    if (e.target === overlayEl) closeProductEditor();\n  });\n  return overlayEl;\n}\n\nfunction activeProviderIds(ctx) {\n  return (ctx.bundle.active_providers || []).map((r) => String(r.print_provider_id));\n}\n\nfunction renderSubnav(ctx) {\n  const tab = TABS.find((t) => t.id === ctx.activeTab);\n  const subnav = overlayEl.querySelector(\"#ce-subnav\");\n  if (!tab?.needsProvider) {\n    subnav.hidden = true;\n    const pills = subnav.querySelector(\"#ce-subnav-pills\");\n    if (pills) pills.innerHTML = \"\";\n    return;\n  }\n  const ids = activeProviderIds(ctx);\n  if (!ids.length) {\n    subnav.hidden = true;\n    return;\n  }\n  if (!ctx.selectedPrintProviderId || !ids.includes(String(ctx.selectedPrintProviderId))) {\n    ctx.selectedPrintProviderId = ids[0];\n  }\n  subnav.hidden = false;\n  const pills = subnav.querySelector(\"#ce-subnav-pills\");\n  if (!pills) return;\n  pills.innerHTML = ids\n    .map((pid) => {\n      const fp = (ctx.bundle.providers || []).find((p) => String(p.external_provider_id) === pid);\n      const label = fp?.name || `Provider ${pid}`;\n      return `<button type=\"button\" class=\"ce-provider-pill ${String(ctx.selectedPrintProviderId) === pid ? \"active\" : \"\"}\" data-pid=\"${escapeHtml(pid)}\">${escapeHtml(label)}</button>`;\n    })\n    .join(\"\");\n  pills.querySelectorAll(\".ce-provider-pill\").forEach((btn) => {\n    btn.onclick = () => {\n      ctx.selectedPrintProviderId = btn.dataset.pid;\n      renderSubnav(ctx);\n      loadActiveTab(ctx);\n    };\n  });\n}\n\nfunction renderTabs(ctx) {\n  const nav = overlayEl.querySelector(\"#ce-tabs\");\n  nav.innerHTML = TABS.map(\n    (t) =>\n      `<button type=\"button\" class=\"ce-tab ${ctx.activeTab === t.id ? \"active\" : \"\"}\" data-tab=\"${t.id}\">${t.label}</button>`\n  ).join(\"\");\n  nav.querySelectorAll(\".ce-tab\").forEach((btn) => {\n    btn.onclick = () => {\n      ctx.activeTab = btn.dataset.tab;\n      renderTabs(ctx);\n      renderSubnav(ctx);\n      loadActiveTab(ctx);\n    };\n  });\n}\n\nasync function loadActiveTab(ctx) {\n  const body = overlayEl.querySelector(\"#ce-body\");\n  body.innerHTML = `<p class=\"catalog-editor-loading\">Loading…</p>`;\n  try {\n    let html = \"\";\n    switch (ctx.activeTab) {\n      case \"provider\":\n        html = await loadProvidersTab(ctx);\n        break;\n      case \"template\":\n        html = await loadTemplateTab(ctx);\n        break;\n      case \"mockups\":\n        html = await loadMockupsTab(ctx);\n        break;\n      case \"variants\":\n        html = await loadVariantsTab(ctx);\n        break;\n      case \"print_area\":\n        html = await loadPrintAreaTab(ctx);\n        break;\n      case \"meta_data\":\n        html = renderMetaTab(ctx);\n        break;\n      case \"products\":\n        html = await loadProductsTab(ctx);\n        break;\n      case \"automations\":\n        html = renderAutomationsTab(ctx);\n        break;\n      default:\n        html = \"<p>Unknown tab</p>\";\n    }\n    body.innerHTML = html;\n    if (ctx.activeTab === \"provider\") bindProvidersTab(ctx, body);\n    if (ctx.activeTab === \"print_area\") bindPrintAreaTab(ctx, body);\n    if (ctx.activeTab === \"products\") bindProductsTab(ctx, body);\n    if (ctx.activeTab === \"automations\") bindAutomationsTab(ctx, body);\n  } catch (err) {\n    body.innerHTML = `<div class=\"ce-error\">${escapeHtml(err.message || \"Load failed\")}</div>`;\n  }\n}\n\nasync function saveCurrentTab() {\n  if (!editorState) return;\n  const ctx = editorState;\n  const saveBtn = overlayEl.querySelector(\"#ce-save\");\n  saveBtn.disabled = true;\n  try {\n    switch (ctx.activeTab) {\n      case \"provider\":\n        await saveProvidersTab(ctx);\n        break;\n      case \"template\":\n        await saveTemplateTab(ctx);\n        break;\n      case \"mockups\":\n        await saveMockupsTab(ctx);\n        break;\n      case \"variants\":\n        await saveVariantsTab(ctx);\n        break;\n      case \"print_area\":\n        await savePrintAreaTab(ctx);\n        break;\n      case \"meta_data\":\n        await saveMetaTab(ctx);\n        break;\n      case \"products\":\n        await saveProductsTab(ctx);\n        break;\n      case \"automations\":\n        await saveAutomationsTab(ctx);\n        break;\n      default:\n        break;\n    }\n    await runMirror(true);\n    ctx.bundle = await fetchEditorBundle(ctx.productKey);\n    updateDriftBadge(ctx);\n    showToast(\"Saved\", \"Tab saved and mirrored to publish index\");\n    await loadActiveTab(ctx);\n  } catch (err) {\n    showToast(\"Save failed\", err.message || \"Unknown error\");\n  } finally {\n    saveBtn.disabled = false;\n  }\n}\n\nasync function runMirror(silent = false) {\n  if (!editorState) return;\n  try {\n    await mirrorProduct(editorState.productKey);\n    editorState.bundle = await fetchEditorBundle(editorState.productKey);\n    updateDriftBadge(editorState);\n    if (!silent) showToast(\"Mirrored\", \"Publish index updated\");\n  } catch (err) {\n    if (!silent) showToast(\"Mirror failed\", err.message || \"\");\n  }\n}\n\nfunction updateDriftBadge(ctx) {\n  const el = overlayEl.querySelector(\"#ce-drift\");\n  const drift = ctx.bundle.drift;\n  if (!drift) {\n    el.textContent = \"\";\n    return;\n  }\n  el.textContent = drift.in_sync ? \"In sync with publish index\" : \"Drift detected — save or mirror to reconcile\";\n  el.classList.toggle(\"is-sync\", !!drift.in_sync);\n  el.classList.toggle(\"is-drift\", !drift.in_sync);\n}\n\nexport async function openProductEditor(productKey) {\n  ensureOverlay();\n  overlayEl.hidden = false;\n  document.body.classList.add(\"catalog-editor-open\");\n\n  editorState = {\n    productKey,\n    activeTab: \"provider\",\n    selectedPrintProviderId: null,\n    selectedVersionId: null,\n    bundle: null,\n    reloadTab: () => loadActiveTab(editorState),\n  };\n\n  const ctx = editorState;\n  overlayEl.querySelector(\"#ce-title\").textContent = productKey;\n  overlayEl.querySelector(\"#ce-body\").innerHTML = `<p class=\"catalog-editor-loading\">Loading product…</p>`;\n\n  try {\n    ctx.bundle = await fetchEditorBundle(productKey);\n    overlayEl.querySelector(\"#ce-title\").textContent = ctx.bundle.product?.title || productKey;\n    const firstVersion = ctx.bundle.versions?.[0];\n    ctx.selectedVersionId = firstVersion?.id || null;\n    updateDriftBadge(ctx);\n    renderTabs(ctx);\n    renderSubnav(ctx);\n    await loadActiveTab(ctx);\n  } catch (err) {\n    overlayEl.querySelector(\"#ce-body\").innerHTML = `<div class=\"ce-error\">${escapeHtml(err.message || \"Failed to load\")}</div>`;\n  }\n}\n\nexport function closeProductEditor() {\n  if (!overlayEl) return;\n  overlayEl.hidden = true;\n  document.body.classList.remove(\"catalog-editor-open\");\n  editorState = null;\n}\n"},"admin-partner/js/catalog-editor/tabs/automations.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { saveAutomations } from \"../api.js\";\n\nexport function renderAutomationsTab(ctx) {\n  const versions = ctx.bundle.versions || [];\n  const version = versions.find((v) => v.id === ctx.selectedVersionId) || versions[0];\n  const auto = version?.auto_publish_config || {};\n  const versionOptions = versions\n    .map(\n      (v) =>\n        `<option value=\"${escapeHtml(v.id)}\" ${v.id === version?.id ? \"selected\" : \"\"}>${escapeHtml(v.display_name)}</option>`\n    )\n    .join(\"\");\n  return `\n    <div class=\"ce-tab-panel\">\n      <div class=\"field\"><label>Product version</label>\n        <select class=\"input\" id=\"ce-auto-version\">${versionOptions}</select></div>\n      <div class=\"field\"><label><input type=\"checkbox\" id=\"ce-auto-publish\" ${auto.auto_publish_enabled ? \"checked\" : \"\"} /> Auto-publish enabled</label></div>\n      <div class=\"field\"><label><input type=\"checkbox\" id=\"ce-auto-shopify\" ${auto.automation_shopify_sync_enabled ? \"checked\" : \"\"} /> Shopify sync automation</label></div>\n      <div class=\"field\"><label><input type=\"checkbox\" id=\"ce-auto-amazon\" ${auto.automation_amazon_publish_enabled ? \"checked\" : \"\"} /> Amazon publish automation</label></div>\n      <div class=\"field\"><label>Social automation JSON</label>\n        <textarea class=\"textarea ce-code\" id=\"ce-auto-social\" rows=\"6\">${escapeHtml(JSON.stringify(auto.automation_social || {}, null, 2))}</textarea></div>\n    </div>`;\n}\n\nexport function bindAutomationsTab(ctx, root) {\n  root.querySelector(\"#ce-auto-version\")?.addEventListener(\"change\", (e) => {\n    ctx.selectedVersionId = e.target.value;\n    ctx.reloadTab();\n  });\n}\n\nexport async function saveAutomationsTab(ctx) {\n  const versionId = document.getElementById(\"ce-auto-version\")?.value || ctx.selectedVersionId;\n  if (!versionId) return;\n  let automation_social = null;\n  try {\n    const raw = document.getElementById(\"ce-auto-social\")?.value?.trim();\n    if (raw) automation_social = JSON.parse(raw);\n  } catch {\n    throw new Error(\"Invalid social automation JSON\");\n  }\n  await saveAutomations(versionId, {\n    auto_publish_enabled: document.getElementById(\"ce-auto-publish\")?.checked,\n    automation_shopify_sync_enabled: document.getElementById(\"ce-auto-shopify\")?.checked,\n    automation_amazon_publish_enabled: document.getElementById(\"ce-auto-amazon\")?.checked,\n    automation_social,\n    auto_mirror: false,\n  });\n}\n"},"admin-partner/js/catalog-editor/tabs/meta.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { saveMeta } from \"../api.js\";\n\nexport function renderMetaTab(ctx) {\n  const p = ctx.bundle.product;\n  const profile = ctx.bundle.publish_profiles?.[0];\n  return `\n    <div class=\"ce-tab-panel\">\n      <h3 class=\"ce-section-title\">Product meta</h3>\n      <div class=\"field\"><label>Title</label><input class=\"input\" id=\"ce-meta-title\" value=\"${escapeHtml(p.title)}\" /></div>\n      <div class=\"field\"><label>Catalog status</label>\n        <select class=\"input\" id=\"ce-meta-status\">\n          <option value=\"offline\" ${p.catalog_status === \"offline\" ? \"selected\" : \"\"}>Offline</option>\n          <option value=\"preview\" ${p.catalog_status === \"preview\" ? \"selected\" : \"\"}>Preview</option>\n          <option value=\"online\" ${p.catalog_status === \"online\" ? \"selected\" : \"\"}>Online</option>\n        </select>\n      </div>\n      <div class=\"field\"><label>Regions (comma-separated)</label>\n        <input class=\"input\" id=\"ce-meta-regions\" value=\"${escapeHtml((p.regions || []).join(\", \"))}\" /></div>\n      <div class=\"field\"><label>Category group</label>\n        <input class=\"input\" id=\"ce-meta-cat-group\" value=\"${escapeHtml(p.catalog_category_group || \"\")}\" /></div>\n      <div class=\"field\"><label>Category leaf</label>\n        <input class=\"input\" id=\"ce-meta-cat-leaf\" value=\"${escapeHtml(p.catalog_category_leaf || \"\")}\" /></div>\n      <div class=\"field\"><label>Production type</label>\n        <input class=\"input\" id=\"ce-meta-prod-type\" value=\"${escapeHtml(p.catalog_production_type || \"\")}\" /></div>\n      <div class=\"field\"><label><input type=\"checkbox\" id=\"ce-meta-use-mocks\" ${p.print_area_edit_use_mocks ? \"checked\" : \"\"} /> Print area edit uses mockups</label></div>\n      <h3 class=\"ce-section-title\">Publish profile</h3>\n      <div class=\"field\"><label>Standard product display name</label>\n        <input class=\"input\" id=\"ce-meta-std-name\" value=\"${escapeHtml(profile?.standard_product_display_name || \"\")}\" /></div>\n      <div class=\"field\"><label>Product features</label>\n        <textarea class=\"textarea\" id=\"ce-meta-features\" rows=\"3\">${escapeHtml(profile?.product_features || \"\")}</textarea></div>\n      <div class=\"field\"><label>Care instructions</label>\n        <textarea class=\"textarea\" id=\"ce-meta-care\" rows=\"2\">${escapeHtml(profile?.care_instructions || \"\")}</textarea></div>\n      <div class=\"field\"><label>Size table HTML</label>\n        <textarea class=\"textarea\" id=\"ce-meta-size\" rows=\"3\">${escapeHtml(profile?.size_table_html || \"\")}</textarea></div>\n      <div class=\"field\"><label>GPSR HTML</label>\n        <textarea class=\"textarea\" id=\"ce-meta-gpsr\" rows=\"2\">${escapeHtml(profile?.gpsr_html || \"\")}</textarea></div>\n    </div>`;\n}\n\nexport async function saveMetaTab(ctx) {\n  const printProviderId = ctx.selectedPrintProviderId || ctx.bundle.active_providers?.[0]?.print_provider_id;\n  const regionsRaw = document.getElementById(\"ce-meta-regions\")?.value || \"\";\n  const regions = regionsRaw.split(\",\").map((s) => s.trim()).filter(Boolean);\n  await saveMeta(ctx.productKey, {\n    title: document.getElementById(\"ce-meta-title\")?.value,\n    catalog_status: document.getElementById(\"ce-meta-status\")?.value,\n    regions,\n    catalog_category_group: document.getElementById(\"ce-meta-cat-group\")?.value || null,\n    catalog_category_leaf: document.getElementById(\"ce-meta-cat-leaf\")?.value || null,\n    catalog_production_type: document.getElementById(\"ce-meta-prod-type\")?.value || null,\n    print_area_edit_use_mocks: document.getElementById(\"ce-meta-use-mocks\")?.checked,\n    print_provider_id: printProviderId,\n    standard_product_display_name: document.getElementById(\"ce-meta-std-name\")?.value || null,\n    product_features: document.getElementById(\"ce-meta-features\")?.value || null,\n    care_instructions: document.getElementById(\"ce-meta-care\")?.value || null,\n    size_table_html: document.getElementById(\"ce-meta-size\")?.value || null,\n    gpsr_html: document.getElementById(\"ce-meta-gpsr\")?.value || null,\n    auto_mirror: false,\n  });\n}\n"},"admin-partner/js/catalog-editor/tabs/mockups.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { fetchMockupsBundle, saveMockups } from \"../api.js\";\n\nexport async function loadMockupsTab(ctx) {\n  const data = await fetchMockupsBundle(ctx.productKey, ctx.selectedPrintProviderId);\n  ctx.mockupsData = data;\n  const images = (data.images || []).slice(0, 40);\n  const imageRows = images\n    .map(\n      (img) => `<tr>\n        <td>${escapeHtml(img.view_key)}</td>\n        <td>${escapeHtml(img.color_name)}</td>\n        <td><a href=\"${escapeHtml(img.image_url)}\" target=\"_blank\" rel=\"noopener\">View</a></td>\n        <td>${img.is_default ? \"Default\" : \"\"}</td>\n      </tr>`\n    )\n    .join(\"\");\n  return `\n    <div class=\"ce-tab-panel\">\n      <div class=\"field\"><label><input type=\"checkbox\" id=\"ce-mock-use-mocks\" ${data.product?.print_area_edit_use_mocks ? \"checked\" : \"\"} /> Print area edit uses mockups</label></div>\n      <h3 class=\"ce-section-title\">Mockup images (${images.length})</h3>\n      <table class=\"data-table ce-table\"><thead><tr><th>View</th><th>Color</th><th>Image</th><th></th></tr></thead>\n        <tbody>${imageRows || \"<tr><td colspan=\\\"4\\\">No mockup images imported yet.</td></tr>\"}</tbody></table>\n      <p class=\"ce-hint\">${(data.mockup_defaults || []).length} print area default(s) configured.</p>\n    </div>`;\n}\n\nexport async function saveMockupsTab(ctx) {\n  await saveMockups(ctx.productKey, {\n    print_area_edit_use_mocks: document.getElementById(\"ce-mock-use-mocks\")?.checked,\n    auto_mirror: false,\n  });\n}\n"},"admin-partner/js/catalog-editor/tabs/print-area.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { fetchPrintAreaBundle, savePrintAreaSnapshot } from \"../api.js\";\n\nexport async function loadPrintAreaTab(ctx) {\n  const data = await fetchPrintAreaBundle(ctx.productKey, ctx.selectedPrintProviderId, ctx.selectedVersionId);\n  ctx.printAreaData = data;\n  const version = data.version;\n  const studioJson = JSON.stringify(version?.studio_config || {}, null, 2);\n  const qrJson = JSON.stringify(version?.qr_logo_snapshot || {}, null, 2);\n  const versionOptions = (data.versions || [])\n    .map(\n      (v) =>\n        `<option value=\"${escapeHtml(v.id)}\" ${v.id === version?.id ? \"selected\" : \"\"}>${escapeHtml(v.display_name)} (${escapeHtml(v.external_provider_id || v.provider_name || \"\")})</option>`\n    )\n    .join(\"\");\n  return `\n    <div class=\"ce-tab-panel\">\n      <div class=\"field\"><label>Product version</label>\n        <select class=\"input\" id=\"ce-pa-version\">${versionOptions}</select></div>\n      <div class=\"field\"><label>Studio config JSON</label>\n        <textarea class=\"textarea ce-code\" id=\"ce-pa-studio\" rows=\"10\">${escapeHtml(studioJson)}</textarea></div>\n      <div class=\"field\"><label>QR / logo snapshot JSON</label>\n        <textarea class=\"textarea ce-code\" id=\"ce-pa-qr\" rows=\"8\">${escapeHtml(qrJson)}</textarea></div>\n      <p class=\"ce-hint\">${(data.mockup_defaults || []).length} mockup default(s), ${(data.variant_print_areas || []).length} variant print area(s).</p>\n    </div>`;\n}\n\nexport function bindPrintAreaTab(ctx, root) {\n  root.querySelector(\"#ce-pa-version\")?.addEventListener(\"change\", (e) => {\n    ctx.selectedVersionId = e.target.value;\n    ctx.reloadTab();\n  });\n}\n\nexport async function savePrintAreaTab(ctx) {\n  const versionId = document.getElementById(\"ce-pa-version\")?.value || ctx.selectedVersionId;\n  if (!versionId) return;\n  let studio_config = {};\n  let qr_logo_snapshot = null;\n  try {\n    studio_config = JSON.parse(document.getElementById(\"ce-pa-studio\")?.value || \"{}\");\n    const qrRaw = document.getElementById(\"ce-pa-qr\")?.value?.trim();\n    if (qrRaw) qr_logo_snapshot = JSON.parse(qrRaw);\n  } catch {\n    throw new Error(\"Invalid print area JSON\");\n  }\n  await savePrintAreaSnapshot(versionId, { studio_config, qr_logo_snapshot, auto_mirror: false });\n}\n"},"admin-partner/js/catalog-editor/tabs/products.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { fetchPublishedBundle, deletePublished } from \"../api.js\";\n\nexport async function loadProductsTab(ctx) {\n  const data = await fetchPublishedBundle(ctx.productKey);\n  ctx.productsData = data;\n  const rows = (data.published || [])\n    .slice(0, 50)\n    .map(\n      (row) => `<tr>\n        <td>${escapeHtml(row.design_id || row.id)}</td>\n        <td>${escapeHtml(row.product_name || \"—\")}</td>\n        <td>${escapeHtml(row.visibility || \"—\")}</td>\n        <td>${row.published_at ? new Date(row.published_at).toLocaleDateString() : \"—\"}</td>\n        <td><button type=\"button\" class=\"btn btn-secondary btn-sm ce-pub-delete\" data-design=\"${escapeHtml(row.design_id)}\">Remove</button></td>\n      </tr>`\n    )\n    .join(\"\");\n  return `\n    <div class=\"ce-tab-panel\">\n      <h3 class=\"ce-section-title\">Published listings (${(data.published || []).length})</h3>\n      <p class=\"ce-hint\">Data from creator DB · ${(data.versions || []).length} product version(s) in master.</p>\n      <table class=\"data-table ce-table\"><thead><tr><th>Design</th><th>Name</th><th>Visibility</th><th>Published</th><th></th></tr></thead>\n        <tbody>${rows || \"<tr><td colspan=\\\"5\\\">No published designs for this product key.</td></tr>\"}</tbody></table>\n    </div>`;\n}\n\nexport function bindProductsTab(ctx, root) {\n  root.querySelectorAll(\".ce-pub-delete\").forEach((btn) => {\n    btn.addEventListener(\"click\", async () => {\n      if (!confirm(\"Remove this published listing record?\")) return;\n      await deletePublished({ design_id: btn.dataset.design });\n      ctx.reloadTab();\n    });\n  });\n}\n\nexport async function saveProductsTab() {\n  /* read-only tab */\n}\n"},"admin-partner/js/catalog-editor/tabs/providers.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { fetchProvidersBundle, saveProviders, createVersion, deleteVersion, saveVersionConfig } from \"../api.js\";\n\nexport async function loadProvidersTab(ctx) {\n  const data = await fetchProvidersBundle(ctx.productKey);\n  ctx.providersData = data;\n  return renderProvidersTab(ctx, data);\n}\n\nfunction renderProvidersTab(ctx, data) {\n  const activeIds = new Set((data.active_providers || []).map((r) => Number(r.print_provider_id)));\n  const providerRows = (data.providers || [])\n    .map((fp) => {\n      const pid = Number(fp.external_provider_id);\n      const checked = activeIds.has(pid) ? \"checked\" : \"\";\n      return `<label class=\"ce-check-row\">\n        <input type=\"checkbox\" class=\"ce-provider-active\" data-pid=\"${pid}\" ${checked} />\n        <span><strong>${escapeHtml(fp.name)}</strong> · ID ${escapeHtml(fp.external_provider_id)}</span>\n      </label>`;\n    })\n    .join(\"\");\n\n  const versionRows = (data.versions || [])\n    .map(\n      (v) => `<tr>\n        <td>${escapeHtml(v.display_name)}</td>\n        <td>${escapeHtml(v.provider_name || v.external_provider_id || \"—\")}</td>\n        <td>${v.publish_enabled ? \"Yes\" : \"No\"}</td>\n        <td><button type=\"button\" class=\"btn btn-secondary btn-sm ce-version-edit\" data-id=\"${escapeHtml(v.id)}\">Config</button>\n        <button type=\"button\" class=\"btn btn-secondary btn-sm ce-version-delete\" data-id=\"${escapeHtml(v.id)}\">Delete</button></td>\n      </tr>`\n    )\n    .join(\"\");\n\n  return `\n    <div class=\"ce-tab-panel\">\n      <h3 class=\"ce-section-title\">Active print providers</h3>\n      <div class=\"ce-check-list\">${providerRows || \"<p>No fulfillment providers synced.</p>\"}</div>\n      <h3 class=\"ce-section-title\">Product versions</h3>\n      <div class=\"ce-inline-actions\">\n        <input class=\"input\" id=\"ce-new-version-name\" placeholder=\"New version name\" />\n        <input class=\"input\" id=\"ce-new-version-pid\" placeholder=\"Print provider ID\" />\n        <button type=\"button\" class=\"btn btn-secondary\" id=\"ce-btn-add-version\">Add version</button>\n      </div>\n      <table class=\"data-table ce-table\"><thead><tr><th>Name</th><th>Provider</th><th>Publish</th><th></th></tr></thead>\n        <tbody>${versionRows || \"<tr><td colspan=\\\"4\\\">No versions yet.</td></tr>\"}</tbody></table>\n    </div>`;\n}\n\nexport function bindProvidersTab(ctx, root) {\n  root.querySelector(\"#ce-btn-add-version\")?.addEventListener(\"click\", async () => {\n    const name = document.getElementById(\"ce-new-version-name\")?.value?.trim();\n    const pid = document.getElementById(\"ce-new-version-pid\")?.value?.trim();\n    if (!pid) return;\n    await createVersion(ctx.productKey, { display_name: name || \"New version\", print_provider_id: pid, auto_mirror: false });\n    ctx.reloadTab();\n  });\n\n  root.querySelectorAll(\".ce-version-delete\").forEach((btn) => {\n    btn.addEventListener(\"click\", async () => {\n      if (!confirm(\"Delete this product version?\")) return;\n      await deleteVersion(btn.dataset.id);\n      ctx.reloadTab();\n    });\n  });\n\n  root.querySelectorAll(\".ce-version-edit\").forEach((btn) => {\n    btn.addEventListener(\"click\", async () => {\n      const v = (ctx.providersData?.versions || []).find((x) => x.id === btn.dataset.id);\n      if (!v) return;\n      const name = prompt(\"Display name\", v.display_name);\n      if (name == null) return;\n      await saveVersionConfig(v.id, {\n        display_name: name,\n        product_version_config: v.product_version_config,\n        publish_enabled: v.publish_enabled,\n        is_active: v.is_active,\n        auto_mirror: false,\n      });\n      ctx.reloadTab();\n    });\n  });\n}\n\nexport async function saveProvidersTab(ctx) {\n  const active = [...document.querySelectorAll(\".ce-provider-active:checked\")].map((el) => Number(el.dataset.pid));\n  await saveProviders(ctx.productKey, { active_print_provider_ids: active, auto_mirror: false });\n}\n"},"admin-partner/js/catalog-editor/tabs/template.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { fetchTemplateBundle, saveTemplate } from \"../api.js\";\n\nexport async function loadTemplateTab(ctx) {\n  const pid = ctx.selectedPrintProviderId;\n  if (!pid) return `<div class=\"ce-tab-panel\"><p>Select an active provider above.</p></div>`;\n  const data = await fetchTemplateBundle(ctx.productKey, pid);\n  ctx.templateData = data;\n  const tpl = data.template;\n  const version = data.version;\n  return `\n    <div class=\"ce-tab-panel\">\n      <h3 class=\"ce-section-title\">Printify template · provider ${escapeHtml(pid)}</h3>\n      <div class=\"field\"><label>Printify product ID</label>\n        <input class=\"input\" id=\"ce-tpl-id\" value=\"${escapeHtml(tpl?.printify_product_id || version?.external_template_product_id || \"\")}\" /></div>\n      <div class=\"field\"><label>Title</label>\n        <input class=\"input\" id=\"ce-tpl-title\" value=\"${escapeHtml(tpl?.title || version?.display_name || \"\")}\" /></div>\n      <p class=\"ce-hint\">Link an existing Printify template product ID or save after creating one in Printify.</p>\n    </div>`;\n}\n\nexport async function saveTemplateTab(ctx) {\n  const pid = ctx.selectedPrintProviderId;\n  if (!pid) return;\n  await saveTemplate(ctx.productKey, pid, {\n    printify_product_id: document.getElementById(\"ce-tpl-id\")?.value?.trim(),\n    title: document.getElementById(\"ce-tpl-title\")?.value?.trim(),\n    auto_mirror: false,\n  });\n}\n"},"admin-partner/js/catalog-editor/tabs/variants.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"/partner/shared/js/partner-api.js\";\nimport { fetchVariantsBundle, saveVariants } from \"../api.js\";\n\nexport async function loadVariantsTab(ctx) {\n  const pid = ctx.selectedPrintProviderId;\n  if (!pid) return `<div class=\"ce-tab-panel\"><p>Select an active provider above.</p></div>`;\n  const data = await fetchVariantsBundle(ctx.productKey, pid);\n  ctx.variantsData = data;\n  const variants = Array.isArray(data.variants_json) ? data.variants_json : [];\n  const configJson = JSON.stringify(data.variant_config || {}, null, 2);\n  const variantPreview = variants\n    .slice(0, 20)\n    .map((v) => `<tr><td>${escapeHtml(v.title || v.id || \"—\")}</td><td>${escapeHtml(String(v.id ?? \"\"))}</td></tr>`)\n    .join(\"\");\n  return `\n    <div class=\"ce-tab-panel\">\n      <h3 class=\"ce-section-title\">Variant config · provider ${escapeHtml(pid)}</h3>\n      <div class=\"field\"><label>Variant config JSON</label>\n        <textarea class=\"textarea ce-code\" id=\"ce-variants-config\" rows=\"12\">${escapeHtml(configJson)}</textarea></div>\n      <h3 class=\"ce-section-title\">Source variants (${variants.length})</h3>\n      <table class=\"data-table ce-table\"><thead><tr><th>Title</th><th>ID</th></tr></thead>\n        <tbody>${variantPreview || \"<tr><td colspan=\\\"2\\\">No variants in publish profile.</td></tr>\"}</tbody></table>\n    </div>`;\n}\n\nexport async function saveVariantsTab(ctx) {\n  const pid = ctx.selectedPrintProviderId;\n  if (!pid) return;\n  let config = {};\n  try {\n    config = JSON.parse(document.getElementById(\"ce-variants-config\")?.value || \"{}\");\n  } catch {\n    throw new Error(\"Invalid variant config JSON\");\n  }\n  await saveVariants(ctx.productKey, pid, { config, auto_mirror: false });\n}\n"},"partner/index.html":{"contentType":"text/html; charset=utf-8","body":"<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>Eazpire Partner Portal</title>\n  <style>[hidden]{display:none!important}.modal-backdrop:not(.show){display:none!important}</style>\n  <link rel=\"stylesheet\" href=\"/shared/css/partner-ui.css\" />\n</head>\n<body>\n  <div id=\"app-shell\" class=\"app-root\" hidden>\n    <aside class=\"sidebar\">\n      <div class=\"brand-block\">\n        <div class=\"logo-mark\">EZ</div>\n        <div>\n          <div class=\"brand-name\">Eazpire Partners</div>\n          <div class=\"brand-sub\">Manufacturer Portal</div>\n        </div>\n      </div>\n      <nav id=\"partner-nav\"></nav>\n      <div class=\"sidebar-card\" id=\"sidebar-progress\">Artifact Ready — loading…</div>\n    </aside>\n    <div id=\"sidebar-backdrop\" class=\"sidebar-backdrop\" aria-hidden=\"true\"></div>\n    <header class=\"topbar\">\n      <button type=\"button\" class=\"icon-btn sidebar-toggle\" id=\"sidebar-toggle\" aria-label=\"Open menu\" aria-expanded=\"false\" aria-controls=\"partner-nav\">☰</button>\n      <div class=\"topbar-start\">\n        <div class=\"crumbs\">Partner / <strong id=\"crumb-current\">overview</strong></div>\n      </div>\n      <div class=\"topbar-actions\">\n        <button type=\"button\" class=\"btn btn-ghost\" id=\"btn-logout\">Sign out</button>\n      </div>\n    </header>\n    <main class=\"main\">\n      <section class=\"view active\" data-route=\"/\" id=\"view-overview\"></section>\n      <section class=\"view\" data-route=\"/company\" id=\"view-company\"></section>\n      <section class=\"view\" data-route=\"/catalog\" id=\"view-catalog\"></section>\n      <section class=\"view\" data-route=\"/orders\" id=\"view-orders\"></section>\n      <section class=\"view\" data-route=\"/api\" id=\"view-api\"></section>\n      <section class=\"view\" data-route=\"/certification\" id=\"view-certification\"></section>\n      <section class=\"view\" data-route=\"/application-status\" id=\"view-application-status\"></section>\n    </main>\n  </div>\n\n  <div id=\"app-applicant\" class=\"app-root app-root--full\" hidden>\n    <header class=\"topbar\">\n      <div class=\"crumbs\">Partner / <strong>Application status</strong></div>\n      <div class=\"topbar-actions\">\n        <button type=\"button\" class=\"btn btn-ghost\" id=\"btn-applicant-logout\">Sign out</button>\n      </div>\n    </header>\n    <main class=\"main\">\n      <section class=\"view active\" id=\"view-applicant-status\"></section>\n    </main>\n  </div>\n\n  <div id=\"app-login\" class=\"partner-screen\" hidden>\n    <div class=\"login-card\" id=\"login-panel\">\n      <div class=\"logo-mark\" style=\"margin-bottom:14px\">EZ</div>\n      <h1>Partner sign in</h1>\n      <p>Sign in with a magic link sent to your email. If your application is under review, you'll see your status after signing in.</p>\n      <form id=\"login-form\" style=\"margin-top:20px\">\n        <div class=\"field\">\n          <label for=\"login-email\">Email</label>\n          <input class=\"input\" id=\"login-email\" type=\"email\" required autocomplete=\"email\" />\n        </div>\n        <button class=\"btn btn-primary\" type=\"submit\" style=\"width:100%\">Send magic link</button>\n      </form>\n      <p id=\"login-message\" class=\"stage-desc\" style=\"margin-top:16px\"></p>\n      <hr style=\"border:0;border-top:1px solid var(--line);margin:24px 0\" />\n      <p class=\"stage-desc\">New to Eazpire manufacturing?</p>\n      <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-show-apply\" style=\"width:100%;margin-top:10px\">Become a Partner</button>\n    </div>\n\n    <div id=\"login-waiting\" class=\"login-card login-waiting\" hidden>\n      <div class=\"login-waiting-spinner\" aria-hidden=\"true\"></div>\n      <h1>Check your email</h1>\n      <p class=\"login-waiting-lead\">We sent a sign-in link to <strong id=\"login-waiting-email\"></strong></p>\n      <p class=\"stage-desc\">Open the link on any device — this page will sign you in automatically.</p>\n      <div class=\"login-waiting-timer\" aria-live=\"polite\">\n        <span class=\"login-waiting-timer-label\">Link expires in</span>\n        <span class=\"login-waiting-timer-value\" id=\"login-waiting-countdown\">15:00</span>\n      </div>\n      <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-login-waiting-cancel\" style=\"width:100%;margin-top:20px\">Cancel</button>\n    </div>\n\n    <div id=\"apply-wizard\" class=\"apply-wizard partner-typeform\" hidden>\n      <div class=\"apply-wizard-top\">\n        <div class=\"apply-wizard-progress-track\" aria-hidden=\"true\">\n          <div class=\"apply-wizard-progress-fill\" id=\"apply-progress-fill\"></div>\n        </div>\n        <div class=\"apply-wizard-progress-label\" id=\"apply-progress-label\">1 of 7</div>\n      </div>\n\n      <form id=\"apply-form\" class=\"apply-wizard-form\" novalidate>\n        <div class=\"apply-step\" data-step=\"0\">\n          <span class=\"apply-step-badge\">1</span>\n          <h2 class=\"apply-question\">What is your company name?</h2>\n          <p class=\"apply-hint\">Legal or trading name — we'll use this on your partner profile.</p>\n          <input class=\"apply-input\" id=\"apply-company\" type=\"text\" autocomplete=\"organization\" />\n          <p class=\"apply-error\" id=\"apply-error-0\" hidden></p>\n        </div>\n\n        <div class=\"apply-step\" data-step=\"1\" hidden>\n          <span class=\"apply-step-badge\">2</span>\n          <h2 class=\"apply-question\">Who is our main contact?</h2>\n          <p class=\"apply-hint\">Full name of the person we'll reach out to.</p>\n          <input class=\"apply-input\" id=\"apply-contact\" type=\"text\" autocomplete=\"name\" />\n          <p class=\"apply-error\" id=\"apply-error-1\" hidden></p>\n        </div>\n\n        <div class=\"apply-step\" data-step=\"2\" hidden>\n          <span class=\"apply-step-badge\">3</span>\n          <h2 class=\"apply-question\">What is your business email?</h2>\n          <p class=\"apply-hint\">We'll send your application status and sign-in link here.</p>\n          <input class=\"apply-input\" id=\"apply-email\" type=\"email\" autocomplete=\"email\" />\n          <p class=\"apply-error\" id=\"apply-error-2\" hidden></p>\n        </div>\n\n        <div class=\"apply-step\" data-step=\"3\" hidden>\n          <span class=\"apply-step-badge\">4</span>\n          <h2 class=\"apply-question\">Where is your company based?</h2>\n          <p class=\"apply-hint\">Country code or full country name (e.g. DE or Germany).</p>\n          <input class=\"apply-input\" id=\"apply-country\" type=\"text\" autocomplete=\"country-name\" />\n          <p class=\"apply-error\" id=\"apply-error-3\" hidden></p>\n        </div>\n\n        <div class=\"apply-step\" data-step=\"4\" hidden>\n          <span class=\"apply-step-badge\">5</span>\n          <h2 class=\"apply-question\">Do you have a website?</h2>\n          <p class=\"apply-hint\">Optional — press Next to skip if you don't have one yet.</p>\n          <input class=\"apply-input\" id=\"apply-website\" type=\"url\" placeholder=\"https://\" autocomplete=\"url\" />\n          <p class=\"apply-error\" id=\"apply-error-4\" hidden></p>\n        </div>\n\n        <div class=\"apply-step\" data-step=\"5\" hidden>\n          <span class=\"apply-step-badge\">6</span>\n          <h2 class=\"apply-question\">What do you manufacture?</h2>\n          <p class=\"apply-hint\">Product types and capabilities, e.g. apparel, mugs, posters.</p>\n          <input class=\"apply-input\" id=\"apply-products\" type=\"text\" />\n          <p class=\"apply-error\" id=\"apply-error-5\" hidden></p>\n        </div>\n\n        <div class=\"apply-step apply-step-review\" data-step=\"6\" hidden>\n          <span class=\"apply-step-badge\">7</span>\n          <h2 class=\"apply-question\">Ready to submit?</h2>\n          <p class=\"apply-hint\">Review your details below. Add an optional message, then submit.</p>\n          <dl class=\"apply-review\" id=\"apply-review-summary\"></dl>\n          <label class=\"apply-review-label\" for=\"apply-message-text\">Message (optional)</label>\n          <textarea class=\"apply-textarea\" id=\"apply-message-text\" rows=\"3\" placeholder=\"Tell us about your production capacity…\"></textarea>\n          <p class=\"apply-error\" id=\"apply-error-6\" hidden></p>\n        </div>\n      </form>\n\n      <div id=\"apply-success\" class=\"apply-success\" hidden>\n        <div class=\"apply-success-icon\">✓</div>\n        <h2 class=\"apply-question\">Application received</h2>\n        <p class=\"apply-hint\">Check your email for a verification link to continue. If you don't see it, check spam.</p>\n      </div>\n\n      <div class=\"apply-wizard-actions\" id=\"apply-wizard-actions\">\n        <button type=\"button\" class=\"apply-btn-back\" id=\"btn-apply-back\" hidden>Back</button>\n        <button type=\"button\" class=\"apply-btn-next\" id=\"btn-apply-next\">Next</button>\n        <button type=\"submit\" class=\"apply-btn-next apply-btn-submit\" id=\"btn-apply-submit\" form=\"apply-form\" hidden>Submit application</button>\n      </div>\n\n      <button type=\"button\" class=\"apply-back-login\" id=\"btn-back-login\">← Back to sign in</button>\n    </div>\n  </div>\n\n  <div id=\"modal-backdrop\" class=\"modal-backdrop\" hidden>\n    <div class=\"modal\" role=\"dialog\" aria-modal=\"true\">\n      <div class=\"modal-head\">\n        <strong id=\"modal-title\">Modal</strong>\n        <button type=\"button\" class=\"btn btn-ghost\" id=\"modal-close\">✕</button>\n      </div>\n      <div class=\"modal-body\" id=\"modal-body\"></div>\n      <div class=\"modal-foot\">\n        <button type=\"button\" class=\"btn btn-secondary\" id=\"modal-cancel\">Cancel</button>\n        <button type=\"button\" class=\"btn btn-primary\" id=\"modal-save\">Save</button>\n      </div>\n    </div>\n  </div>\n  <div id=\"partner-toast\" class=\"toast\"><strong></strong><span></span></div>\n  <script type=\"module\" src=\"/js/app.js\"></script>\n</body>\n</html>\n"},"partner/js/app.js":{"contentType":"application/javascript; charset=utf-8","body":"import { partnerFetch, badgeForStatus, escapeHtml } from \"/shared/js/partner-api.js\";\nimport { initShell, openModal, closeModal, showToast, renderTable } from \"/shared/js/partner-shell.js\";\n\nconst NAV = [\n  { route: \"/\", label: \"Overview\", icon: \"⌘\" },\n  { route: \"/company\", label: \"Company\", icon: \"🏭\" },\n  { route: \"/catalog\", label: \"Catalog\", icon: \"▦\" },\n  { route: \"/orders\", label: \"Orders\", icon: \"↗\" },\n  { route: \"/api\", label: \"API\", icon: \"{ }\" },\n  { route: \"/certification\", label: \"Certification\", icon: \"✓\" },\n];\n\nlet session = null;\nlet sessionMode = null;\nlet shellInitialized = false;\n\nconst LOGIN_POLL_TTL_MS = 15 * 60 * 1000;\nconst LOGIN_POLL_INTERVAL_MS = 2500;\n\nconst BLOCKED_EMAIL_MESSAGE = \"This email address cannot be used for partner applications.\";\nconst APPLICATION_REQUIRED_MESSAGE =\n  \"We don't have a partner application for this email yet. Please complete the Become a Partner form first — then you can sign in with a magic link.\";\n\nconst loginWaitState = {\n  pollToken: null,\n  email: \"\",\n  pollTimer: null,\n  countdownTimer: null,\n  expiresAt: 0,\n  active: false,\n};\n\nfunction formatCountdown(msLeft) {\n  const totalSec = Math.max(0, Math.ceil(msLeft / 1000));\n  const min = Math.floor(totalSec / 60);\n  const sec = totalSec % 60;\n  return `${min}:${String(sec).padStart(2, \"0\")}`;\n}\n\nfunction stopLoginWait() {\n  loginWaitState.active = false;\n  if (loginWaitState.pollTimer) {\n    clearInterval(loginWaitState.pollTimer);\n    loginWaitState.pollTimer = null;\n  }\n  if (loginWaitState.countdownTimer) {\n    clearInterval(loginWaitState.countdownTimer);\n    loginWaitState.countdownTimer = null;\n  }\n  loginWaitState.pollToken = null;\n}\n\nfunction showLoginFormPanel() {\n  stopLoginWait();\n  document.getElementById(\"login-panel\").hidden = false;\n  document.getElementById(\"login-waiting\").hidden = true;\n}\n\nfunction showLoginWaitingPanel(email) {\n  document.getElementById(\"login-panel\").hidden = true;\n  document.getElementById(\"login-waiting\").hidden = false;\n  document.getElementById(\"login-waiting-email\").textContent = email;\n  document.getElementById(\"login-message\").textContent = \"\";\n}\n\nfunction updateLoginCountdown() {\n  const el = document.getElementById(\"login-waiting-countdown\");\n  if (!el) return;\n  const msLeft = loginWaitState.expiresAt - Date.now();\n  el.textContent = formatCountdown(msLeft);\n  if (msLeft <= 0) {\n    stopLoginWait();\n    showLoginFormPanel();\n    document.getElementById(\"login-message\").textContent =\n      \"The sign-in link has expired. Request a new link below.\";\n  }\n}\n\nasync function pollLoginStatus() {\n  if (!loginWaitState.active || !loginWaitState.pollToken) return;\n  try {\n    const data = await partnerFetch(\"partner-auth-poll\", {\n      query: { poll_token: loginWaitState.pollToken },\n    });\n    if (data.status === \"verified\" && data.exchange_token) {\n      stopLoginWait();\n      const exchanged = await partnerFetch(\"partner-auth-exchange\", {\n        method: \"POST\",\n        body: { exchange_token: data.exchange_token },\n      });\n      const mode = exchanged.mode || data.mode;\n      if (mode === \"applicant\") {\n        const meMode = await ensureSession();\n        if (meMode === \"full\") {\n          await enterFullPortal(\"/\");\n          return;\n        }\n        showApplicantShell();\n        await renderApplicationStatus();\n        history.replaceState({}, \"\", \"/application-status\");\n      } else {\n        await enterFullPortal(\"/\");\n      }\n      return;\n    }\n    if (data.status === \"expired\") {\n      stopLoginWait();\n      showLoginFormPanel();\n      document.getElementById(\"login-message\").textContent =\n        \"The sign-in link has expired. Request a new link below.\";\n    }\n  } catch {\n    /* keep polling until expiry */\n  }\n}\n\nfunction startLoginWait(email, pollToken) {\n  stopLoginWait();\n  loginWaitState.email = email;\n  loginWaitState.pollToken = pollToken;\n  loginWaitState.expiresAt = Date.now() + LOGIN_POLL_TTL_MS;\n  loginWaitState.active = Boolean(pollToken);\n  showLoginWaitingPanel(email);\n  updateLoginCountdown();\n  if (!pollToken) return;\n  loginWaitState.countdownTimer = setInterval(updateLoginCountdown, 1000);\n  pollLoginStatus();\n  loginWaitState.pollTimer = setInterval(pollLoginStatus, LOGIN_POLL_INTERVAL_MS);\n}\n\nasync function ensureSession() {\n  try {\n    const me = await partnerFetch(\"partner-auth-me\");\n    session = me.session;\n    sessionMode = session?.mode || (session?.manufacturer_id ? \"full\" : null);\n    if (me.upgraded || sessionMode === \"full\") {\n      sessionMode = \"full\";\n      return \"full\";\n    }\n    return sessionMode;\n  } catch {\n    session = null;\n    sessionMode = null;\n    return null;\n  }\n}\n\nasync function enterFullPortal(route = \"/\") {\n  sessionMode = \"full\";\n  showShell();\n  if (!shellInitialized) {\n    initShell({ navItems: NAV, onRoute, brandSub: \"Manufacturer Portal\" });\n    shellInitialized = true;\n  }\n  const onStatusPage =\n    route.includes(\"application-status\") || location.pathname.includes(\"application-status\");\n  const target = onStatusPage ? \"/\" : route || \"/\";\n  if (location.pathname !== target) {\n    history.replaceState({}, \"\", target);\n  }\n  await onRoute(target);\n}\n\nfunction showLogin(authErrorCode = \"\") {\n  stopLoginWait();\n  showLoginFormPanel();\n  document.getElementById(\"app-login\").hidden = false;\n  document.getElementById(\"app-shell\").hidden = true;\n  document.getElementById(\"app-applicant\").hidden = true;\n  const msg = document.getElementById(\"login-message\");\n  if (msg && authErrorCode) {\n    const messages = {\n      invalid_or_expired_token:\n        \"This sign-in link is invalid or has expired. Request a new link below.\",\n      token_already_used:\n        \"This sign-in link was already used (often by an email security scanner). Request a new link below.\",\n      token_required: \"Sign-in link is missing. Request a new link below.\",\n    };\n    msg.textContent = messages[authErrorCode] || \"Sign-in failed. Request a new link below.\";\n  }\n}\n\nfunction showShell() {\n  document.getElementById(\"app-login\").hidden = true;\n  document.getElementById(\"app-shell\").hidden = false;\n  document.getElementById(\"app-applicant\").hidden = true;\n}\n\nfunction showApplicantShell() {\n  document.getElementById(\"app-login\").hidden = true;\n  document.getElementById(\"app-shell\").hidden = true;\n  document.getElementById(\"app-applicant\").hidden = false;\n}\n\nasync function renderApplicationStatus() {\n  const mode = await ensureSession();\n  if (mode === \"full\") {\n    await enterFullPortal(\"/\");\n    return;\n  }\n\n  const data = await partnerFetch(\"partner-application-status\");\n  if (data.upgraded) {\n    session = data.session;\n    sessionMode = \"full\";\n    await enterFullPortal(\"/\");\n    return;\n  }\n\n  const el = document.getElementById(\"view-applicant-status\");\n  const app = data.application || session?.application || {};\n  const status = app.status || \"pending_review\";\n  const statusLabel = {\n    pending_email_verification: \"Email verification pending\",\n    pending_review: \"Under review\",\n    approved: \"Approved\",\n    rejected: \"Not approved\",\n  }[status] || status;\n\n  el.innerHTML = `\n    <div class=\"panel\" style=\"max-width:640px\">\n      <div class=\"panel-header\"><strong>Partner application</strong><span class=\"badge ${badgeForStatus(status)}\">${escapeHtml(statusLabel)}</span></div>\n      <div class=\"panel-body\">\n        <p><strong>${escapeHtml(app.company_name || \"Your company\")}</strong></p>\n        <p class=\"stage-desc\" style=\"margin-top:8px\">Thank you for applying to become an Eazpire manufacturing partner.</p>\n        ${\n          status === \"pending_review\"\n            ? `<p style=\"margin-top:16px\">Your application is being reviewed by our team. You will receive an email when a decision is made. Once approved, you will be taken to the full partner portal automatically.</p>`\n            : status === \"pending_email_verification\"\n              ? `<p style=\"margin-top:16px\">Please check your inbox for a verification link to continue. You can also request a magic link from the sign-in page to view this status.</p>`\n              : status === \"rejected\"\n                ? `<p style=\"margin-top:16px\">Unfortunately we could not approve your application at this time.${app.rejection_reason ? ` Reason: ${escapeHtml(app.rejection_reason)}` : \"\"}</p>`\n                : \"\"\n        }\n        <dl style=\"margin-top:20px;display:grid;grid-template-columns:auto 1fr;gap:8px 16px;font-size:14px\">\n          <dt>Contact</dt><dd>${escapeHtml(app.contact_name || \"—\")}</dd>\n          <dt>Email</dt><dd>${escapeHtml(app.email || session?.email || \"—\")}</dd>\n          <dt>Country</dt><dd>${escapeHtml(app.country || \"—\")}</dd>\n          ${app.website ? `<dt>Website</dt><dd>${escapeHtml(app.website)}</dd>` : \"\"}\n          ${app.product_types ? `<dt>Capabilities</dt><dd>${escapeHtml(app.product_types)}</dd>` : \"\"}\n        </dl>\n      </div>\n    </div>`;\n}\n\nasync function renderOverview() {\n  const el = document.getElementById(\"view-overview\");\n  const { dashboard } = await partnerFetch(\"manufacturer-dashboard\");\n  const kpis = dashboard?.kpis || {};\n  el.innerHTML = `\n    <h1 class=\"stage-title\">Overview</h1>\n    <p class=\"stage-desc\">Your manufacturer workspace at a glance.</p>\n    <div class=\"kpi-grid\" style=\"margin-top:20px\">\n      ${kpiCard(\"Products\", kpis.products_total ?? 0)}\n      ${kpiCard(\"Pending review\", kpis.products_pending ?? 0)}\n      ${kpiCard(\"Open orders\", kpis.orders_open ?? 0)}\n      ${kpiCard(\"Certification\", `${kpis.certification_pct ?? 0}%`)}\n    </div>\n    <div class=\"panel\" style=\"margin-top:18px\">\n      <div class=\"panel-header\"><strong>Action items</strong></div>\n      <div class=\"panel-body\">${(dashboard?.action_items || []).map(actionRow).join(\"\") || '<div class=\"empty\">No action items</div>'}</div>\n    </div>`;\n}\n\nfunction kpiCard(label, value) {\n  return `<div class=\"kpi-card\"><div class=\"kpi-label\">${escapeHtml(label)}</div><div class=\"kpi-value\">${escapeHtml(value)}</div></div>`;\n}\n\nfunction actionRow(item) {\n  return `<div class=\"order-card\"><strong>${escapeHtml(item.title)}</strong><p>${escapeHtml(item.detail || \"\")}</p><span class=\"badge ${badgeForStatus(item.status)}\">${escapeHtml(item.status || \"info\")}</span></div>`;\n}\n\nasync function renderCompany() {\n  const el = document.getElementById(\"view-company\");\n  const [{ manufacturer, certification_progress }, { locations }] = await Promise.all([\n    partnerFetch(\"manufacturer-get\"),\n    partnerFetch(\"manufacturer-location-list\"),\n  ]);\n  document.getElementById(\"sidebar-progress\").textContent = `Artifact Ready ${certification_progress?.pct ?? 0}%`;\n  el.innerHTML = `\n    <div style=\"display:flex;justify-content:space-between;align-items:flex-end;gap:16px;margin-bottom:18px\">\n      <div><h1 class=\"stage-title\">Company & locations</h1><p class=\"stage-desc\">Legal profile and fulfillment locations.</p></div>\n      <button type=\"button\" class=\"btn btn-primary\" id=\"btn-add-location\">Add location</button>\n    </div>\n    <div class=\"panel\" style=\"margin-bottom:18px\">\n      <div class=\"panel-header\"><strong>Company profile</strong><button type=\"button\" class=\"btn btn-secondary\" id=\"btn-save-company\">Save</button></div>\n      <div class=\"panel-body split-row\">\n        ${field(\"name\", \"Display name\", manufacturer?.name)}\n        ${field(\"legal_name\", \"Legal name\", manufacturer?.legal_name)}\n        ${field(\"country\", \"Country\", manufacturer?.country)}\n        ${field(\"website\", \"Website\", manufacturer?.website)}\n        ${field(\"support_email\", \"Support email\", manufacturer?.support_email)}\n        ${field(\"business_email\", \"Business email\", manufacturer?.business_email)}\n      </div>\n    </div>\n    <div class=\"panel\">\n      <div class=\"panel-header\"><strong>Locations</strong></div>\n      <div class=\"panel-body\">${renderTable(\n        [\"Name\", \"Country\", \"Status\"],\n        (locations || []).map(\n          (l) => `<tr><td>${escapeHtml(l.name)}</td><td>${escapeHtml(l.country)}</td><td><span class=\"badge badge-neutral\">${escapeHtml(l.status)}</span></td></tr>`\n        ).join(\"\") || '<tr><td colspan=\"3\" class=\"empty\">No locations yet</td></tr>'\n      )}</div>\n    </div>`;\n\n  document.getElementById(\"btn-save-company\").onclick = async () => {\n    const body = {};\n    el.querySelectorAll(\"[data-field]\").forEach((input) => {\n      body[input.dataset.field] = input.value;\n    });\n    await partnerFetch(\"manufacturer-update\", { method: \"POST\", body });\n    showToast(\"Saved\", \"Company profile updated\");\n  };\n\n  document.getElementById(\"btn-add-location\").onclick = () => {\n    openModal({\n      title: \"Add location\",\n      bodyHtml: `\n        <div class=\"field\"><label>Name</label><input class=\"input\" id=\"loc-name\" /></div>\n        <div class=\"field\"><label>Country</label><input class=\"input\" id=\"loc-country\" /></div>\n        <div class=\"field\"><label>City</label><input class=\"input\" id=\"loc-city\" /></div>`,\n      onSave: async () => {\n        await partnerFetch(\"manufacturer-location-create\", {\n          method: \"POST\",\n          body: {\n            name: document.getElementById(\"loc-name\").value,\n            country: document.getElementById(\"loc-country\").value,\n            city: document.getElementById(\"loc-city\").value,\n          },\n        });\n        showToast(\"Location added\", \"\");\n        await renderCompany();\n      },\n    });\n  };\n}\n\nfunction field(key, label, value) {\n  return `<div class=\"field\"><label>${escapeHtml(label)}</label><input class=\"input\" data-field=\"${escapeHtml(key)}\" value=\"${escapeHtml(value || \"\")}\" /></div>`;\n}\n\nasync function renderCatalog() {\n  const el = document.getElementById(\"view-catalog\");\n  const tab = sessionStorage.getItem(\"catalog_tab\") || \"products\";\n  el.innerHTML = `\n    <div style=\"display:flex;justify-content:space-between;align-items:flex-end;gap:16px;margin-bottom:18px\">\n      <div>\n        <h1 class=\"stage-title\">Catalog</h1>\n        <p class=\"stage-desc\">Products and Universal Blueprints for creator-ready listings.</p>\n        <div style=\"display:flex;gap:8px;margin-top:12px\">\n          <button type=\"button\" class=\"btn ${tab === \"products\" ? \"btn-primary\" : \"btn-secondary\"}\" data-catalog-tab=\"products\">Products</button>\n          <button type=\"button\" class=\"btn ${tab === \"blueprints\" ? \"btn-primary\" : \"btn-secondary\"}\" data-catalog-tab=\"blueprints\">Blueprints</button>\n        </div>\n      </div>\n      <button type=\"button\" class=\"btn btn-primary\" id=\"btn-catalog-primary\">${tab === \"blueprints\" ? \"New blueprint\" : \"Add product\"}</button>\n    </div>\n    <div id=\"catalog-panel\"></div>`;\n\n  el.querySelectorAll(\"[data-catalog-tab]\").forEach((btn) => {\n    btn.onclick = () => {\n      sessionStorage.setItem(\"catalog_tab\", btn.dataset.catalogTab);\n      renderCatalog();\n    };\n  });\n\n  document.getElementById(\"btn-catalog-primary\").onclick = () =>\n    tab === \"blueprints\" ? openBlueprintWizard() : openProductModal();\n\n  const panel = document.getElementById(\"catalog-panel\");\n  if (tab === \"blueprints\") await renderBlueprintList(panel);\n  else await renderProductList(panel);\n}\n\nasync function renderProductList(panel) {\n  const { products } = await partnerFetch(\"manufacturer-product-list\");\n  panel.innerHTML = `<div class=\"panel\"><div class=\"panel-body\">${renderTable(\n    [\"Product\", \"Category\", \"Status\", \"\"],\n    (products || []).map(\n      (p) => `<tr>\n        <td>${escapeHtml(p.title)}</td>\n        <td>${escapeHtml(p.normalized_category || p.category || \"—\")}</td>\n        <td><span class=\"badge ${badgeForStatus(p.status)}\">${escapeHtml(p.status)}</span></td>\n        <td><button type=\"button\" class=\"btn btn-secondary btn-product\" data-id=\"${escapeHtml(p.id)}\">Manage</button></td>\n      </tr>`\n    ).join(\"\") || '<tr><td colspan=\"4\" class=\"empty\">No products yet</td></tr>'\n  )}</div></div>`;\n  panel.querySelectorAll(\".btn-product\").forEach((btn) => {\n    btn.onclick = () => openProductModal(btn.dataset.id);\n  });\n}\n\nasync function renderBlueprintList(panel) {\n  const { blueprints } = await partnerFetch(\"partner-blueprint-list\");\n  panel.innerHTML = `<div class=\"panel\"><div class=\"panel-body\">${renderTable(\n    [\"Blueprint\", \"Source\", \"Status\", \"Quality\", \"\"],\n    (blueprints || []).map(\n      (b) => `<tr>\n        <td>${escapeHtml(b.title)}</td>\n        <td>${escapeHtml(b.source_type || \"manual\")}</td>\n        <td><span class=\"badge ${badgeForStatus(b.eazpire_status || b.status)}\">${escapeHtml(b.eazpire_status || b.status)}</span></td>\n        <td>${escapeHtml(b.quality_score ?? \"—\")}</td>\n        <td><button type=\"button\" class=\"btn btn-secondary btn-blueprint\" data-id=\"${escapeHtml(b.id)}\">Edit</button></td>\n      </tr>`\n    ).join(\"\") || '<tr><td colspan=\"5\" class=\"empty\">No blueprints yet — create your first Universal Blueprint.</td></tr>'\n  )}</div></div>`;\n  panel.querySelectorAll(\".btn-blueprint\").forEach((btn) => {\n    btn.onclick = () => openBlueprintWizard(btn.dataset.id);\n  });\n}\n\nasync function openBlueprintWizard(providerBlueprintId) {\n  let draft = {\n    title: \"\",\n    normalized_category: \"apparel.tshirt\",\n    productId: null,\n    variants: [{ variant_key: \"black_m\", color: \"Black\", size: \"M\", base_cost: 15, currency: \"EUR\" }],\n    print_areas: [\n      {\n        area_key: \"front\",\n        width_px: 4500,\n        height_px: 5400,\n        dpi: 300,\n        safe_zone: { x: 300, y: 300, width: 3900, height: 4800 },\n      },\n    ],\n  };\n  let validation = null;\n\n  if (providerBlueprintId) {\n    const data = await partnerFetch(\"partner-blueprint-get\", { query: { blueprint_id: providerBlueprintId } });\n    const raw = data.provider?.raw || {};\n    draft = {\n      provider_blueprint_id: providerBlueprintId,\n      title: data.provider?.title || raw.title || \"\",\n      normalized_category: raw.normalized_category || data.eazpire?.normalized_category || \"apparel.tshirt\",\n      external_product_id: raw.external_product_id || \"\",\n      variants: raw.variants?.length ? raw.variants : draft.variants,\n      print_areas: raw.print_areas?.length ? raw.print_areas : draft.print_areas,\n    };\n    try {\n      const v = await partnerFetch(\"partner-blueprint-validate\", { query: { blueprint_id: providerBlueprintId } });\n      validation = v.validation;\n    } catch {\n      /* ignore */\n    }\n  }\n\n  openModal({\n    title: providerBlueprintId ? \"Edit Universal Blueprint\" : \"New Universal Blueprint\",\n    bodyHtml: blueprintWizardHtml(draft, validation),\n    onSave: async () => {\n      const body = readBlueprintWizardForm(draft);\n      const op = providerBlueprintId ? \"partner-blueprint-update\" : \"partner-blueprint-create\";\n      await partnerFetch(op, { method: \"POST\", body });\n      showToast(\"Blueprint saved\", \"Normalized and validated\");\n      await renderCatalog();\n    },\n  });\n\n  document.getElementById(\"btn-bp-import-json\")?.addEventListener(\"click\", async () => {\n    const text = document.getElementById(\"bp-json-import\")?.value?.trim();\n    if (!text) return;\n    try {\n      await partnerFetch(\"partner-blueprint-upload-json\", { method: \"POST\", body: { json: JSON.parse(text) } });\n      showToast(\"JSON imported\", \"Blueprint converted\");\n      closeModal();\n      await renderCatalog();\n    } catch (e) {\n      showToast(\"Import failed\", e.message || String(e));\n    }\n  });\n\n  document.getElementById(\"btn-bp-validate\")?.addEventListener(\"click\", async () => {\n    const body = readBlueprintWizardForm(draft);\n    const saved = await partnerFetch(providerBlueprintId ? \"partner-blueprint-update\" : \"partner-blueprint-create\", {\n      method: \"POST\",\n      body,\n    });\n    const id = saved.provider?.id || providerBlueprintId;\n    const v = await partnerFetch(\"partner-blueprint-validate\", { query: { blueprint_id: id } });\n    showToast(v.validation?.ok ? \"Validation passed\" : \"Validation issues\", `${v.validation?.errors?.length || 0} errors`);\n    openBlueprintWizard(id);\n  });\n\n  document.getElementById(\"btn-bp-submit\")?.addEventListener(\"click\", async () => {\n    const body = readBlueprintWizardForm(draft);\n    const saved = await partnerFetch(providerBlueprintId ? \"partner-blueprint-update\" : \"partner-blueprint-create\", {\n      method: \"POST\",\n      body,\n    });\n    const id = saved.provider?.id || providerBlueprintId;\n    try {\n      await partnerFetch(\"partner-blueprint-submit-review\", { method: \"POST\", body: { blueprint_id: id } });\n      showToast(\"Submitted\", \"Blueprint sent for admin review\");\n      closeModal();\n      await renderCatalog();\n    } catch (e) {\n      showToast(\"Submit blocked\", (e.data?.errors || [e.message]).map((x) => x.message || x).join(\", \"));\n    }\n  });\n}\n\nfunction blueprintWizardHtml(draft, validation) {\n  const pa = draft.print_areas?.[0] || {};\n  const v0 = draft.variants?.[0] || {};\n  const valBlock = validation\n    ? `<div class=\"panel\" style=\"margin-top:12px;background:var(--surface-2)\">\n        <div class=\"panel-body\">\n          <strong>Validation</strong> — Score ${validation.score ?? 0}\n          ${validation.errors?.length ? `<ul>${validation.errors.map((e) => `<li>${escapeHtml(e.message || e.code)}</li>`).join(\"\")}</ul>` : \"<p>No hard errors</p>\"}\n        </div>\n      </div>`\n    : \"\";\n  return `\n    <p class=\"stage-desc\">Universal Blueprint wizard (V1): identity, variants, print areas, shipping defaults.</p>\n    <div class=\"field\"><label>Product title</label><input class=\"input\" id=\"bp-title\" value=\"${escapeHtml(draft.title)}\" required /></div>\n    <div class=\"field\"><label>Category</label>\n      <select class=\"input\" id=\"bp-category\">\n        <option value=\"apparel.tshirt\" ${draft.normalized_category === \"apparel.tshirt\" ? \"selected\" : \"\"}>T-Shirt</option>\n        <option value=\"apparel.hoodie\" ${draft.normalized_category === \"apparel.hoodie\" ? \"selected\" : \"\"}>Hoodie</option>\n        <option value=\"apparel.socks\" ${draft.normalized_category === \"apparel.socks\" ? \"selected\" : \"\"}>Socks</option>\n        <option value=\"wall_art.poster\" ${draft.normalized_category === \"wall_art.poster\" ? \"selected\" : \"\"}>Poster</option>\n        <option value=\"home.mug\" ${draft.normalized_category === \"home.mug\" ? \"selected\" : \"\"}>Mug</option>\n        <option value=\"accessory.cap\" ${draft.normalized_category === \"accessory.cap\" ? \"selected\" : \"\"}>Cap</option>\n      </select>\n    </div>\n    <div class=\"field\"><label>External product ID</label><input class=\"input\" id=\"bp-ext-id\" value=\"${escapeHtml(draft.external_product_id || \"\")}\" placeholder=\"Your SKU / product code\" /></div>\n    <hr style=\"border:0;border-top:1px solid var(--line);margin:16px 0\" />\n    <p><strong>Variant (first)</strong></p>\n    <div class=\"split-row\">\n      <div class=\"field\"><label>Color</label><input class=\"input\" id=\"bp-v-color\" value=\"${escapeHtml(v0.color?.name || v0.color || \"Black\")}\" /></div>\n      <div class=\"field\"><label>Size</label><input class=\"input\" id=\"bp-v-size\" value=\"${escapeHtml(v0.size?.label || v0.size || \"M\")}\" /></div>\n      <div class=\"field\"><label>Base cost (EUR)</label><input class=\"input\" id=\"bp-v-cost\" type=\"number\" step=\"0.01\" value=\"${escapeHtml(v0.base_cost ?? 15)}\" /></div>\n    </div>\n    <hr style=\"border:0;border-top:1px solid var(--line);margin:16px 0\" />\n    <p><strong>Print area — front</strong></p>\n    <div class=\"split-row\">\n      <div class=\"field\"><label>Canvas width px</label><input class=\"input\" id=\"bp-pa-w\" type=\"number\" value=\"${escapeHtml(pa.width_px || pa.canvas?.width_px || 4500)}\" /></div>\n      <div class=\"field\"><label>Canvas height px</label><input class=\"input\" id=\"bp-pa-h\" type=\"number\" value=\"${escapeHtml(pa.height_px || pa.canvas?.height_px || 5400)}\" /></div>\n      <div class=\"field\"><label>DPI</label><input class=\"input\" id=\"bp-pa-dpi\" type=\"number\" value=\"${escapeHtml(pa.dpi || pa.canvas?.dpi || 300)}\" /></div>\n    </div>\n    <hr style=\"border:0;border-top:1px solid var(--line);margin:16px 0\" />\n    <p><strong>Import JSON</strong></p>\n    <textarea class=\"textarea\" id=\"bp-json-import\" rows=\"3\" placeholder='Paste provider JSON…'></textarea>\n    <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-bp-import-json\" style=\"margin-top:8px\">Import JSON</button>\n    ${valBlock}\n    <div style=\"margin-top:14px;display:flex;gap:8px;flex-wrap:wrap\">\n      <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-bp-validate\">Run validation</button>\n      <button type=\"button\" class=\"btn btn-warning\" id=\"btn-bp-submit\">Submit for review</button>\n    </div>`;\n}\n\nfunction readBlueprintWizardForm(draft) {\n  const w = Number(document.getElementById(\"bp-pa-w\").value);\n  const h = Number(document.getElementById(\"bp-pa-h\").value);\n  const dpi = Number(document.getElementById(\"bp-pa-dpi\").value);\n  return {\n    provider_blueprint_id: draft.provider_blueprint_id,\n    title: document.getElementById(\"bp-title\").value,\n    normalized_category: document.getElementById(\"bp-category\").value,\n    external_product_id: document.getElementById(\"bp-ext-id\").value || undefined,\n    variants: [\n      {\n        variant_key: `${document.getElementById(\"bp-v-color\").value}_${document.getElementById(\"bp-v-size\").value}`.toLowerCase().replace(/\\s+/g, \"_\"),\n        color: document.getElementById(\"bp-v-color\").value,\n        size: document.getElementById(\"bp-v-size\").value,\n        base_cost: Number(document.getElementById(\"bp-v-cost\").value),\n        currency: \"EUR\",\n      },\n    ],\n    print_areas: [\n      {\n        area_key: \"front\",\n        label: \"Front Print\",\n        width_px: w,\n        height_px: h,\n        dpi,\n        safe_zone: { x: Math.round(w * 0.07), y: Math.round(h * 0.07), width: Math.round(w * 0.86), height: Math.round(h * 0.86) },\n      },\n    ],\n    shipping: [{ ship_from_country: \"DE\", ship_to_countries: [\"DE\", \"AT\", \"CH\"], base_shipping: 4.9, currency: \"EUR\" }],\n  };\n}\nasync function openProductModal(productId) {\n  let product = { title: \"\", sku_base: \"\", description: \"\" };\n  let variants = [];\n  let print_areas = [];\n  if (productId) {\n    const data = await partnerFetch(\"manufacturer-product-get\", { query: { product_id: productId } });\n    product = data.product;\n    variants = data.variants || [];\n    print_areas = data.print_areas || [];\n  }\n\n  openModal({\n    title: productId ? \"Edit product\" : \"Add product\",\n    bodyHtml: `\n      <div class=\"field\"><label>Title</label><input class=\"input\" id=\"p-title\" value=\"${escapeHtml(product.title)}\" /></div>\n      <div class=\"field\"><label>SKU base</label><input class=\"input\" id=\"p-sku\" value=\"${escapeHtml(product.sku_base || \"\")}\" /></div>\n      <div class=\"field\"><label>Description</label><textarea class=\"textarea\" id=\"p-desc\">${escapeHtml(product.description || \"\")}</textarea></div>\n      ${productId ? `\n        <hr style=\"border:0;border-top:1px solid var(--line);margin:18px 0\" />\n        <p><strong>Variants</strong> (${variants.length})</p>\n        <div class=\"field\"><label>New variant SKU</label><input class=\"input\" id=\"v-sku\" placeholder=\"SKU-RED-M\" /></div>\n        <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-add-variant\">Add variant</button>\n        <hr style=\"border:0;border-top:1px solid var(--line);margin:18px 0\" />\n        <p><strong>Print area</strong></p>\n        <div class=\"split-row\">\n          <div class=\"field\"><label>Width px</label><input class=\"input\" id=\"pa-w\" type=\"number\" value=\"${escapeHtml(print_areas[0]?.width_px || 4500)}\" /></div>\n          <div class=\"field\"><label>Height px</label><input class=\"input\" id=\"pa-h\" type=\"number\" value=\"${escapeHtml(print_areas[0]?.height_px || 5400)}\" /></div>\n        </div>\n        <button type=\"button\" class=\"btn btn-secondary\" id=\"btn-save-print-area\">Save print area</button>\n        <button type=\"button\" class=\"btn btn-warning\" id=\"btn-submit-review\" style=\"margin-left:8px\">Submit for review</button>\n      ` : \"\"}`,\n    onSave: async () => {\n      const body = {\n        title: document.getElementById(\"p-title\").value,\n        sku_base: document.getElementById(\"p-sku\").value,\n        description: document.getElementById(\"p-desc\").value,\n      };\n      if (productId) {\n        body.product_id = productId;\n        await partnerFetch(\"manufacturer-product-update\", { method: \"POST\", body });\n      } else {\n        await partnerFetch(\"manufacturer-product-create\", { method: \"POST\", body });\n      }\n      showToast(\"Product saved\", \"\");\n      await renderCatalog();\n    },\n  });\n\n  if (productId) {\n    document.getElementById(\"btn-add-variant\")?.addEventListener(\"click\", async () => {\n      await partnerFetch(\"manufacturer-variant-create\", {\n        method: \"POST\",\n        body: { product_id: productId, sku: document.getElementById(\"v-sku\").value, title: document.getElementById(\"v-sku\").value },\n      });\n      showToast(\"Variant added\", \"\");\n      openProductModal(productId);\n    });\n    document.getElementById(\"btn-save-print-area\")?.addEventListener(\"click\", async () => {\n      await partnerFetch(\"manufacturer-print-area-upsert\", {\n        method: \"POST\",\n        body: {\n          product_id: productId,\n          placement_key: \"front\",\n          width_px: Number(document.getElementById(\"pa-w\").value),\n          height_px: Number(document.getElementById(\"pa-h\").value),\n          dpi: 300,\n          safe_zone: { x: 0, y: 0, width: Number(document.getElementById(\"pa-w\").value), height: Number(document.getElementById(\"pa-h\").value) },\n        },\n      });\n      showToast(\"Print area saved\", \"\");\n    });\n    document.getElementById(\"btn-submit-review\")?.addEventListener(\"click\", async () => {\n      try {\n        await partnerFetch(\"manufacturer-product-submit-review\", { method: \"POST\", body: { product_id: productId } });\n        showToast(\"Submitted\", \"Product sent for Eazpire review\");\n        closeModal();\n        await renderCatalog();\n      } catch (e) {\n        showToast(\"Review blocked\", (e.data?.errors || [e.message]).join(\", \"));\n      }\n    });\n  }\n}\n\nasync function renderOrders() {\n  const el = document.getElementById(\"view-orders\");\n  const { orders } = await partnerFetch(\"manufacturer-order-list\");\n  el.innerHTML = `\n    <h1 class=\"stage-title\">Orders & fulfillment</h1>\n    <p class=\"stage-desc\">Accept test orders, download print files, add tracking.</p>\n    <div class=\"panel\" style=\"margin-top:18px\"><div class=\"panel-body\">${renderTable(\n      [\"Order\", \"Status\", \"Tracking\", \"Actions\"],\n      (orders || []).map((o) => `<tr>\n        <td>${escapeHtml(o.order_number || o.id)}</td>\n        <td><span class=\"badge ${badgeForStatus(o.status)}\">${escapeHtml(o.status)}</span></td>\n        <td>${escapeHtml(o.tracking_number || \"—\")}</td>\n        <td>${orderActions(o)}</td>\n      </tr>`).join(\"\") || '<tr><td colspan=\"4\" class=\"empty\">No orders yet</td></tr>'\n    )}</div></div>`;\n  bindOrderActions(el);\n}\n\nfunction orderActions(order) {\n  const id = escapeHtml(order.id);\n  if (order.status === \"received\") return `<button class=\"btn btn-secondary btn-accept\" data-id=\"${id}\">Accept</button>`;\n  if (order.status === \"in_production\") {\n    return `<button class=\"btn btn-secondary btn-print\" data-id=\"${id}\">Print file</button>\n      <button class=\"btn btn-primary btn-track\" data-id=\"${id}\">Tracking</button>`;\n  }\n  return \"—\";\n}\n\nfunction bindOrderActions(root) {\n  root.querySelectorAll(\".btn-accept\").forEach((btn) => {\n    btn.onclick = async () => {\n      await partnerFetch(\"manufacturer-order-accept\", { method: \"POST\", body: { order_id: btn.dataset.id } });\n      showToast(\"Order accepted\", \"\");\n      await renderOrders();\n    };\n  });\n  root.querySelectorAll(\".btn-print\").forEach((btn) => {\n    btn.onclick = async () => {\n      const data = await partnerFetch(\"manufacturer-order-download-print-file\", { query: { order_id: btn.dataset.id } });\n      if (data.url) window.open(data.url, \"_blank\");\n    };\n  });\n  root.querySelectorAll(\".btn-track\").forEach((btn) => {\n    btn.onclick = () => {\n      openModal({\n        title: \"Upload tracking\",\n        bodyHtml: `<div class=\"field\"><label>Tracking number</label><input class=\"input\" id=\"track-no\" /></div>\n          <div class=\"field\"><label>Carrier</label><input class=\"input\" id=\"track-carrier\" value=\"DHL\" /></div>`,\n        onSave: async () => {\n          await partnerFetch(\"manufacturer-order-tracking-update\", {\n            method: \"POST\",\n            body: {\n              order_id: btn.dataset.id,\n              tracking_number: document.getElementById(\"track-no\").value,\n              carrier: document.getElementById(\"track-carrier\").value,\n            },\n          });\n          showToast(\"Tracking saved\", \"\");\n          await renderOrders();\n        },\n      });\n    };\n  });\n}\n\nfunction renderApiDocs() {\n  document.getElementById(\"view-api\").innerHTML = `\n    <h1 class=\"stage-title\">API & webhooks</h1>\n    <p class=\"stage-desc\">V1: documentation preview. API keys ship in a later release.</p>\n    <div class=\"code-panel\"><pre>POST ${location.origin}?op=manufacturer-product-list\nCookie: partner_session=…</pre></div>`;\n}\n\nasync function renderCertification() {\n  const el = document.getElementById(\"view-certification\");\n  const { certifications } = await partnerFetch(\"manufacturer-certification-list\");\n  el.innerHTML = `\n    <div class=\"cert-hero\"><h2>Certification</h2><p>Complete checklist items to unlock Artifact Ready status.</p></div>\n    <div class=\"panel\"><div class=\"panel-body\">${(certifications || []).map(\n      (c) => `<div class=\"check-item order-card\"><div><strong>${escapeHtml(c.title || c.certification_key)}</strong><p>${escapeHtml(c.description || \"\")}</p></div><span class=\"badge ${badgeForStatus(c.status)}\">${escapeHtml(c.status)}</span></div>`\n    ).join(\"\") || '<div class=\"empty\">No certification items yet</div>'}</div></div>\n    <button type=\"button\" class=\"btn btn-primary\" id=\"btn-request-cert\" style=\"margin-top:14px\">Request review</button>`;\n  document.getElementById(\"btn-request-cert\").onclick = async () => {\n    await partnerFetch(\"manufacturer-certification-request\", { method: \"POST\", body: { certification_key: \"verified_manufacturer\" } });\n    showToast(\"Review requested\", \"\");\n    await renderCertification();\n  };\n}\n\nconst ROUTE_RENDERERS = {\n  \"/\": renderOverview,\n  \"/company\": renderCompany,\n  \"/catalog\": renderCatalog,\n  \"/orders\": renderOrders,\n  \"/api\": renderApiDocs,\n  \"/certification\": renderCertification,\n};\n\nasync function onRoute(route) {\n  const fn = ROUTE_RENDERERS[route] || ROUTE_RENDERERS[\"/\"];\n  try {\n    await fn();\n  } catch (e) {\n    if (e.status === 401) showLogin();\n    else showToast(\"Error\", e.message || String(e));\n  }\n}\n\ndocument.getElementById(\"login-form\").addEventListener(\"submit\", async (e) => {\n  e.preventDefault();\n  const email = document.getElementById(\"login-email\").value.trim();\n  const submitBtn = e.target.querySelector('button[type=\"submit\"]');\n  const loginMessage = document.getElementById(\"login-message\");\n  loginMessage.textContent = \"\";\n  loginMessage.classList.remove(\"login-message--apply-hint\");\n  if (submitBtn) submitBtn.disabled = true;\n  try {\n    const data = await partnerFetch(\"partner-auth-request\", { method: \"POST\", body: { email } });\n    if (data.poll_token) {\n      startLoginWait(email, data.poll_token);\n    } else {\n      showLoginFormPanel();\n      loginMessage.textContent =\n        \"If this email is registered or has a partner application on file, you will receive a sign-in link within a few minutes. Check spam or contact Eazpire if you were invited but receive nothing.\";\n    }\n  } catch (err) {\n    const code = err.message || err.data?.error;\n    if (code === \"application_required\") {\n      loginMessage.textContent = APPLICATION_REQUIRED_MESSAGE;\n      loginMessage.classList.add(\"login-message--apply-hint\");\n      showLoginFormPanel();\n      pulseBecomePartnerButton();\n    } else {\n      const blocked = code === \"email_blocked\";\n      loginMessage.textContent = blocked\n        ? BLOCKED_EMAIL_MESSAGE\n        : err.message || \"Could not send sign-in link. Please try again.\";\n      showLoginFormPanel();\n    }\n  } finally {\n    if (submitBtn) submitBtn.disabled = false;\n  }\n});\n\nfunction pulseBecomePartnerButton() {\n  const btn = document.getElementById(\"btn-show-apply\");\n  if (!btn) return;\n  btn.classList.remove(\"btn-attention-pulse\");\n  void btn.offsetWidth;\n  btn.classList.add(\"btn-attention-pulse\");\n  btn.scrollIntoView({ behavior: \"smooth\", block: \"nearest\" });\n  window.setTimeout(() => btn.classList.remove(\"btn-attention-pulse\"), 1600);\n}\n\ndocument.getElementById(\"btn-login-waiting-cancel\").addEventListener(\"click\", () => {\n  stopLoginWait();\n  showLoginFormPanel();\n});\n\ndocument.getElementById(\"btn-logout\").addEventListener(\"click\", async () => {\n  await partnerFetch(\"partner-auth-logout\", { method: \"POST\" });\n  showLogin();\n});\n\ndocument.getElementById(\"btn-applicant-logout\").addEventListener(\"click\", async () => {\n  await partnerFetch(\"partner-auth-logout\", { method: \"POST\" });\n  showLogin();\n});\n\nconst APPLY_STEP_COUNT = 7;\n\nconst applyWizard = {\n  step: 0,\n  submitting: false,\n};\n\nfunction applyFieldValue(id) {\n  return document.getElementById(id)?.value?.trim() || \"\";\n}\n\nfunction showApplyError(stepIndex, message) {\n  const el = document.getElementById(`apply-error-${stepIndex}`);\n  if (!el) return;\n  el.textContent = message;\n  el.hidden = !message;\n}\n\nfunction clearApplyErrors() {\n  for (let i = 0; i < APPLY_STEP_COUNT; i++) showApplyError(i, \"\");\n}\n\nfunction validateApplyStep(stepIndex) {\n  clearApplyErrors();\n  if (stepIndex === 0) {\n    if (!applyFieldValue(\"apply-company\")) {\n      showApplyError(0, \"Please fill in your company name.\");\n      return false;\n    }\n  } else if (stepIndex === 1) {\n    if (!applyFieldValue(\"apply-contact\")) {\n      showApplyError(1, \"Please fill in a contact name.\");\n      return false;\n    }\n  } else if (stepIndex === 2) {\n    const email = applyFieldValue(\"apply-email\");\n    if (!email) {\n      showApplyError(2, \"Please fill in your business email.\");\n      return false;\n    }\n    if (!/^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/.test(email)) {\n      showApplyError(2, \"Please enter a valid email address.\");\n      return false;\n    }\n  } else if (stepIndex === 3) {\n    if (!applyFieldValue(\"apply-country\")) {\n      showApplyError(3, \"Please fill in your country.\");\n      return false;\n    }\n  } else if (stepIndex === 4) {\n    const website = applyFieldValue(\"apply-website\");\n    if (website && !/^https?:\\/\\/.+/i.test(website)) {\n      showApplyError(4, \"Please enter a valid URL starting with http:// or https://\");\n      return false;\n    }\n  }\n  return true;\n}\n\nfunction renderApplyReview() {\n  const summary = document.getElementById(\"apply-review-summary\");\n  if (!summary) return;\n  const website = applyFieldValue(\"apply-website\");\n  const products = applyFieldValue(\"apply-products\");\n  summary.innerHTML = `\n    <dt>Company</dt><dd>${escapeHtml(applyFieldValue(\"apply-company\"))}</dd>\n    <dt>Contact</dt><dd>${escapeHtml(applyFieldValue(\"apply-contact\"))}</dd>\n    <dt>Email</dt><dd>${escapeHtml(applyFieldValue(\"apply-email\"))}</dd>\n    <dt>Country</dt><dd>${escapeHtml(applyFieldValue(\"apply-country\"))}</dd>\n    <dt>Website</dt><dd>${escapeHtml(website || \"—\")}</dd>\n    <dt>Capabilities</dt><dd>${escapeHtml(products || \"—\")}</dd>`;\n}\n\nfunction renderApplyStep() {\n  const { step } = applyWizard;\n  document.querySelectorAll(\".apply-step\").forEach((el) => {\n    el.hidden = Number(el.dataset.step) !== step;\n  });\n\n  const pct = ((step + 1) / APPLY_STEP_COUNT) * 100;\n  const fill = document.getElementById(\"apply-progress-fill\");\n  const label = document.getElementById(\"apply-progress-label\");\n  if (fill) fill.style.width = `${pct}%`;\n  if (label) label.textContent = `${step + 1} of ${APPLY_STEP_COUNT}`;\n\n  const backBtn = document.getElementById(\"btn-apply-back\");\n  const nextBtn = document.getElementById(\"btn-apply-next\");\n  const submitBtn = document.getElementById(\"btn-apply-submit\");\n  const isReview = step === APPLY_STEP_COUNT - 1;\n\n  if (backBtn) backBtn.hidden = step === 0;\n  if (nextBtn) nextBtn.hidden = isReview;\n  if (submitBtn) submitBtn.hidden = !isReview;\n\n  if (isReview) renderApplyReview();\n\n  const activeStep = document.querySelector(`.apply-step[data-step=\"${step}\"]`);\n  const focusInput = activeStep?.querySelector(\".apply-input, .apply-textarea\");\n  if (focusInput && !applyWizard.submitting) {\n    requestAnimationFrame(() => focusInput.focus());\n  }\n}\n\nfunction resetApplyWizard() {\n  applyWizard.step = 0;\n  applyWizard.submitting = false;\n  document.getElementById(\"apply-form\")?.reset();\n  clearApplyErrors();\n  const submitBtn = document.getElementById(\"btn-apply-submit\");\n  if (submitBtn) submitBtn.disabled = false;\n  document.getElementById(\"apply-form\")?.removeAttribute(\"hidden\");\n  document.getElementById(\"apply-success\")?.setAttribute(\"hidden\", \"\");\n  document.getElementById(\"apply-wizard-actions\")?.removeAttribute(\"hidden\");\n  document.querySelector(\".apply-wizard-top\")?.removeAttribute(\"hidden\");\n  renderApplyStep();\n}\n\nfunction showApplyWizard() {\n  stopLoginWait();\n  document.getElementById(\"login-panel\").hidden = true;\n  document.getElementById(\"login-waiting\").hidden = true;\n  document.getElementById(\"apply-wizard\").hidden = false;\n  resetApplyWizard();\n}\n\nfunction hideApplyWizard() {\n  document.getElementById(\"apply-wizard\").hidden = true;\n  showLoginFormPanel();\n  resetApplyWizard();\n}\n\nfunction advanceApplyStep() {\n  if (applyWizard.submitting) return;\n  if (!validateApplyStep(applyWizard.step)) return;\n  if (applyWizard.step < APPLY_STEP_COUNT - 1) {\n    applyWizard.step += 1;\n    renderApplyStep();\n  }\n}\n\nfunction retreatApplyStep() {\n  if (applyWizard.submitting) return;\n  if (applyWizard.step > 0) {\n    applyWizard.step -= 1;\n    renderApplyStep();\n  }\n}\n\nfunction showApplySuccess() {\n  applyWizard.submitting = true;\n  document.getElementById(\"apply-form\")?.setAttribute(\"hidden\", \"\");\n  document.getElementById(\"apply-success\")?.removeAttribute(\"hidden\");\n  document.getElementById(\"apply-wizard-actions\")?.setAttribute(\"hidden\", \"\");\n  document.querySelector(\".apply-wizard-top\")?.setAttribute(\"hidden\", \"\");\n}\n\ndocument.getElementById(\"btn-show-apply\").addEventListener(\"click\", showApplyWizard);\n\ndocument.getElementById(\"btn-back-login\").addEventListener(\"click\", hideApplyWizard);\n\ndocument.getElementById(\"btn-apply-back\").addEventListener(\"click\", retreatApplyStep);\n\ndocument.getElementById(\"btn-apply-next\").addEventListener(\"click\", advanceApplyStep);\n\ndocument.getElementById(\"apply-form\").addEventListener(\"keydown\", (e) => {\n  if (e.key !== \"Enter\") return;\n  const tag = e.target?.tagName?.toLowerCase();\n  if (tag === \"textarea\") return;\n  e.preventDefault();\n  if (applyWizard.step < APPLY_STEP_COUNT - 1) advanceApplyStep();\n});\n\ndocument.getElementById(\"apply-form\").addEventListener(\"submit\", async (e) => {\n  e.preventDefault();\n  if (applyWizard.submitting) return;\n  if (!validateApplyStep(applyWizard.step)) return;\n\n  const submitBtn = document.getElementById(\"btn-apply-submit\");\n  if (submitBtn) submitBtn.disabled = true;\n\n  try {\n    await partnerFetch(\"partner-application-submit\", {\n      method: \"POST\",\n      body: {\n        company_name: applyFieldValue(\"apply-company\"),\n        contact_name: applyFieldValue(\"apply-contact\"),\n        email: applyFieldValue(\"apply-email\"),\n        country: applyFieldValue(\"apply-country\"),\n        website: applyFieldValue(\"apply-website\") || undefined,\n        product_types: applyFieldValue(\"apply-products\") || undefined,\n        message: applyFieldValue(\"apply-message-text\") || undefined,\n        capabilities: applyFieldValue(\"apply-products\") || undefined,\n      },\n    });\n    showApplySuccess();\n  } catch (err) {\n    const blocked = err.message === \"email_blocked\" || err.data?.error === \"email_blocked\";\n    if (blocked) {\n      applyWizard.step = 2;\n      renderApplyStep();\n      showApplyError(2, BLOCKED_EMAIL_MESSAGE);\n    } else {\n      showApplyError(APPLY_STEP_COUNT - 1, err.message || \"Something went wrong. Please try again.\");\n    }\n    if (submitBtn) submitBtn.disabled = false;\n  }\n});\n\n(async function boot() {\n  const mode = await ensureSession();\n  if (mode === \"full\") {\n    await enterFullPortal(location.pathname.includes(\"application-status\") ? \"/\" : location.pathname || \"/\");\n  } else if (mode === \"applicant\") {\n    showApplicantShell();\n    await renderApplicationStatus();\n  } else {\n    const authError = new URLSearchParams(location.search).get(\"auth_error\") || \"\";\n    showLogin(authError);\n    if (authError) {\n      history.replaceState({}, \"\", \"/\");\n    }\n    if (location.pathname === \"/application-status\") {\n      history.replaceState({}, \"\", \"/\");\n    }\n  }\n})();\n"},"shared/css/partner-ui.css":{"contentType":"text/css; charset=utf-8","body":"/* Eazpire Partner UI Kit — shared by partner.eazpire.com + admin.eazpire.com/partner */\n:root {\n  --bg: #f4f6fb;\n  --surface: #ffffff;\n  --surface-2: #f8fafc;\n  --surface-3: #eef2f7;\n  --text: #111827;\n  --muted: #64748b;\n  --line: #e2e8f0;\n  --brand: #6d5dfc;\n  --brand-2: #00b7a8;\n  --danger: #ef4444;\n  --warning: #f59e0b;\n  --success: #10b981;\n  --info: #0ea5e9;\n  --shadow-sm: 0 8px 24px rgba(15, 23, 42, 0.08);\n  --shadow: 0 18px 50px rgba(15, 23, 42, 0.12);\n  --radius: 18px;\n  --sidebar: 260px;\n  --topbar: 76px;\n  --font: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n}\n* { box-sizing: border-box; }\n[hidden] { display: none !important; }\nhtml, body { margin: 0; min-height: 100%; max-width: 100%; overflow-x: hidden; font-family: var(--font); color: var(--text); background: radial-gradient(circle at 10% 0%, rgba(109,93,252,.16), transparent 28%), radial-gradient(circle at 92% 8%, rgba(0,183,168,.14), transparent 26%), var(--bg); }\n.partner-screen {\n  position: fixed;\n  inset: 0;\n  z-index: 900;\n  display: grid;\n  place-items: center;\n  padding: 24px;\n  background: radial-gradient(circle at 10% 0%, rgba(109,93,252,.16), transparent 28%), radial-gradient(circle at 92% 8%, rgba(0,183,168,.14), transparent 26%), var(--bg);\n}\n.app-root {\n  height: 100vh;\n  min-height: 100vh;\n  min-width: 0;\n  width: 100%;\n  max-width: 100%;\n  display: grid;\n  grid-template-columns: var(--sidebar) minmax(0, 1fr);\n  grid-template-rows: var(--topbar) minmax(0, 1fr);\n  overflow: hidden;\n}\n.sidebar {\n  grid-row: 1 / span 2;\n  min-height: 0;\n  padding: 22px 18px;\n  background: linear-gradient(180deg, rgba(17,24,39,.98), rgba(15,23,42,.96));\n  color: #fff;\n  display: flex;\n  flex-direction: column;\n  overflow-x: hidden;\n  overflow-y: auto;\n}\n#partner-nav { flex: 1; min-height: 0; }\n.brand-block { display: flex; gap: 12px; align-items: center; margin-bottom: 22px; }\n.logo-mark { width: 42px; height: 42px; border-radius: 14px; display: grid; place-items: center; background: linear-gradient(135deg, var(--brand), var(--brand-2)); font-weight: 900; }\n.brand-name { font-weight: 800; font-size: 18px; }\n.brand-sub { color: rgba(255,255,255,.55); font-size: 12px; }\n.nav-section-title { margin: 16px 12px 8px; color: rgba(255,255,255,.42); font-size: 11px; letter-spacing: .12em; text-transform: uppercase; font-weight: 750; }\n.nav-item { display: flex; align-items: center; gap: 11px; height: 42px; padding: 0 12px; margin: 4px 0; border-radius: 13px; color: rgba(255,255,255,.72); text-decoration: none; font-size: 14px; font-weight: 650; cursor: pointer; border: 0; background: transparent; width: 100%; text-align: left; }\n.nav-item:hover, .nav-item.active { color: #fff; background: rgba(255,255,255,.10); box-shadow: inset 0 0 0 1px rgba(255,255,255,.10); }\n.nav-icon { width: 23px; height: 23px; border-radius: 8px; background: rgba(255,255,255,.10); display: grid; place-items: center; font-size: 13px; }\n.sidebar-card { margin-top: auto; padding: 14px; border-radius: 18px; background: rgba(255,255,255,.08); border: 1px solid rgba(255,255,255,.10); font-size: 12px; color: rgba(255,255,255,.58); }\n.partner-card { margin-top: 14px; padding: 12px; border-radius: 14px; border: 1px solid rgba(109,93,252,.35); background: rgba(109,93,252,.12); font-size: 12px; }\n.topbar {\n  grid-column: 2;\n  min-width: 0;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 16px;\n  padding: 0 28px;\n  border-bottom: 1px solid rgba(226,232,240,.86);\n  background: rgba(255,255,255,.68);\n  backdrop-filter: blur(18px);\n}\n.crumbs { color: var(--muted); font-size: 13px; display: flex; gap: 8px; align-items: center; min-width: 0; flex-shrink: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }\n.crumbs strong { color: var(--text); }\n.topbar-actions { display: flex; gap: 10px; align-items: center; min-width: 0; flex: 0 1 auto; flex-wrap: wrap; justify-content: flex-end; }\n.main {\n  grid-column: 2;\n  min-width: 0;\n  min-height: 0;\n  overflow-x: hidden;\n  overflow-y: auto;\n  padding: 28px;\n}\n.view { display: none; min-width: 0; max-width: 100%; }\n.view.active { display: block; }\n.kpi-grid { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 16px; margin-bottom: 18px; min-width: 0; }\n.kpi-card, .panel { background: rgba(255,255,255,.88); border: 1px solid rgba(226,232,240,.92); box-shadow: var(--shadow-sm); border-radius: var(--radius); }\n.kpi-card { padding: 18px; }\n.kpi-label { color: var(--muted); font-size: 12px; font-weight: 750; text-transform: uppercase; letter-spacing: .08em; }\n.kpi-value { margin-top: 12px; font-size: 30px; font-weight: 880; letter-spacing: -.04em; }\n.panel-header { padding: 18px 20px; border-bottom: 1px solid var(--line); display: flex; justify-content: space-between; align-items: center; }\n.panel-body { padding: 20px; }\n.table { width: 100%; border-collapse: collapse; table-layout: fixed; }\n.table th { text-align: left; padding: 12px 14px; font-size: 11px; text-transform: uppercase; color: var(--muted); background: var(--surface-2); border-bottom: 1px solid var(--line); overflow-wrap: anywhere; word-break: break-word; }\n.table td { padding: 14px; border-bottom: 1px solid var(--line); font-size: 13px; overflow-wrap: anywhere; word-break: break-word; }\n.btn { height: 40px; padding: 0 15px; border-radius: 13px; display: inline-flex; align-items: center; justify-content: center; gap: 8px; font-weight: 760; font-size: 13px; border: 1px solid var(--line); background: #fff; cursor: pointer; }\n.btn-primary { color: #fff; background: linear-gradient(135deg, var(--brand), #5043e6); border: 0; box-shadow: 0 12px 22px rgba(109,93,252,.22); }\n.btn-secondary { background: #fff; }\n.btn-warning { background: #fef3c7; color: #92400e; border-color: #fde68a; }\n.btn-danger { color: #fff; background: #dc2626; border: 0; box-shadow: 0 12px 22px rgba(220,38,38,.22); }\n.btn-danger:hover { transform: translateY(-1px); }\n.btn-success { color: #052e25; background: #a7f3d0; border-color: #86efac; }\n.btn-ghost { background: transparent; border-color: transparent; color: var(--muted); }\n.btn-primary:hover { transform: translateY(-1px); }\n.icon-btn {\n  width: 40px;\n  height: 40px;\n  border-radius: 13px;\n  background: #fff;\n  border: 1px solid var(--line);\n  display: grid;\n  place-items: center;\n  color: var(--muted);\n  cursor: pointer;\n  font: inherit;\n  font-size: 18px;\n  line-height: 1;\n}\n.badge { min-height: 24px; padding: 4px 9px; border-radius: 999px; font-size: 11px; font-weight: 820; display: inline-flex; align-items: center; border: 1px solid transparent; }\n.badge-success { background: #dcfce7; color: #166534; border-color: #bbf7d0; }\n.badge-warning { background: #fef3c7; color: #92400e; border-color: #fde68a; }\n.badge-neutral { background: #f1f5f9; color: #475569; border-color: #e2e8f0; }\n.badge-danger { background: #fee2e2; color: #991b1b; border-color: #fecaca; }\n.badge-info { background: #e0f2fe; color: #075985; border-color: #bae6fd; }\n.badge-purple { background: #ede9fe; color: #5b21b6; border-color: #ddd6fe; }\n.field { display: grid; gap: 7px; margin-bottom: 14px; }\n.field label { font-size: 12px; font-weight: 760; color: var(--muted); }\n.input, .select, .textarea { border: 1px solid var(--line); background: #fff; color: var(--text); border-radius: 13px; min-height: 42px; padding: 0 12px; width: 100%; font: inherit; }\n.textarea { min-height: 92px; padding: 12px; resize: vertical; }\n.login-card { width: 420px; max-width: calc(100vw - 32px); padding: 28px; border-radius: 24px; background: #fff; box-shadow: var(--shadow); border: 1px solid var(--line); }\n.login-card h1 { margin: 0 0 8px; font-size: 28px; letter-spacing: -.04em; }\n.login-card p { color: var(--muted); line-height: 1.5; }\n.login-message--apply-hint { color: var(--text) !important; font-weight: 500; }\n.btn-attention-pulse {\n  animation: btn-attention-pulse 0.45s ease-in-out 2;\n  border-color: var(--accent) !important;\n  box-shadow: 0 0 0 0 rgba(109, 40, 217, 0.45);\n}\n@keyframes btn-attention-pulse {\n  0%, 100% { transform: scale(1); box-shadow: 0 0 0 0 rgba(109, 40, 217, 0.35); }\n  50% { transform: scale(1.04); box-shadow: 0 0 0 10px rgba(109, 40, 217, 0); }\n}\n.login-waiting { text-align: center; }\n.login-waiting-spinner {\n  width: 48px;\n  height: 48px;\n  margin: 0 auto 20px;\n  border-radius: 50%;\n  border: 3px solid var(--line);\n  border-top-color: var(--brand);\n  animation: login-wait-spin 0.9s linear infinite;\n}\n@keyframes login-wait-spin {\n  to { transform: rotate(360deg); }\n}\n.login-waiting-lead { margin: 0 0 10px; }\n.login-waiting-lead strong { color: var(--text); font-weight: 700; }\n.login-waiting-timer {\n  margin-top: 22px;\n  padding: 14px 18px;\n  border-radius: 16px;\n  background: var(--surface-2);\n  border: 1px solid var(--line);\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n  align-items: center;\n}\n.login-waiting-timer-label {\n  font-size: 12px;\n  color: var(--muted);\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  font-weight: 650;\n}\n.login-waiting-timer-value {\n  font-size: 28px;\n  font-weight: 800;\n  letter-spacing: 0.06em;\n  font-variant-numeric: tabular-nums;\n  color: var(--text);\n}\n.modal-backdrop { position: fixed; inset: 0; background: rgba(15,23,42,.54); backdrop-filter: blur(8px); display: none; place-items: center; z-index: 1000; }\n.modal-backdrop.show { display: grid; }\n.modal { width: 640px; max-width: calc(100vw - 32px); border-radius: 24px; background: #fff; box-shadow: 0 30px 90px rgba(0,0,0,.28); overflow: hidden; }\n.modal-head, .modal-foot { padding: 16px 22px; border-bottom: 1px solid var(--line); display: flex; justify-content: space-between; align-items: center; }\n.modal-foot { border-bottom: 0; border-top: 1px solid var(--line); background: var(--surface-2); justify-content: flex-end; gap: 10px; }\n.modal-body { padding: 22px; max-height: 70vh; overflow: auto; }\n.confirm-modal-message { margin: 0; color: var(--text); font-size: 14px; line-height: 1.6; }\n.modal.confirm-modal .modal-body { padding-top: 18px; padding-bottom: 18px; }\n.toast { position: fixed; right: 26px; bottom: 26px; z-index: 1100; min-width: 280px; padding: 14px 16px; border-radius: 16px; background: #111827; color: #fff; box-shadow: var(--shadow); opacity: 0; transform: translateY(10px); pointer-events: none; transition: .22s ease; }\n.toast.show { opacity: 1; transform: translateY(0); }\n.toast span { color: rgba(255,255,255,.68); font-size: 12px; display: block; margin-top: 4px; }\n.kanban-board { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 16px; min-width: 0; }\n.kanban-col { background: rgba(255,255,255,.72); border: 1px solid var(--line); border-radius: 20px; padding: 12px; min-height: 320px; }\n.order-card { background: #fff; border: 1px solid var(--line); border-radius: 16px; padding: 14px; margin-bottom: 12px; box-shadow: var(--shadow-sm); font-size: 12px; }\n.stage-title { margin: 0; font-size: 30px; letter-spacing: -.05em; }\n.stage-desc { color: var(--muted); margin-top: 8px; line-height: 1.5; }\n.empty { color: var(--muted); padding: 24px; text-align: center; }\n.split-row { display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, 1fr); gap: 14px; }\n.panel, .kpi-card { min-width: 0; max-width: 100%; }\n.layout-stage { min-width: 0; max-width: 100%; }\nbody:has(.app-root:not([hidden])) { overflow: hidden; }\n.app-root--full { grid-template-columns: minmax(0, 1fr); }\n.app-root--full .topbar,\n.app-root--full .main { grid-column: 1; }\n.cert-hero { padding: 24px; border-radius: 24px; background: linear-gradient(135deg, #111827, #312e81 52%, #0f766e); color: #fff; margin-bottom: 18px; }\n.code-panel { background: #0f172a; color: #dbeafe; border-radius: 20px; padding: 20px; font-family: ui-monospace, monospace; font-size: 13px; overflow: auto; }\n\n/* Partner application — Typeform-style wizard (partner.eazpire.com only) */\n.partner-screen:has(.apply-wizard:not([hidden])) {\n  display: block;\n  padding: 0;\n  background: #faf9f7;\n}\n.apply-wizard.partner-typeform {\n  position: fixed;\n  inset: 0;\n  z-index: 950;\n  display: flex;\n  flex-direction: column;\n  background: #faf9f7;\n  color: var(--text);\n  overflow: hidden;\n}\n.apply-wizard-top {\n  flex-shrink: 0;\n  padding: 20px 24px 0;\n  max-width: 720px;\n  width: 100%;\n  margin: 0 auto;\n  box-sizing: border-box;\n}\n.apply-wizard-progress-track {\n  height: 4px;\n  background: #e8e6e3;\n  border-radius: 999px;\n  overflow: hidden;\n}\n.apply-wizard-progress-fill {\n  height: 100%;\n  width: 14.28%;\n  background: linear-gradient(90deg, #f97316, #fb923c);\n  border-radius: 999px;\n  transition: width 0.35s cubic-bezier(0.4, 0, 0.2, 1);\n}\n.apply-wizard-progress-label {\n  margin-top: 10px;\n  font-size: 13px;\n  font-weight: 600;\n  color: var(--muted);\n  letter-spacing: 0.02em;\n}\n.apply-wizard-form {\n  flex: 1;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  max-width: 720px;\n  width: 100%;\n  margin: 0 auto;\n  padding: 32px 24px;\n  box-sizing: border-box;\n  overflow: auto;\n}\n.apply-step {\n  animation: apply-step-in 0.38s cubic-bezier(0.4, 0, 0.2, 1) both;\n}\n.apply-step[hidden] { display: none !important; }\n@keyframes apply-step-in {\n  from { opacity: 0; transform: translateY(16px); }\n  to { opacity: 1; transform: translateY(0); }\n}\n.apply-step-badge {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  min-width: 32px;\n  height: 32px;\n  padding: 0 10px;\n  border-radius: 8px;\n  background: linear-gradient(135deg, #f97316, #ea580c);\n  color: #fff;\n  font-size: 14px;\n  font-weight: 800;\n  margin-bottom: 20px;\n}\n.apply-question {\n  margin: 0;\n  font-size: clamp(26px, 5vw, 36px);\n  font-weight: 700;\n  letter-spacing: -0.03em;\n  line-height: 1.2;\n}\n.apply-hint {\n  margin: 12px 0 28px;\n  color: var(--muted);\n  font-size: 16px;\n  line-height: 1.5;\n  max-width: 540px;\n}\n.apply-input,\n.apply-textarea {\n  display: block;\n  width: 100%;\n  max-width: 560px;\n  border: 0;\n  border-bottom: 2px solid #d1d5db;\n  border-radius: 0;\n  background: transparent;\n  font: inherit;\n  font-size: 22px;\n  padding: 10px 0 12px;\n  color: var(--text);\n  outline: none;\n  transition: border-color 0.2s ease, box-shadow 0.2s ease;\n}\n.apply-input:focus,\n.apply-textarea:focus {\n  border-bottom-color: #f97316;\n  box-shadow: 0 2px 0 -1px rgba(249, 115, 22, 0.35);\n}\n.apply-input::placeholder,\n.apply-textarea::placeholder { color: #9ca3af; font-size: 18px; }\n.apply-textarea {\n  font-size: 18px;\n  min-height: 100px;\n  resize: vertical;\n  margin-top: 8px;\n  border: 0;\n  border-bottom: 2px solid #d1d5db;\n}\n.apply-error {\n  margin: 14px 0 0;\n  color: var(--danger);\n  font-size: 14px;\n  font-weight: 600;\n}\n.apply-review {\n  margin: 0 0 24px;\n  display: grid;\n  grid-template-columns: auto 1fr;\n  gap: 10px 20px;\n  font-size: 15px;\n  max-width: 560px;\n}\n.apply-review dt {\n  color: var(--muted);\n  font-weight: 600;\n}\n.apply-review dd {\n  margin: 0;\n  font-weight: 650;\n  word-break: break-word;\n}\n.apply-review-label {\n  display: block;\n  font-size: 13px;\n  font-weight: 700;\n  color: var(--muted);\n  margin-bottom: 6px;\n}\n.apply-wizard-actions {\n  flex-shrink: 0;\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  max-width: 720px;\n  width: 100%;\n  margin: 0 auto;\n  padding: 0 24px 16px;\n  box-sizing: border-box;\n}\n.apply-btn-back {\n  height: 48px;\n  padding: 0 18px;\n  border: 0;\n  background: transparent;\n  color: var(--muted);\n  font: inherit;\n  font-size: 15px;\n  font-weight: 650;\n  cursor: pointer;\n  border-radius: 12px;\n}\n.apply-btn-back:hover { color: var(--text); background: rgba(0,0,0,.04); }\n.apply-btn-next {\n  height: 48px;\n  padding: 0 28px;\n  border: 0;\n  border-radius: 12px;\n  background: linear-gradient(135deg, #f97316, #ea580c);\n  color: #fff;\n  font: inherit;\n  font-size: 15px;\n  font-weight: 750;\n  cursor: pointer;\n  box-shadow: 0 8px 20px rgba(249, 115, 22, 0.28);\n  transition: transform 0.15s ease, box-shadow 0.15s ease;\n}\n.apply-btn-next:hover {\n  transform: translateY(-1px);\n  box-shadow: 0 12px 24px rgba(249, 115, 22, 0.32);\n}\n.apply-btn-next:disabled {\n  opacity: 0.55;\n  cursor: not-allowed;\n  transform: none;\n}\n.apply-btn-submit { margin-left: auto; }\n.apply-back-login {\n  flex-shrink: 0;\n  display: block;\n  margin: 0 auto 28px;\n  padding: 8px 16px;\n  border: 0;\n  background: transparent;\n  color: var(--muted);\n  font: inherit;\n  font-size: 14px;\n  font-weight: 600;\n  cursor: pointer;\n}\n.apply-back-login:hover { color: var(--text); }\n.apply-success {\n  flex: 1;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  max-width: 720px;\n  width: 100%;\n  margin: 0 auto;\n  padding: 32px 24px;\n  animation: apply-step-in 0.45s ease both;\n}\n.apply-success-icon {\n  width: 56px;\n  height: 56px;\n  border-radius: 50%;\n  background: #dcfce7;\n  color: #166534;\n  display: grid;\n  place-items: center;\n  font-size: 28px;\n  font-weight: 800;\n  margin-bottom: 20px;\n}\n@media (max-width: 600px) {\n  .apply-wizard-form { padding: 24px 20px; justify-content: flex-start; padding-top: 48px; }\n  .apply-question { font-size: 24px; }\n  .apply-input { font-size: 18px; }\n  .apply-wizard-actions { padding: 0 20px 12px; }\n  .apply-btn-next { flex: 1; }\n}\n\n/* ===== Admin partner portal (admin.eazpire.com/partner) ===== */\nhtml[data-portal=\"admin\"] .sidebar {\n  position: relative;\n}\nhtml[data-portal=\"admin\"] #topbar-extra {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  flex-shrink: 0;\n}\nhtml[data-portal=\"admin\"] .topbar-actions .btn {\n  flex-shrink: 0;\n  white-space: nowrap;\n}\nhtml[data-portal=\"admin\"] .sidebar::before {\n  content: \"\";\n  position: absolute;\n  inset: -40px -80px auto auto;\n  width: 240px;\n  height: 240px;\n  border-radius: 50%;\n  background: radial-gradient(circle, rgba(109,93,252,.45), transparent 66%);\n  pointer-events: none;\n}\nhtml[data-portal=\"admin\"] .brand-block {\n  position: relative;\n  z-index: 1;\n}\nhtml[data-portal=\"admin\"] .sidebar-card {\n  position: relative;\n  z-index: 1;\n}\nhtml[data-portal=\"admin\"] .sidebar-card h4 {\n  margin: 0 0 8px;\n  font-size: 14px;\n  color: #fff;\n}\nhtml[data-portal=\"admin\"] .sidebar-card p {\n  margin: 0;\n  line-height: 1.4;\n}\nhtml[data-portal=\"admin\"] #partner-nav {\n  position: relative;\n  z-index: 1;\n  flex: 1;\n}\nhtml[data-portal=\"admin\"] .search-box {\n  width: auto;\n  min-width: 0;\n  flex: 1 1 140px;\n  max-width: 320px;\n  height: 42px;\n  border: 1px solid var(--line);\n  background: rgba(255,255,255,.82);\n  border-radius: 14px;\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 0 14px;\n  color: var(--muted);\n}\nhtml[data-portal=\"admin\"] .search-box input {\n  border: 0;\n  outline: 0;\n  background: transparent;\n  width: 100%;\n  color: var(--text);\n  font: inherit;\n  font-size: 13px;\n}\nhtml[data-portal=\"admin\"] .layout-stage {\n  animation: adminStageIn .32s ease both;\n  min-width: 0;\n  max-width: 100%;\n}\n@keyframes adminStageIn {\n  from { opacity: 0; transform: translateY(12px); }\n  to { opacity: 1; transform: translateY(0); }\n}\nhtml[data-portal=\"admin\"] .stage-heading {\n  display: flex;\n  align-items: flex-end;\n  justify-content: space-between;\n  gap: 20px;\n  margin-bottom: 20px;\n}\nhtml[data-portal=\"admin\"] .stage-kicker {\n  color: var(--brand);\n  font-size: 12px;\n  font-weight: 850;\n  letter-spacing: .12em;\n  text-transform: uppercase;\n}\nhtml[data-portal=\"admin\"] .stage-title {\n  margin: 6px 0 0;\n  font-size: 34px;\n  letter-spacing: -.05em;\n}\nhtml[data-portal=\"admin\"] .stage-desc {\n  margin: 8px 0 0;\n  max-width: 820px;\n}\nhtml[data-portal=\"admin\"] .kpi-trend {\n  margin-top: 9px;\n  display: inline-flex;\n  gap: 6px;\n  align-items: center;\n  font-size: 12px;\n  font-weight: 760;\n  color: var(--success);\n}\nhtml[data-portal=\"admin\"] .kpi-trend.is-warning { color: var(--warning); }\nhtml[data-portal=\"admin\"] .panel-title {\n  margin: 0;\n  font-size: 16px;\n  letter-spacing: -.02em;\n}\nhtml[data-portal=\"admin\"] .panel-subtitle {\n  margin: 4px 0 0;\n  color: var(--muted);\n  font-size: 12px;\n}\nhtml[data-portal=\"admin\"] .table {\n  border-collapse: separate;\n  border-spacing: 0;\n}\nhtml[data-portal=\"admin\"] .table tr:last-child td { border-bottom: 0; }\nhtml[data-portal=\"admin\"] .entity {\n  display: flex;\n  align-items: center;\n  gap: 11px;\n}\nhtml[data-portal=\"admin\"] .avatar {\n  width: 38px;\n  height: 38px;\n  border-radius: 13px;\n  display: grid;\n  place-items: center;\n  font-weight: 850;\n  color: #fff;\n  background: linear-gradient(135deg, var(--brand), var(--brand-2));\n  flex-shrink: 0;\n  font-size: 12px;\n}\nhtml[data-portal=\"admin\"] .entity strong { display: block; font-size: 13px; }\nhtml[data-portal=\"admin\"] .entity span { display: block; margin-top: 2px; color: var(--muted); font-size: 12px; }\nhtml[data-portal=\"admin\"] .pill-tabs {\n  display: flex;\n  gap: 8px;\n  padding: 6px;\n  border-radius: 999px;\n  background: var(--surface-3);\n}\nhtml[data-portal=\"admin\"] .pill-tab {\n  padding: 8px 12px;\n  border-radius: 999px;\n  background: transparent;\n  color: var(--muted);\n  font-size: 12px;\n  font-weight: 780;\n  border: 0;\n  cursor: pointer;\n  font: inherit;\n}\nhtml[data-portal=\"admin\"] .pill-tab.active {\n  background: #fff;\n  color: var(--text);\n  box-shadow: var(--shadow-sm);\n}\nhtml[data-portal=\"admin\"] .pill-tab-count {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  min-width: 18px;\n  height: 18px;\n  margin-left: 6px;\n  padding: 0 5px;\n  border-radius: 999px;\n  background: rgba(15, 23, 42, 0.08);\n  font-size: 10px;\n  font-weight: 800;\n}\nhtml[data-portal=\"admin\"] .prior-history-list {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 6px;\n  margin-top: 8px;\n}\nhtml[data-portal=\"admin\"] .prior-history-chip {\n  border: 1px solid rgba(245, 158, 11, 0.35);\n  background: rgba(245, 158, 11, 0.12);\n  color: #92400e;\n  border-radius: 999px;\n  padding: 4px 10px;\n  font-size: 11px;\n  font-weight: 700;\n  cursor: pointer;\n  font: inherit;\n}\nhtml[data-portal=\"admin\"] .action-mode-options {\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n  margin-top: 16px;\n}\nhtml[data-portal=\"admin\"] .action-mode-option {\n  display: flex;\n  gap: 10px;\n  align-items: flex-start;\n  cursor: pointer;\n}\nhtml[data-portal=\"admin\"] .action-mode-option input {\n  margin-top: 4px;\n}\nhtml[data-portal=\"admin\"] .info-reason-box {\n  padding: 12px 14px;\n  border-radius: 12px;\n  background: var(--surface-3);\n  color: var(--text);\n  font-size: 13px;\n  line-height: 1.5;\n  white-space: pre-wrap;\n}\nhtml[data-portal=\"admin\"] .command-time-hint {\n  margin: -6px 0 16px;\n  font-size: 12px;\n  color: var(--muted);\n}\nhtml[data-portal=\"admin\"] .command-layout .content-grid {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr);\n  gap: 18px;\n}\nhtml[data-portal=\"admin\"] .map-panel {\n  min-height: 320px;\n  position: relative;\n  overflow: hidden;\n  background:\n    radial-gradient(circle at 20% 20%, rgba(109,93,252,.20), transparent 22%),\n    radial-gradient(circle at 78% 26%, rgba(0,183,168,.18), transparent 24%),\n    linear-gradient(135deg, #fff, #f8fafc);\n}\nhtml[data-portal=\"admin\"] .map-grid {\n  position: absolute;\n  inset: 0;\n  background-image: linear-gradient(rgba(148,163,184,.14) 1px, transparent 1px), linear-gradient(90deg, rgba(148,163,184,.14) 1px, transparent 1px);\n  background-size: 42px 42px;\n  mask-image: radial-gradient(circle at center, black, transparent 78%);\n}\nhtml[data-portal=\"admin\"] .node {\n  position: absolute;\n  width: 150px;\n  padding: 12px;\n  border-radius: 16px;\n  background: rgba(255,255,255,.84);\n  border: 1px solid rgba(226,232,240,.95);\n  box-shadow: var(--shadow-sm);\n}\nhtml[data-portal=\"admin\"] .node h4 { margin: 0 0 4px; font-size: 13px; }\nhtml[data-portal=\"admin\"] .node p { margin: 0; color: var(--muted); font-size: 11px; }\nhtml[data-portal=\"admin\"] .node.a { left: 48px; top: 52px; }\nhtml[data-portal=\"admin\"] .node.b { right: 54px; top: 70px; }\nhtml[data-portal=\"admin\"] .node.c { left: 300px; bottom: 56px; }\nhtml[data-portal=\"admin\"] .node.d { right: 180px; bottom: 86px; }\nhtml[data-portal=\"admin\"] .timeline { display: grid; gap: 14px; }\nhtml[data-portal=\"admin\"] .timeline-item { display: grid; grid-template-columns: 34px 1fr; gap: 12px; }\nhtml[data-portal=\"admin\"] .dot {\n  width: 34px;\n  height: 34px;\n  border-radius: 13px;\n  display: grid;\n  place-items: center;\n  background: #ede9fe;\n  color: var(--brand);\n  font-weight: 850;\n  font-size: 12px;\n}\nhtml[data-portal=\"admin\"] .timeline-content {\n  padding-bottom: 12px;\n  border-bottom: 1px dashed var(--line);\n}\nhtml[data-portal=\"admin\"] .timeline-content strong { font-size: 13px; }\nhtml[data-portal=\"admin\"] .timeline-content p {\n  margin: 4px 0 0;\n  color: var(--muted);\n  font-size: 12px;\n  line-height: 1.45;\n}\nhtml[data-portal=\"admin\"] .studio-shell {\n  display: grid;\n  grid-template-columns: minmax(0, 360px) minmax(0, 1fr);\n  gap: 18px;\n}\nhtml[data-portal=\"admin\"] .filter-list { display: grid; gap: 10px; }\nhtml[data-portal=\"admin\"] .filter-item {\n  padding: 14px;\n  border-radius: 15px;\n  background: #fff;\n  border: 1px solid var(--line);\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\nhtml[data-portal=\"admin\"] .filter-item strong { font-size: 13px; }\nhtml[data-portal=\"admin\"] .filter-item span { color: var(--muted); font-size: 12px; }\nhtml[data-portal=\"admin\"] .catalog-toolbar {\n  display: flex;\n  justify-content: space-between;\n  gap: 16px;\n  margin-bottom: 16px;\n  flex-wrap: wrap;\n}\nhtml[data-portal=\"admin\"] .card-grid {\n  display: grid;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n  gap: 16px;\n}\nhtml[data-portal=\"admin\"] .catalog-grid { grid-template-columns: repeat(4, minmax(0, 1fr)); }\nhtml[data-portal=\"admin\"] .product-card {\n  overflow: hidden;\n  border-radius: 18px;\n  background: #fff;\n  border: 1px solid var(--line);\n  box-shadow: var(--shadow-sm);\n}\nhtml[data-portal=\"admin\"] .product-image {\n  height: 150px;\n  background:\n    linear-gradient(135deg, rgba(109,93,252,.20), rgba(0,183,168,.18)),\n    repeating-linear-gradient(45deg, rgba(15,23,42,.04) 0 10px, transparent 10px 20px);\n  display: grid;\n  place-items: center;\n  font-size: 42px;\n}\nhtml[data-portal=\"admin\"] .product-card-content { padding: 15px; }\nhtml[data-portal=\"admin\"] .product-card h3 { margin: 0; font-size: 15px; letter-spacing: -.02em; }\nhtml[data-portal=\"admin\"] .product-card p { color: var(--muted); margin: 7px 0 13px; font-size: 12px; line-height: 1.45; }\nhtml[data-portal=\"admin\"] .meta-row { display: flex; align-items: center; justify-content: space-between; gap: 10px; }\nhtml[data-portal=\"admin\"] .money { font-weight: 850; letter-spacing: -.02em; }\nhtml[data-portal=\"admin\"] .kanban-head {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 6px 4px 14px;\n}\nhtml[data-portal=\"admin\"] .kanban-head h3 { margin: 0; font-size: 14px; text-transform: capitalize; }\nhtml[data-portal=\"admin\"] .kanban-col { min-height: 560px; }\nhtml[data-portal=\"admin\"] .order-card h4 { margin: 0; font-size: 14px; }\nhtml[data-portal=\"admin\"] .order-card p { margin: 7px 0 12px; color: var(--muted); line-height: 1.45; }\nhtml[data-portal=\"admin\"] .order-meta {\n  display: flex;\n  justify-content: space-between;\n  color: var(--muted);\n  font-size: 11px;\n  font-weight: 720;\n}\nhtml[data-portal=\"admin\"] .api-layout {\n  display: grid;\n  grid-template-columns: minmax(0, 320px) minmax(0, 1fr);\n  gap: 18px;\n}\nhtml[data-portal=\"admin\"] .code-panel {\n  padding: 0;\n  overflow: hidden;\n}\nhtml[data-portal=\"admin\"] .code-tabs {\n  display: flex;\n  gap: 2px;\n  padding: 10px;\n  border-bottom: 1px solid rgba(255,255,255,.08);\n}\nhtml[data-portal=\"admin\"] .code-tab {\n  padding: 9px 12px;\n  border-radius: 10px;\n  background: rgba(255,255,255,.06);\n  color: rgba(255,255,255,.72);\n  font-size: 12px;\n  font-weight: 770;\n}\nhtml[data-portal=\"admin\"] .code-panel pre {\n  margin: 0;\n  padding: 22px;\n  overflow: auto;\n  line-height: 1.55;\n  font-size: 13px;\n}\nhtml[data-portal=\"admin\"] .doc-list { display: grid; gap: 10px; }\nhtml[data-portal=\"admin\"] .doc-item {\n  padding: 14px;\n  border-radius: 16px;\n  background: #fff;\n  border: 1px solid var(--line);\n}\nhtml[data-portal=\"admin\"] .doc-item strong { display: block; font-size: 13px; }\nhtml[data-portal=\"admin\"] .doc-item span { color: var(--muted); display: block; font-size: 12px; margin-top: 4px; }\nhtml[data-portal=\"admin\"] .component-zone {\n  display: grid;\n  grid-template-columns: minmax(0, 1.1fr) minmax(0, 0.9fr);\n  gap: 18px;\n  align-items: start;\n}\nhtml[data-portal=\"admin\"] .cert-layout {\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) minmax(0, 420px);\n  gap: 18px;\n}\nhtml[data-portal=\"admin\"] .cert-hero {\n  min-height: 310px;\n  padding: 28px;\n  position: relative;\n  overflow: hidden;\n  margin-bottom: 0;\n}\nhtml[data-portal=\"admin\"] .cert-hero::after {\n  content: \"\";\n  position: absolute;\n  right: -90px;\n  top: -90px;\n  width: 300px;\n  height: 300px;\n  border-radius: 50%;\n  background: radial-gradient(circle, rgba(255,255,255,.24), transparent 68%);\n  pointer-events: none;\n}\nhtml[data-portal=\"admin\"] .cert-hero h2 {\n  margin: 0;\n  font-size: 38px;\n  letter-spacing: -.06em;\n  max-width: 640px;\n  position: relative;\n  z-index: 1;\n}\nhtml[data-portal=\"admin\"] .cert-hero p {\n  color: rgba(255,255,255,.70);\n  max-width: 660px;\n  line-height: 1.55;\n  position: relative;\n  z-index: 1;\n}\nhtml[data-portal=\"admin\"] .cert-badges {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px;\n  margin-top: 28px;\n  position: relative;\n  z-index: 1;\n}\nhtml[data-portal=\"admin\"] .cert-badge {\n  background: rgba(255,255,255,.12);\n  border: 1px solid rgba(255,255,255,.18);\n  color: #fff;\n  border-radius: 999px;\n  padding: 9px 12px;\n  font-size: 12px;\n  font-weight: 780;\n}\nhtml[data-portal=\"admin\"] .score-ring {\n  width: 180px;\n  height: 180px;\n  border-radius: 50%;\n  margin: 18px auto;\n  background: conic-gradient(var(--success) 0 91%, #e2e8f0 91% 100%);\n  display: grid;\n  place-items: center;\n  position: relative;\n}\nhtml[data-portal=\"admin\"] .score-ring::before {\n  content: \"\";\n  position: absolute;\n  inset: 14px;\n  border-radius: 50%;\n  background: #fff;\n}\nhtml[data-portal=\"admin\"] .score-ring strong {\n  position: relative;\n  font-size: 38px;\n  letter-spacing: -.05em;\n}\nhtml[data-portal=\"admin\"] .checklist { display: grid; gap: 10px; }\nhtml[data-portal=\"admin\"] .check-item {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 12px;\n  padding: 12px 14px;\n  border-radius: 14px;\n  background: #fff;\n  border: 1px solid var(--line);\n}\nhtml[data-portal=\"admin\"] .check-item strong { font-size: 13px; }\nhtml[data-portal=\"admin\"] .empty-state {\n  border: 1px dashed #cbd5e1;\n  border-radius: 18px;\n  padding: 24px;\n  text-align: center;\n  background: rgba(248,250,252,.7);\n}\nhtml[data-portal=\"admin\"] .empty-state .icon { font-size: 34px; margin-bottom: 8px; }\nhtml[data-portal=\"admin\"] .empty-state h3 { margin: 0; }\nhtml[data-portal=\"admin\"] .empty-state p {\n  color: var(--muted);\n  margin: 8px auto 16px;\n  max-width: 460px;\n  line-height: 1.45;\n}\nhtml[data-portal=\"admin\"] .admin-login-card .login-brand {\n  margin-bottom: 20px;\n}\nhtml[data-portal=\"admin\"] .admin-login-card .login-brand .logo-mark {\n  box-shadow: 0 14px 28px rgba(109, 93, 252, 0.36);\n}\nhtml[data-portal=\"admin\"] .login-message {\n  margin-top: 16px;\n  color: var(--muted);\n  line-height: 1.5;\n  font-size: 14px;\n}\nhtml[data-portal=\"admin\"] .modal-backdrop {\n  display: grid;\n  opacity: 0;\n  visibility: hidden;\n  transition: .22s ease;\n}\nhtml[data-portal=\"admin\"] .modal-backdrop.show {\n  opacity: 1;\n  visibility: visible;\n}\nhtml[data-portal=\"admin\"] .modal {\n  transform: translateY(14px) scale(.98);\n  transition: .22s ease;\n}\nhtml[data-portal=\"admin\"] .modal-backdrop.show .modal {\n  transform: translateY(0) scale(1);\n}\nhtml[data-portal=\"admin\"] .modal-head h3 {\n  margin: 0;\n  letter-spacing: -.03em;\n  font-size: 18px;\n}\nhtml[data-portal=\"admin\"] .confirm-modal-message {\n  font-size: 15px;\n}\nhtml[data-portal=\"admin\"] body.theme-studio { --brand: #0ea5e9; --brand-2: #22c55e; --bg: #f3f8fb; }\nhtml[data-portal=\"admin\"] body.theme-ops { --brand: #f97316; --brand-2: #ef4444; --bg: #fbf6f2; }\nhtml[data-portal=\"admin\"] body.theme-api { --brand: #7c3aed; --brand-2: #06b6d4; --bg: #f7f4ff; }\nhtml[data-portal=\"admin\"] body.theme-cert { --brand: #059669; --brand-2: #6366f1; --bg: #f4fbf8; }\n\n@media (max-width: 900px) {\n  .kpi-grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }\n  .split-row { grid-template-columns: minmax(0, 1fr); }\n}\n@media (max-width: 520px) {\n  .kpi-grid { grid-template-columns: minmax(0, 1fr); }\n}\n\n/* ===== Mobile shell — drawer sidebar, compact topbar (≤768px) ===== */\n.sidebar-backdrop,\n.sidebar-toggle,\n.search-toggle { display: none; }\n\n.topbar-start {\n  min-width: 0;\n  flex: 1 1 auto;\n  overflow: hidden;\n}\n\n@media (max-width: 768px) {\n  :root { --topbar: 60px; }\n\n  .sidebar-backdrop {\n    display: block;\n    position: fixed;\n    inset: 0;\n    z-index: 750;\n    background: rgba(15, 23, 42, 0.48);\n    backdrop-filter: blur(4px);\n    opacity: 0;\n    visibility: hidden;\n    pointer-events: none;\n    transition: opacity 0.28s ease, visibility 0.28s ease;\n  }\n\n  .app-root.sidebar-open .sidebar-backdrop {\n    opacity: 1;\n    visibility: visible;\n    pointer-events: auto;\n  }\n\n  .sidebar-toggle {\n    display: grid;\n    flex-shrink: 0;\n    width: 44px;\n    height: 44px;\n    min-width: 44px;\n    min-height: 44px;\n  }\n\n  .app-root:not(.app-root--full) {\n    grid-template-columns: minmax(0, 1fr);\n    grid-template-rows: auto minmax(0, 1fr);\n  }\n\n  .app-root:not(.app-root--full) .sidebar {\n    position: fixed;\n    top: 0;\n    left: 0;\n    bottom: 0;\n    width: min(280px, 86vw);\n    z-index: 800;\n    grid-row: unset;\n    transform: translateX(-100%);\n    transition: transform 0.28s cubic-bezier(0.4, 0, 0.2, 1);\n    box-shadow: none;\n  }\n\n  .app-root.sidebar-open .sidebar {\n    transform: translateX(0);\n    box-shadow: 12px 0 48px rgba(0, 0, 0, 0.28);\n  }\n\n  html[data-portal=\"admin\"] .sidebar {\n    position: fixed;\n  }\n\n  .topbar {\n    grid-column: 1;\n    padding: 0 12px 0 8px;\n    gap: 8px;\n    min-height: var(--topbar);\n    flex-wrap: nowrap;\n  }\n\n  .main {\n    grid-column: 1;\n    padding: 16px;\n  }\n\n  .crumbs .crumbs-host,\n  .crumbs .crumbs-sep { display: none; }\n\n  .topbar-actions {\n    flex-shrink: 0;\n    flex-wrap: nowrap;\n    gap: 6px;\n    position: relative;\n  }\n\n  .search-toggle {\n    display: grid;\n    width: 44px;\n    height: 44px;\n    min-width: 44px;\n    min-height: 44px;\n    flex-shrink: 0;\n  }\n\n  .topbar-actions .search-box {\n    display: none;\n    position: absolute;\n    top: calc(100% + 4px);\n    left: -8px;\n    right: -12px;\n    width: auto;\n    max-width: none;\n    flex: none;\n    height: 44px;\n    z-index: 20;\n    box-shadow: var(--shadow-sm);\n  }\n\n  .topbar-actions.search-expanded .search-box {\n    display: flex;\n  }\n\n  html[data-portal=\"admin\"] #topbar-extra .btn:not(.btn-primary) {\n    display: none;\n  }\n\n  html[data-portal=\"admin\"] #topbar-extra .btn-primary {\n    height: 44px;\n    padding: 0 12px;\n    font-size: 12px;\n  }\n\n  #btn-logout {\n    min-height: 44px;\n    height: 44px;\n    padding: 0 12px;\n    font-size: 12px;\n    flex-shrink: 0;\n  }\n\n  .btn,\n  .nav-item,\n  .icon-btn {\n    min-height: 44px;\n  }\n\n  .nav-item { height: 44px; }\n\n  body.drawer-open .app-root:not(.app-root--full) .main {\n    overflow: hidden;\n  }\n\n  .kpi-grid,\n  html[data-portal=\"admin\"] .kpi-grid,\n  html[data-portal=\"admin\"] .catalog-grid,\n  html[data-portal=\"admin\"] .card-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n    gap: 12px;\n  }\n\n  .kanban-board {\n    display: flex;\n    flex-wrap: nowrap;\n    gap: 12px;\n    overflow-x: auto;\n    overflow-y: hidden;\n    -webkit-overflow-scrolling: touch;\n    scroll-snap-type: x proximity;\n    padding-bottom: 10px;\n    margin-bottom: 4px;\n    grid-template-columns: unset;\n  }\n\n  .kanban-col {\n    flex: 0 0 min(280px, 82vw);\n    scroll-snap-align: start;\n    min-height: 360px;\n  }\n\n  html[data-portal=\"admin\"] .kanban-col {\n    min-height: 420px;\n  }\n\n  .table-scroll {\n    overflow-x: auto;\n    -webkit-overflow-scrolling: touch;\n    margin: 0 -4px;\n    padding: 0 4px;\n  }\n\n  .table-scroll .table {\n    min-width: 520px;\n  }\n\n  .modal-backdrop.show {\n    align-items: flex-end;\n    padding: 0;\n  }\n\n  .modal {\n    width: 100%;\n    max-width: 100%;\n    max-height: calc(100vh - 24px);\n    border-radius: 20px 20px 0 0;\n    display: flex;\n    flex-direction: column;\n  }\n\n  .modal-body {\n    max-height: none;\n    flex: 1 1 auto;\n    overflow: auto;\n  }\n\n  html[data-portal=\"admin\"] .stage-heading {\n    flex-direction: column;\n    align-items: flex-start;\n    gap: 12px;\n  }\n\n  html[data-portal=\"admin\"] .stage-title {\n    font-size: 26px;\n  }\n\n  html[data-portal=\"admin\"] .panel-header {\n    flex-direction: column;\n    align-items: flex-start;\n    gap: 10px;\n  }\n\n  html[data-portal=\"admin\"] .catalog-toolbar {\n    flex-direction: column;\n    align-items: stretch;\n  }\n\n  html[data-portal=\"admin\"] .pill-tabs {\n    flex-wrap: wrap;\n    border-radius: 16px;\n  }\n\n  .toast {\n    left: 16px;\n    right: 16px;\n    bottom: 16px;\n    min-width: auto;\n  }\n\n  .login-card {\n    padding: 22px 20px;\n  }\n\n  .partner-screen {\n    padding: 16px;\n  }\n\n  .app-root--full .topbar {\n    grid-column: 1;\n    padding: 0 16px;\n  }\n\n  .app-root--full .main {\n    padding: 16px;\n  }\n}\n\n@media (max-width: 480px) {\n  .kpi-grid,\n  html[data-portal=\"admin\"] .kpi-grid,\n  html[data-portal=\"admin\"] .catalog-grid,\n  html[data-portal=\"admin\"] .card-grid {\n    grid-template-columns: minmax(0, 1fr);\n  }\n}\n\n@media (min-width: 1100px) {\n  html[data-portal=\"admin\"] .command-layout .content-grid {\n    grid-template-columns: minmax(0, 1.35fr) minmax(0, 390px);\n  }\n}\n@media (max-width: 900px) {\n  html[data-portal=\"admin\"] .studio-shell,\n  html[data-portal=\"admin\"] .api-layout,\n  html[data-portal=\"admin\"] .cert-layout,\n  html[data-portal=\"admin\"] .component-zone {\n    grid-template-columns: minmax(0, 1fr);\n  }\n  html[data-portal=\"admin\"] .kpi-grid,\n  html[data-portal=\"admin\"] .catalog-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n  html[data-portal=\"admin\"] .card-grid {\n    grid-template-columns: repeat(2, minmax(0, 1fr));\n  }\n}\n\n/* Catalog product editor (Partner Admin) */\n.catalog-editor-overlay {\n  position: fixed;\n  inset: 0;\n  z-index: 2000;\n  background: var(--bg);\n  overflow: auto;\n}\n.catalog-editor {\n  min-height: 100vh;\n  display: flex;\n  flex-direction: column;\n}\n.catalog-editor-header {\n  display: flex;\n  align-items: flex-start;\n  justify-content: space-between;\n  gap: 16px;\n  padding: 16px 24px;\n  border-bottom: 1px solid var(--line);\n  background: var(--surface);\n  position: sticky;\n  top: 0;\n  z-index: 2;\n}\n.catalog-editor-title {\n  display: flex;\n  align-items: flex-start;\n  gap: 12px;\n}\n.catalog-editor-title h1 {\n  margin: 0;\n  font-size: 1.25rem;\n}\n.catalog-editor-sub {\n  margin: 4px 0 0;\n  font-size: 0.85rem;\n  color: var(--muted);\n}\n.catalog-editor-actions {\n  display: flex;\n  gap: 8px;\n  flex-shrink: 0;\n}\n.catalog-editor-tabs {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 4px;\n  padding: 8px 24px;\n  border-bottom: 1px solid var(--line);\n  background: var(--surface-2);\n}\n.ce-tab {\n  padding: 8px 14px;\n  border-radius: 999px;\n  background: transparent;\n  color: var(--muted);\n  font-weight: 600;\n  font-size: 0.85rem;\n}\n.ce-tab.active {\n  background: var(--surface);\n  color: var(--text);\n  box-shadow: var(--shadow-sm);\n}\n.catalog-editor-subnav {\n  display: flex;\n  flex-wrap: wrap;\n  align-items: center;\n  gap: 12px;\n  padding: 10px 24px;\n  border-bottom: 1px solid var(--line);\n  background: var(--surface);\n}\n.ce-provider-pills {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 6px;\n}\n.ce-provider-pill {\n  padding: 6px 12px;\n  border-radius: 999px;\n  border: 1px solid var(--line);\n  background: var(--surface-2);\n  font-size: 0.8rem;\n}\n.ce-provider-pill.active {\n  border-color: var(--brand);\n  background: color-mix(in srgb, var(--brand) 12%, transparent);\n}\n.catalog-editor-body {\n  flex: 1;\n  padding: 24px;\n  max-width: 1200px;\n}\n.ce-tab-panel h2 {\n  margin: 0 0 8px;\n  font-size: 1.1rem;\n}\n.ce-form-grid {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 16px;\n  margin-top: 16px;\n}\n.ce-form-grid .full {\n  grid-column: 1 / -1;\n}\n.ce-check-row,\n.ce-check-col {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 12px;\n}\n.ce-check-col {\n  flex-direction: column;\n}\n.ce-json-editor {\n  font-family: ui-monospace, monospace;\n  font-size: 0.8rem;\n}\n.ce-mockup-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));\n  gap: 12px;\n  margin-top: 16px;\n}\n.ce-mockup-card img {\n  width: 100%;\n  border-radius: 8px;\n  border: 1px solid var(--line);\n}\n.ce-mockup-meta {\n  font-size: 0.75rem;\n  color: var(--muted);\n  margin-top: 4px;\n}\n.ce-provider-list {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n  margin-top: 12px;\n}\n.ce-provider-row {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 10px 12px;\n  border: 1px solid var(--line);\n  border-radius: var(--radius-sm);\n}\n.ce-inline-form {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n  align-items: center;\n}\n.catalog-editor-loading {\n  padding: 48px;\n  text-align: center;\n}\n.catalog-editor-foot {\n  position: sticky;\n  bottom: 0;\n  padding: 12px 24px;\n  border-top: 1px solid var(--line);\n  background: var(--surface);\n}\n.catalog-editor-foot-actions {\n  display: flex;\n  justify-content: flex-end;\n  gap: 8px;\n}\n.ce-hint {\n  font-size: 0.85rem;\n  color: var(--muted);\n  margin-top: 8px;\n}\n.ce-section-title {\n  margin: 20px 0 8px;\n  font-size: 1rem;\n}\n.ce-error {\n  color: var(--danger);\n  padding: 16px;\n}\n#ce-drift.is-sync { color: var(--success); }\n#ce-drift.is-drift { color: var(--warning); }\nbody.catalog-editor-open { overflow: hidden; }\n.btn-sm {\n  padding: 6px 10px;\n  font-size: 0.8rem;\n}\n.input-sm {\n  padding: 6px 8px;\n  font-size: 0.85rem;\n}\nbody.catalog-editor-open {\n  overflow: hidden;\n}\n.catalog-editor-foot {\n  display: flex;\n  justify-content: flex-end;\n  gap: 8px;\n  padding: 12px 24px;\n  border-top: 1px solid var(--line);\n  background: var(--surface);\n  position: sticky;\n  bottom: 0;\n}\n.catalog-editor-foot-actions {\n  display: flex;\n  gap: 8px;\n}\n#ce-drift.is-sync {\n  color: var(--success);\n}\n#ce-drift.is-drift {\n  color: var(--warning);\n}\n.ce-section-title {\n  margin: 20px 0 10px;\n  font-size: 1rem;\n}\n.ce-section-title:first-child {\n  margin-top: 0;\n}\n.ce-hint {\n  color: var(--muted);\n  font-size: 0.85rem;\n}\n.ce-error {\n  padding: 16px;\n  border-radius: var(--radius-sm);\n  background: color-mix(in srgb, var(--danger) 10%, transparent);\n  color: var(--danger);\n}\n.ce-check-list {\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n}\n.ce-check-row {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 8px 10px;\n  border: 1px solid var(--line);\n  border-radius: var(--radius-sm);\n}\n.ce-inline-actions {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 8px;\n  margin-bottom: 12px;\n}\n.ce-table {\n  width: 100%;\n  margin-top: 8px;\n}\n.ce-code {\n  font-family: ui-monospace, monospace;\n  font-size: 0.8rem;\n}\n@media (max-width: 768px) {\n  .catalog-editor-foot {\n    flex-direction: column;\n  }\n}\n"},"shared/js/partner-api.js":{"contentType":"application/javascript; charset=utf-8","body":"export function partnerApiBase() {\n  return window.__PARTNER_API_BASE__ || window.location.origin;\n}\n\nexport async function partnerFetch(op, { method = \"GET\", body, query = {} } = {}) {\n  const url = new URL(partnerApiBase());\n  url.searchParams.set(\"op\", op);\n  for (const [k, v] of Object.entries(query)) {\n    if (v != null && v !== \"\") url.searchParams.set(k, v);\n  }\n  const res = await fetch(url.toString(), {\n    method,\n    credentials: \"include\",\n    headers: body ? { \"content-type\": \"application/json\" } : undefined,\n    body: body ? JSON.stringify(body) : undefined,\n  });\n  const data = await res.json().catch(() => ({}));\n  if (!res.ok || data.ok === false) {\n    const err = new Error(data.error || `http_${res.status}`);\n    err.data = data;\n    err.status = res.status;\n    throw err;\n  }\n  return data;\n}\n\nexport function badgeForStatus(status) {\n  const map = {\n    verified: \"badge-success\",\n    active: \"badge-success\",\n    shipped: \"badge-success\",\n    approved: \"badge-success\",\n    pending_email_verification: \"badge-neutral\",\n    pending_review: \"badge-warning\",\n    in_production: \"badge-warning\",\n    received: \"badge-neutral\",\n    draft: \"badge-neutral\",\n    rejected: \"badge-danger\",\n    suspended: \"badge-danger\",\n    failed: \"badge-danger\",\n  };\n  return map[status] || \"badge-neutral\";\n}\n\nexport function escapeHtml(s) {\n  return String(s ?? \"\")\n    .replace(/&/g, \"&amp;\")\n    .replace(/</g, \"&lt;\")\n    .replace(/>/g, \"&gt;\")\n    .replace(/\"/g, \"&quot;\");\n}\n"},"shared/js/partner-components.js":{"contentType":"application/javascript; charset=utf-8","body":"export { badgeForStatus, escapeHtml } from \"./partner-api.js\";\nexport { renderTable } from \"./partner-shell.js\";\n"},"shared/js/partner-shell.js":{"contentType":"application/javascript; charset=utf-8","body":"import { escapeHtml } from \"./partner-api.js\";\n\nlet modalSaveHandler = null;\nlet modalCancelHandler = null;\n\nconst DEFAULT_MODAL_FOOTER = {\n  saveLabel: \"Save\",\n  saveClass: \"btn btn-primary\",\n  cancelLabel: \"Cancel\",\n  saveDisplay: \"\",\n};\n\nfunction resetModalFooter() {\n  const saveBtn = document.getElementById(\"modal-save\");\n  const cancelBtn = document.getElementById(\"modal-cancel\");\n  const modal = document.querySelector(\"#modal-backdrop .modal\");\n  if (saveBtn) {\n    saveBtn.textContent = DEFAULT_MODAL_FOOTER.saveLabel;\n    saveBtn.className = DEFAULT_MODAL_FOOTER.saveClass;\n    saveBtn.style.display = DEFAULT_MODAL_FOOTER.saveDisplay;\n    saveBtn.disabled = false;\n  }\n  if (cancelBtn) {\n    cancelBtn.textContent = DEFAULT_MODAL_FOOTER.cancelLabel;\n    cancelBtn.style.display = \"\";\n  }\n  modal?.classList.remove(\"confirm-modal\");\n}\n\nexport function showToast(title, text) {\n  const el = document.getElementById(\"partner-toast\");\n  if (!el) return;\n  el.querySelector(\"strong\").textContent = title;\n  el.querySelector(\"span\").textContent = text || \"\";\n  el.classList.add(\"show\");\n  clearTimeout(showToast._t);\n  showToast._t = setTimeout(() => el.classList.remove(\"show\"), 2600);\n}\n\nexport function openModal({ title, bodyHtml, onSave }) {\n  const backdrop = document.getElementById(\"modal-backdrop\");\n  document.getElementById(\"modal-title\").textContent = title;\n  document.getElementById(\"modal-body\").innerHTML = bodyHtml;\n  modalSaveHandler = onSave || null;\n  modalCancelHandler = null;\n  backdrop.hidden = false;\n  backdrop.classList.add(\"show\");\n}\n\nfunction dismissModal() {\n  const backdrop = document.getElementById(\"modal-backdrop\");\n  if (!backdrop?.classList.contains(\"show\")) return;\n  const handler = modalCancelHandler;\n  closeModal();\n  if (handler) handler();\n}\n\nexport function closeModal() {\n  const backdrop = document.getElementById(\"modal-backdrop\");\n  backdrop.classList.remove(\"show\");\n  backdrop.hidden = true;\n  modalSaveHandler = null;\n  modalCancelHandler = null;\n  resetModalFooter();\n}\n\n/** Reject/suspend style modal with mode radios and optional reason textarea. */\nexport function openActionModeModal({\n  title,\n  message,\n  modes,\n  defaultMode,\n  reasonLabel = \"Reason (optional)\",\n  reasonPlaceholder = \"\",\n  confirmLabels = {},\n  confirmClasses = {},\n  onConfirm,\n}) {\n  const defaultVal = defaultMode || modes[0]?.value;\n  const modesHtml = (modes || [])\n    .map(\n      (mode) => `<label class=\"action-mode-option\">\n        <input type=\"radio\" name=\"action-mode\" value=\"${escapeHtml(mode.value)}\" ${mode.value === defaultVal ? \"checked\" : \"\"} />\n        <span><strong>${escapeHtml(mode.label)}</strong> — ${escapeHtml(mode.description || \"\")}</span>\n      </label>`\n    )\n    .join(\"\");\n\n  openModal({\n    title,\n    bodyHtml: `\n      ${message ? `<p class=\"confirm-modal-message\">${escapeHtml(message)}</p>` : \"\"}\n      <div class=\"action-mode-options\">${modesHtml}</div>\n      <div class=\"field\" style=\"margin-top:16px\">\n        <label>${escapeHtml(reasonLabel)}</label>\n        <textarea class=\"textarea\" id=\"action-mode-reason\" rows=\"3\" placeholder=\"${escapeHtml(reasonPlaceholder)}\"></textarea>\n      </div>`,\n    onSave: async () => {\n      const mode = document.querySelector('input[name=\"action-mode\"]:checked')?.value;\n      const reason = document.getElementById(\"action-mode-reason\")?.value?.trim() || \"\";\n      if (onConfirm) await onConfirm({ mode, reason });\n    },\n  });\n\n  modalCancelHandler = null;\n  const saveBtn = document.getElementById(\"modal-save\");\n  const modal = document.querySelector(\"#modal-backdrop .modal\");\n  modal?.classList.add(\"confirm-modal\", \"action-mode-modal\");\n\n  const updateSaveBtn = () => {\n    const mode = document.querySelector('input[name=\"action-mode\"]:checked')?.value;\n    if (!saveBtn || !mode) return;\n    saveBtn.textContent = confirmLabels[mode] || \"Confirm\";\n    saveBtn.className = `btn ${confirmClasses[mode] || \"btn-primary\"}`;\n    saveBtn.style.display = \"\";\n  };\n\n  document.querySelectorAll('input[name=\"action-mode\"]').forEach((radio) => {\n    radio.addEventListener(\"change\", updateSaveBtn);\n  });\n  updateSaveBtn();\n}\n\n/** Styled confirmation dialog using the shared modal shell (replaces window.confirm). */\nexport function confirmAction({\n  title,\n  message,\n  confirmLabel = \"Confirm\",\n  cancelLabel = \"Cancel\",\n  confirmClass = \"btn-primary\",\n  onConfirm,\n  onCancel,\n}) {\n  openModal({\n    title,\n    bodyHtml: `<p class=\"confirm-modal-message\">${escapeHtml(message)}</p>`,\n    onSave: onConfirm,\n  });\n  modalCancelHandler = onCancel || null;\n  const saveBtn = document.getElementById(\"modal-save\");\n  const cancelBtn = document.getElementById(\"modal-cancel\");\n  const modal = document.querySelector(\"#modal-backdrop .modal\");\n  modal?.classList.add(\"confirm-modal\");\n  if (saveBtn) {\n    saveBtn.textContent = confirmLabel;\n    saveBtn.className = `btn ${confirmClass}`;\n    saveBtn.style.display = \"\";\n  }\n  if (cancelBtn) cancelBtn.textContent = cancelLabel;\n}\n\nfunction navItemHtml(item) {\n  return `<button type=\"button\" class=\"nav-item\" data-route=\"${escapeHtml(item.route)}\"><span class=\"nav-icon\">${item.icon || \"•\"}</span>${escapeHtml(item.label)}</button>`;\n}\n\nconst MOBILE_DRAWER_MQ = \"(max-width: 768px)\";\n\nfunction getActiveShell() {\n  return document.querySelector(\".app-root:not([hidden]):not(.app-root--full)\");\n}\n\nfunction setDrawerOpen(shell, open) {\n  if (!shell) return;\n  shell.classList.toggle(\"sidebar-open\", open);\n  const toggle = shell.querySelector(\"#sidebar-toggle\");\n  if (toggle) {\n    toggle.setAttribute(\"aria-expanded\", String(open));\n    toggle.setAttribute(\"aria-label\", open ? \"Close menu\" : \"Open menu\");\n  }\n  const backdrop = shell.querySelector(\"#sidebar-backdrop\");\n  if (backdrop) backdrop.setAttribute(\"aria-hidden\", String(!open));\n  document.body.classList.toggle(\"drawer-open\", open);\n}\n\nfunction closeDrawer(shell = getActiveShell()) {\n  setDrawerOpen(shell, false);\n}\n\nfunction initMobileShell(shell) {\n  if (!shell || shell.classList.contains(\"app-root--full\")) return;\n\n  const toggle = shell.querySelector(\"#sidebar-toggle\");\n  const backdrop = shell.querySelector(\"#sidebar-backdrop\");\n  const nav = shell.querySelector(\"#partner-nav\");\n\n  toggle?.addEventListener(\"click\", () => {\n    const open = !shell.classList.contains(\"sidebar-open\");\n    setDrawerOpen(shell, open);\n  });\n\n  backdrop?.addEventListener(\"click\", () => closeDrawer(shell));\n\n  nav?.querySelectorAll(\"[data-route]\").forEach((btn) => {\n    btn.addEventListener(\"click\", () => {\n      if (window.matchMedia(MOBILE_DRAWER_MQ).matches) closeDrawer(shell);\n    });\n  });\n\n  const searchBox = shell.querySelector(\".search-box\");\n  const actions = shell.querySelector(\".topbar-actions\");\n  if (searchBox && actions && !shell.querySelector(\"#search-toggle\")) {\n    const searchToggle = document.createElement(\"button\");\n    searchToggle.type = \"button\";\n    searchToggle.id = \"search-toggle\";\n    searchToggle.className = \"icon-btn search-toggle\";\n    searchToggle.setAttribute(\"aria-label\", \"Search\");\n    searchToggle.textContent = \"⌕\";\n    actions.insertBefore(searchToggle, searchBox);\n    searchToggle.addEventListener(\"click\", () => {\n      actions.classList.toggle(\"search-expanded\");\n      if (actions.classList.contains(\"search-expanded\")) {\n        searchBox.querySelector(\"input\")?.focus();\n      } else {\n        searchBox.querySelector(\"input\")?.blur();\n      }\n    });\n  }\n\n  window.matchMedia(MOBILE_DRAWER_MQ).addEventListener(\"change\", (e) => {\n    if (!e.matches) {\n      closeDrawer(shell);\n      actions?.classList.remove(\"search-expanded\");\n    }\n  });\n}\n\nexport function initShell({ navItems, navSections, onRoute, brandSub = \"Manufacturer Portal\", crumbLabels = {} }) {\n  document.querySelector(\".brand-sub\").textContent = brandSub;\n  const nav = document.getElementById(\"partner-nav\");\n  if (navSections?.length) {\n    nav.innerHTML = navSections\n      .map(\n        (section) =>\n          `<div class=\"nav-section-title\">${escapeHtml(section.title)}</div>${section.items.map(navItemHtml).join(\"\")}`\n      )\n      .join(\"\");\n  } else {\n    nav.innerHTML = (navItems || []).map(navItemHtml).join(\"\");\n  }\n  initShell._crumbLabels = crumbLabels;\n\n  nav.querySelectorAll(\"[data-route]\").forEach((btn) => {\n    btn.addEventListener(\"click\", () => navigate(btn.dataset.route, onRoute));\n  });\n\n  document.getElementById(\"modal-close\")?.addEventListener(\"click\", dismissModal);\n  document.getElementById(\"modal-cancel\")?.addEventListener(\"click\", dismissModal);\n  document.getElementById(\"modal-save\")?.addEventListener(\"click\", async () => {\n    try {\n      if (modalSaveHandler) await modalSaveHandler();\n      closeModal();\n    } catch (e) {\n      showToast(\"Error\", e.message || String(e));\n    }\n  });\n  document.getElementById(\"modal-backdrop\")?.addEventListener(\"click\", (e) => {\n    if (e.target.id === \"modal-backdrop\") dismissModal();\n  });\n  document.addEventListener(\"keydown\", (e) => {\n    if (e.key !== \"Escape\") return;\n    const shell = getActiveShell();\n    if (shell?.classList.contains(\"sidebar-open\")) {\n      closeDrawer(shell);\n      return;\n    }\n    dismissModal();\n  });\n\n  const shell = document.getElementById(\"app-shell\");\n  initMobileShell(shell);\n\n  const initial = location.pathname.replace(/\\/$/, \"\") || \"/\";\n  navigate(initial === \"\" ? \"/\" : initial, onRoute, true);\n  window.addEventListener(\"popstate\", () => navigate(location.pathname, onRoute, true));\n}\n\nexport function navigate(route, onRoute, replace = false) {\n  const path = route || \"/\";\n  if (!replace) history.pushState({}, \"\", path);\n  closeDrawer();\n  document.querySelectorAll(\".nav-item\").forEach((el) => {\n    el.classList.toggle(\"active\", el.dataset.route === path);\n  });\n  document.querySelectorAll(\".view\").forEach((v) => v.classList.remove(\"active\"));\n  const view = document.querySelector(`.view[data-route=\"${path}\"]`) || document.querySelector('.view[data-route=\"/\"]');\n  view?.classList.add(\"active\");\n  const crumb = document.getElementById(\"crumb-current\");\n  if (crumb) {\n    const labels = initShell._crumbLabels || {};\n    crumb.textContent = labels[path] || (path === \"/\" ? \"Overview\" : path.replace(/^\\/partner\\/?/, \"\").replace(/\\//g, \" / \") || \"Overview\");\n  }\n  onRoute(path);\n}\n\nexport function setTopbarExtra(html) {\n  const el = document.getElementById(\"topbar-extra\");\n  if (el) el.innerHTML = html || \"\";\n}\n\nexport function renderTable(headers, rowsHtml) {\n  return `<div class=\"table-scroll\"><table class=\"table\"><thead><tr>${headers.map((h) => `<th>${escapeHtml(h)}</th>`).join(\"\")}</tr></thead><tbody>${rowsHtml}</tbody></table></div>`;\n}\n"}};
